-- Poems batch 105
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('25d3637e-47f4-4da8-ba81-d094d2ae9f03','頌古三十一首  其五','釋玿','宋','宋诗','song-poetry','','[]','喝聲絕處怒雷收，喪盡家風一不留。',32,'全唐诗/poet.song.120000.json','["喝聲絕處怒雷收，喪盡家風一不留。", "總是戰爭收拾得，却因歌舞破除休。"]'),
('533060c4-d84e-43c5-bee2-dcf7771f9922','頌古三十一首  其六','釋玿','宋','宋诗','song-poetry','','[]','大雄山下老狐精，千古叢林惱殺人。',32,'全唐诗/poet.song.120000.json','["大雄山下老狐精，千古叢林惱殺人。", "若遇金毛師子子，看伊無處著渾身。"]'),
('903f87d6-f2a6-435e-87dc-1a1db66b24bd','頌古三十一首  其七','釋玿','宋','宋诗','song-poetry','','[]','是賊識賊精識精，南泉無過强惺惺。',32,'全唐诗/poet.song.120000.json','["是賊識賊精識精，南泉無過强惺惺。", "趙州禮拜歸堂去，前箭猶輕後箭深。"]'),
('acd11cae-bef9-4e58-9862-6c6ad23264d7','頌古三十一首  其八','釋玿','宋','宋诗','song-poetry','','[]','家財喪盡沒絲毫，祇箇一身猶恨多。',32,'全唐诗/poet.song.120000.json','["家財喪盡沒絲毫，祇箇一身猶恨多。", "却向池陽最深處，殺人空手不持刀。"]'),
('398d06cc-b4d3-4ddd-bd57-9fb7a1155e05','頌古三十一首  其九','釋玿','宋','宋诗','song-poetry','','[]','前得得，後不得，一貫誰知兩五百。',42,'全唐诗/poet.song.120000.json','["前得得，後不得，一貫誰知兩五百。", "雨檜蕭蕭，風松瑟瑟。", "隔山人聽鷓鴣詞，錯認胡笳十八拍。"]'),
('db0434fa-5a6f-4e43-a8e0-c168765875e6','頌古三十一首  其一○','釋玿','宋','宋诗','song-poetry','','[]','此兒活計口皮邊，點著風馳與電旋。',32,'全唐诗/poet.song.120000.json','["此兒活計口皮邊，點著風馳與電旋。", "謾說鎮州蘿蔔大，何曾親見老南泉。"]'),
('7bde5098-3c54-4308-8bef-2445653d7f41','頌古三十一首  其一一','釋玿','宋','宋诗','song-poetry','','[]','當機轉處不躊躇，琉璃盤裏走明珠。',32,'全唐诗/poet.song.120000.json','["當機轉處不躊躇，琉璃盤裏走明珠。", "趙州老子村校書，一條拄杖兩人舁。"]'),
('913f22a0-70f3-4903-b9c5-d847b0174fc6','頌古三十一首  其一二','釋玿','宋','宋诗','song-poetry','','[]','庭前柏樹子，一二三四五。',24,'全唐诗/poet.song.120000.json','["庭前柏樹子，一二三四五。", "竇八布衫穿，禾山解打鼓。"]'),
('88cb8d98-07ed-4f5b-bdee-6014c0004b47','頌古三十一首  其一三','釋玿','宋','宋诗','song-poetry','','[]','無直路，却縈紆。',33,'全唐诗/poet.song.120000.json','["無直路，却縈紆。", "趙州東壁上，依舊挂葫蘆。", "有張公喫村酒，李公醉不醒。"]'),
('c87917d0-254f-423b-a622-f82bbfcdfff6','頌古三十一首  其一四','釋玿','宋','宋诗','song-poetry','','[]','利刀截斷命根，跳出狐群狗隊。',28,'全唐诗/poet.song.120000.json','["利刀截斷命根，跳出狐群狗隊。", "拈起萬煅蒺藜，鐵額銅頭粉碎。"]'),
('e7a0fb00-27d5-4b25-be1a-4ee66d87159e','頌古三十一首  其一五','釋玿','宋','宋诗','song-poetry','','[]','拶到懸崖撒手時，七斤衫重有誰知。',32,'全唐诗/poet.song.120000.json','["拶到懸崖撒手時，七斤衫重有誰知。", "寒來暑往渾無用，挂在趙州東院西。"]'),
('37610d77-d4b1-47c7-9120-2dd3e57b735a','頌古三十一首  其一六','釋玿','宋','宋诗','song-poetry','','[]','明日大悲院裏齋，鐵圍山岳盡衝開。',42,'全唐诗/poet.song.120000.json','["明日大悲院裏齋，鐵圍山岳盡衝開。", "豬頭象鼻，烏觜魚腮。", "石人撫掌呵呵笑，寒山拾得在天台。"]'),
('b2259a71-11c0-42af-b0a9-800bc6ccdb8d','頌古三十一首  其一七','釋玿','宋','宋诗','song-poetry','','[]','劫火光中共唱酬，隨波逐浪謾悠悠。',32,'全唐诗/poet.song.120000.json','["劫火光中共唱酬，隨波逐浪謾悠悠。", "剖盡衷腸人不會，草鞋拈取蓋龜休。"]'),
('e76f0670-ce6e-4ac4-a10e-96b8cd804af1','頌古三十一首  其一八','釋玿','宋','宋诗','song-poetry','','[]','投子投子，機輪無阻。',34,'全唐诗/poet.song.120000.json','["投子投子，機輪無阻。", "要吞即吞，要吐即吐。", "若還殢齒粘牙，爭得超今邁古。"]'),
('e52ef96c-0bb2-4ecc-a371-936f859ed97e','頌古三十一首  其一九','釋玿','宋','宋诗','song-poetry','','[]','有是父兮有是子，同條生也同條死。',48,'全唐诗/poet.song.120000.json','["有是父兮有是子，同條生也同條死。", "三世如來烈焰堆，互換說法元如此。", "莫顛言，休倒語，截斷葛藤須薦取。"]'),
('72981c1f-bbeb-4650-8265-2a8abd064a62','頌古三十一首  其二○','釋玿','宋','宋诗','song-poetry','','[]','塞北千人帳，江南萬斛船。',24,'全唐诗/poet.song.120000.json','["塞北千人帳，江南萬斛船。", "菩提窩裏坐，總謂是虛傳。"]'),
('b98c48ca-64cc-40dc-81e5-2491658524b5','頌古三十一首  其二一','釋玿','宋','宋诗','song-poetry','','[]','曹山不如，花根本艷。',46,'全唐诗/poet.song.120000.json','["曹山不如，花根本艷。", "不如曹山，虎體元班。", "江南地暖，塞北春寒。", "一把柳絲收不得，和烟搭在玉闌干。"]'),
('d226521d-532e-4fb5-acf7-a131305c4ef7','頌古三十一首  其二二','釋玿','宋','宋诗','song-poetry','','[]','隔，穿耳胡僧眼睛黑。',26,'全唐诗/poet.song.120000.json','["隔，穿耳胡僧眼睛黑。", "東院西邊是趙州，觀音院裏安彌勒。"]'),
('664cbfd6-9bf2-4944-814a-41d20e6a78b8','頌古三十一首  其二三','釋玿','宋','宋诗','song-poetry','','[]','北禪夜分歲，特地巧安排。',48,'全唐诗/poet.song.120000.json','["北禪夜分歲，特地巧安排。", "維那出隻手，線去又絲來。", "田郎催拍板，鮑老舞三臺。", "若教行正令，活作一坑埋。"]'),
('8b137d46-1c41-4317-865f-5d8fb8c08fbf','頌古三十一首  其二四','釋玿','宋','宋诗','song-poetry','','[]','苦中樂，樂中苦，大唐打鼓新羅舞。',32,'全唐诗/poet.song.120000.json','["苦中樂，樂中苦，大唐打鼓新羅舞。", "寒山燒火滿頭灰，却笑豐干倒騎虎。"]'),
('edbf068b-c526-4db8-b06f-9a8df24dce72','頌古三十一首  其二五','釋玿','宋','宋诗','song-poetry','','[]','有主有賓，有禮有樂。',51,'全唐诗/poet.song.120000.json','["有主有賓，有禮有樂。", "得失是非，如何摸索。", "纔摸索，無上醍醐成毒藥。", "君不見大鵬展翼蓋十洲，投窗之物空啾啾。"]'),
('44278ce4-b67c-4fec-9f89-3aba4e2255b7','頌古三十一首  其二六','釋玿','宋','宋诗','song-poetry','','[]','一人牙如劍樹，一人口似血盆。',42,'全唐诗/poet.song.120000.json','["一人牙如劍樹，一人口似血盆。", "一拳還一踢，一踢報一拳。", "亞豎摩醯頂門眼，不妨親踏上頭關。"]'),
('8dd0b281-75cf-458b-a742-ac46ac649db2','頌古三十一首  其二七','釋玿','宋','宋诗','song-poetry','','[]','我手何似佛手，堪笑紫湖養狗。',28,'全唐诗/poet.song.120000.json','["我手何似佛手，堪笑紫湖養狗。", "撞著焦尾大蟲，性命輸他一口。"]'),
('8ba6282d-33f9-409a-9c70-285e4623a568','頌古三十一首  其二八','釋玿','宋','宋诗','song-poetry','','[]','我脚何似驢脚，擬議知君大錯。',28,'全唐诗/poet.song.120000.json','["我脚何似驢脚，擬議知君大錯。", "進前欲飲醍醐，已似遭他毒藥。"]'),
('fb0bbde2-a422-4822-be86-97e5fc2fa67b','頌古三十一首  其二九','釋玿','宋','宋诗','song-poetry','','[]','人人盡有生緣，且非夷狄中原。',28,'全唐诗/poet.song.120000.json','["人人盡有生緣，且非夷狄中原。", "鎮府出大蘿蔔，趙州親見南泉。"]'),
('4bd50575-513f-4253-acbf-7c45cab311d6','頌古三十一首  其三○','釋玿','宋','宋诗','song-poetry','','[]','佛手驢脚生緣，生緣驢脚佛手。',44,'全唐诗/poet.song.120000.json','["佛手驢脚生緣，生緣驢脚佛手。", "李公醉倒街頭，元是張公喫酒。", "黄龍山裏老婆禪，恰似河陽新婦醜。"]'),
('ad1bc256-81e6-4802-b656-91e37226b022','頌古三十一首  其三一','釋玿','宋','宋诗','song-poetry','','[]','唇上必并班豹剝，舌頭當的帝都丁。',32,'全唐诗/poet.song.120000.json','["唇上必并班豹剝，舌頭當的帝都丁。", "自古上賢猶不識，造次凡流豈可明。"]'),
('e6e839cd-ba1d-468a-b585-0c13a0da09a9','偈頌十二首  其一','釋安永','宋','宋诗','song-poetry','','[]','經年不跨雲門路，逐浪隨波恁麽去。',90,'全唐诗/poet.song.120000.json','["經年不跨雲門路，逐浪隨波恁麽去。", "而今老大復癡憨，歸來且作村菴主。", "跨瞎驢，撾毒鼓，百戰場中偃文武。", "從教臨濟撥動煙塵，溈仰互爲隊伍，列伍位鎗旗，布三玄戈弩。", "不消咳嗽一聲，直下一時敗露。"]'),
('861cc6d4-81b2-44dc-9133-78342aeb0eff','偈頌十二首  其二','釋安永','宋','宋诗','song-poetry','','[]','虎頭带角人難措，石火電光休密布。',32,'全唐诗/poet.song.120000.json','["虎頭带角人難措，石火電光休密布。", "中興天子展神鋒，萬象之中看獨露。"]'),
('8be9ec38-9de4-4a07-b889-c4c2279fef14','偈頌十二首  其三','釋安永','宋','宋诗','song-poetry','','[]','海門鼓浪拍天飛，妙喜家風孰與知。',68,'全唐诗/poet.song.120000.json','["海門鼓浪拍天飛，妙喜家風孰與知。", "今日風雲重借便，分明向上爲全提。", "文彩未彰，消息已露。", "動地驚天，不容回互。", "雲漢昭回星斗垂，誰敢抬頭正眼覷。"]'),
('6a7754ce-3ded-45d2-8778-01a1647320af','偈頌十二首  其四','釋安永','宋','宋诗','song-poetry','','[]','枯木生花劫外春，馨香逼界古今聞。',32,'全唐诗/poet.song.120000.json','["枯木生花劫外春，馨香逼界古今聞。", "忽然樹倒歸何處，猿叫千山月滿船。"]'),
('9b12df72-5fa8-460c-9a31-2dd7f9292d17','偈頌十二首  其五','釋安永','宋','宋诗','song-poetry','','[]','世出世間稱第一，誰敢當頭正眼觀。',32,'全唐诗/poet.song.120000.json','["世出世間稱第一，誰敢當頭正眼觀。", "今日風雲欣慶會，九重深處現龍顔。"]'),
('72319259-a302-4f56-924c-fbda86552525','偈頌十二首  其六','釋安永','宋','宋诗','song-poetry','','[]','甚生標格，與麽奇特。',52,'全唐诗/poet.song.120000.json','["甚生標格，與麽奇特。", "甚生標格，如是富貴。", "未離兜率降王宮，天上人間無比類。", "萬國來朝仰聖明，南山又見添蒼翠。"]'),
('d74304b2-527f-45a9-bad8-9256cda0ed4f','偈頌十二首  其七','釋安永','宋','宋诗','song-poetry','','[]','解語非干舌，能言不在聲。',24,'全唐诗/poet.song.120000.json','["解語非干舌，能言不在聲。", "非聲非舌用，還家罷問程。"]'),
('78d20396-9869-46fc-ae13-5cd7ed3d3020','偈頌十二首  其八','釋安永','宋','宋诗','song-poetry','','[]','擘開滄海取龍吞，五逆聞雷不許聞。',32,'全唐诗/poet.song.120000.json','["擘開滄海取龍吞，五逆聞雷不許聞。", "翻笑波心遺劍客，區區空記刻舟痕。"]'),
('e9c72e5a-d561-4b2a-aca8-008f5b4c57a2','偈頌十二首  其九','釋安永','宋','宋诗','song-poetry','','[]','茫茫人看中秋月，徒向閻浮記時節。',56,'全唐诗/poet.song.120000.json','["茫茫人看中秋月，徒向閻浮記時節。", "不智明月向人圓，已是眼中重著屑。", "瞎了眼，降却屑，昨夜三更轉向西，驚起蒼龍拗角折。"]'),
('07883085-0b82-4171-8049-1780a5fc376a','偈頌十二首  其一○','釋安永','宋','宋诗','song-poetry','','[]','春深不放白牛閒，依舊隨羣入亂山。',32,'全唐诗/poet.song.120000.json','["春深不放白牛閒，依舊隨羣入亂山。", "拽杷牽犁償宿債，尾巴再露與人看。"]'),
('ef7f85e1-9357-425a-9298-6e4e2fc4eec0','偈頌十二首  其一一','釋安永','宋','宋诗','song-poetry','','[]','國師不跨石門句，舌頭未舉先分付。',32,'全唐诗/poet.song.120000.json','["國師不跨石門句，舌頭未舉先分付。", "那堪覿面涉思惟，沖天鷂子新羅去。"]'),
('d6d6067a-6517-4578-9657-cb87ef99d2a9','偈頌十二首  其一二','釋安永','宋','宋诗','song-poetry','','[]','少處減些多處添，白雲官路販私鹽。',32,'全唐诗/poet.song.120000.json','["少處減些多處添，白雲官路販私鹽。", "一條性命俱拋下，不怕當初王令嚴。"]'),
('16b82e21-2415-476e-aef1-6b51b584b5da','六祖','釋安永','宋','宋诗','song-poetry','','[]','黄梅半夜錯分付，纔得星兒便亂做。',32,'全唐诗/poet.song.120000.json','["黄梅半夜錯分付，纔得星兒便亂做。", "大庾嶺頭屙一堆，後代兒孫遭點污。"]'),
('dc9ed7f8-445c-4c40-aa53-10ee44532348','黄檗','釋安永','宋','宋诗','song-poetry','','[]','生緣不在北門村，行脚何曾參百丈。',32,'全唐诗/poet.song.120000.json','["生緣不在北門村，行脚何曾參百丈。", "夢裏思歸黄檗山，無端平地堆青嶂。"]'),
('7dddbec3-f6e8-417b-9af7-11f01273aaa2','洋嶼菴造水筧','釋安永','宋','宋诗','song-poetry','','[]','路遶懸崖萬仞頭，擔泉带月幾時休。',32,'全唐诗/poet.song.120000.json','["路遶懸崖萬仞頭，擔泉带月幾時休。", "箇中撥轉通天竅，人自安閒水自流。"]'),
('d286e33b-cc91-44d7-b19c-ccdcd59077aa','頌古三十一首  其一','釋安永','宋','宋诗','song-poetry','','[]','道泰時清才子貴，家肥國富小兒嬌。',32,'全唐诗/poet.song.120000.json','["道泰時清才子貴，家肥國富小兒嬌。", "不因紫陌花開早，爭見黄鶯下柳條。"]'),
('3344b691-bf46-40d3-983d-4dcfb5e2cda9','頌古三十一首  其二','釋安永','宋','宋诗','song-poetry','','[]','不因一事，不長一智。',36,'全唐诗/poet.song.120000.json','["不因一事，不長一智。", "不曾殺生，了無忌諱。", "傳言送語當風流，拈得口兮失却鼻。"]'),
('081185f4-4a0b-4c4a-9446-a3f5b47c9e81','頌古三十一首  其三','釋安永','宋','宋诗','song-poetry','','[]','魚行水濁，鳥飛毛落。',20,'全唐诗/poet.song.120000.json','["魚行水濁，鳥飛毛落。", "大士橫身，不受斧鑿。"]'),
('1e8e7282-2746-480e-9144-d9af968369ba','頌古三十一首  其四','釋安永','宋','宋诗','song-poetry','','[]','白日青天，開眼放尿。',20,'全唐诗/poet.song.120000.json','["白日青天，開眼放尿。", "黄面瞿曇，一場漏逗。"]'),
('145360bb-378a-42a4-b4d6-e9f5bc18998d','頌古三十一首  其五','釋安永','宋','宋诗','song-poetry','','[]','覿面當機掣電飛，當機覿面誰能用。',32,'全唐诗/poet.song.120000.json','["覿面當機掣電飛，當機覿面誰能用。", "一劍分身定死生，君王萬古聲名重。"]'),
('bca2020d-61ca-47d0-b72d-076b3d618cbc','頌古三十一首  其六','釋安永','宋','宋诗','song-poetry','','[]','喪盡家財，無本可據。',20,'全唐诗/poet.song.120000.json','["喪盡家財，無本可據。", "赤手殺人，彌天罪過。"]'),
('c2584cef-452c-4c4f-9225-5be1acad73c8','頌古三十一首  其七','釋安永','宋','宋诗','song-poetry','','[]','石火光中驗正邪，等閒拈却眼中沙。',32,'全唐诗/poet.song.120000.json','["石火光中驗正邪，等閒拈却眼中沙。", "自從不曾少鹽醬，敢保渠儂未到家。"]'),
('6c9ee6ad-e1b3-499a-a925-aeb2f3590f68','頌古三十一首  其八','釋安永','宋','宋诗','song-poetry','','[]','世路風波不見君，愁腸暗寫共誰論。',32,'全唐诗/poet.song.120000.json','["世路風波不見君，愁腸暗寫共誰論。", "迅雷纔震清飚起，白日一天星斗分。"]'),
('b7fca0a9-2b60-400b-bb79-9f0d89b88321','頌古三十一首  其九','釋安永','宋','宋诗','song-poetry','','[]','一刀兩段絕譊訛，天下禪和不奈何。',32,'全唐诗/poet.song.120000.json','["一刀兩段絕譊訛，天下禪和不奈何。", "頭戴草鞋重漏泄，知恩者少負恩多。"]'),
('cfe64923-c032-4303-b333-d4fdb580be57','頌古三十一首  其一○','釋安永','宋','宋诗','song-poetry','','[]','不放溪東西，隨分納些兒。',24,'全唐诗/poet.song.120000.json','["不放溪東西，隨分納些兒。", "冷暖只自知，分明說向誰。"]'),
('63df31f2-dae3-44a3-9427-9d61dedd618d','頌古三十一首  其一一','釋安永','宋','宋诗','song-poetry','','[]','妙轉之機掣電飛，目前生殺盡交馳。',32,'全唐诗/poet.song.120000.json','["妙轉之機掣電飛，目前生殺盡交馳。", "明珠自有明珠價，休向籬邊彈雀兒。"]'),
('076ebda6-07ff-4e6a-9b15-f501b11cb03f','頌古三十一首  其一二','釋安永','宋','宋诗','song-poetry','','[]','臭口未開經萬劫，絲毫纔犯鐵輪隨。',32,'全唐诗/poet.song.120000.json','["臭口未開經萬劫，絲毫纔犯鐵輪隨。", "雨散雲收明月夜，反動江波說向誰。"]'),
('d512d36b-585c-44ab-b86c-50cf60bf3860','頌古三十一首  其一三','釋安永','宋','宋诗','song-poetry','','[]','掣開金殿鎖，撞碎玉樓鐘。',24,'全唐诗/poet.song.120000.json','["掣開金殿鎖，撞碎玉樓鐘。", "貪程未歸客，徒自覓行蹤。"]'),
('2c14c0cc-7ebc-41f1-b122-c9cc3dce73de','頌古三十一首  其一四','釋安永','宋','宋诗','song-poetry','','[]','三度扣關轉不開，赤手迢迢空往來。',32,'全唐诗/poet.song.120000.json','["三度扣關轉不開，赤手迢迢空往來。", "忽然業鏡百雜碎，始覺從前滿面灰。"]'),
('c0e2d14a-66c5-434c-950a-3a9d217e5cb1','頌古三十一首  其一五','釋安永','宋','宋诗','song-poetry','','[]','紅爐起浪拍天飛，疾焰過風孰敢窺。',32,'全唐诗/poet.song.120000.json','["紅爐起浪拍天飛，疾焰過風孰敢窺。", "任是三頭并六臂，到此休誇第一機。"]'),
('b451ac1a-817a-4b3e-8725-09f407cc6567','頌古三十一首  其一六','釋安永','宋','宋诗','song-poetry','','[]','見成底事沒商量，剔起眉毛未廝當。',32,'全唐诗/poet.song.120000.json','["見成底事沒商量，剔起眉毛未廝當。", "日暮碧天鴻鴈斷，海門斜去兩三行。"]'),
('76a56dbe-cdb1-43a2-987f-dc6008115f0e','頌古三十一首  其一七','釋安永','宋','宋诗','song-poetry','','[]','快人一言，快馬一鞭。',20,'全唐诗/poet.song.120000.json','["快人一言，快馬一鞭。", "停囚長智，十萬八千。"]'),
('9adcf129-5b45-49a1-92f3-a1298fe2122d','頌古三十一首  其一八','釋安永','宋','宋诗','song-poetry','','[]','乞兒拾得錫，暗地空寶惜。',24,'全唐诗/poet.song.120000.json','["乞兒拾得錫，暗地空寶惜。", "撞著明眼人，一文也不直。"]'),
('2f20d295-79ca-4ce6-bc1d-75cbe6ffa4e7','頌古三十一首  其一九','釋安永','宋','宋诗','song-poetry','','[]','見兔放鷹，因邪打正。',20,'全唐诗/poet.song.120000.json','["見兔放鷹，因邪打正。", "脚未跨門，直須猛省。"]'),
('e0953d9f-2dd4-402d-8fad-146326a89d01','頌古三十一首  其二○','釋安永','宋','宋诗','song-poetry','','[]','三人證龜喚作鼈，啞子得夢向誰說。',32,'全唐诗/poet.song.120000.json','["三人證龜喚作鼈，啞子得夢向誰說。", "電光影裏浪驅馳，踏破澄潭一輪月。"]'),
('b837fa21-5540-4fd9-8786-67c72c7181b7','頌古三十一首  其二一','釋安永','宋','宋诗','song-poetry','','[]','一出一入，半合半開。',34,'全唐诗/poet.song.120000.json','["一出一入，半合半開。", "羸鶴翹寒木，狂猿嘯古臺。", "要知奇特事，當甚破草鞋。"]'),
('f48590ce-ea86-48d3-9c03-ce6c00c8693c','頌古三十一首  其二二','釋安永','宋','宋诗','song-poetry','','[]','入草親尋草裏人，重重有路掌中平。',32,'全唐诗/poet.song.120000.json','["入草親尋草裏人，重重有路掌中平。", "不遇大商空突曉，日高猶聽打三更。"]'),
('84c2aa26-479f-4b40-8777-f566ba29e558','頌古三十一首  其二三','釋安永','宋','宋诗','song-poetry','','[]','問處分明答處親，縱橫有路慣反身。',32,'全唐诗/poet.song.120000.json','["問處分明答處親，縱橫有路慣反身。", "相如奪得連城璧，秦主安然致太平。"]'),
('b35f566c-689e-4f1d-9c0c-aaf90dd458f8','頌古三十一首  其二四','釋安永','宋','宋诗','song-poetry','','[]','南北山相對，東西有路分。',24,'全唐诗/poet.song.120000.json','["南北山相對，東西有路分。", "不經場陣裏，爭見李將軍。"]'),
('df6432b2-e1f8-4d33-8149-9e41da343d50','頌古三十一首  其二五','釋安永','宋','宋诗','song-poetry','','[]','這僧掩耳偷鈴，雲山將錯就錯。',28,'全唐诗/poet.song.120000.json','["這僧掩耳偷鈴，雲山將錯就錯。", "若是碧眼胡兒，別有反身一著。"]'),
('c876f7e4-7e8b-4d11-8651-f0f0a16a29d3','頌古三十一首  其二六','釋安永','宋','宋诗','song-poetry','','[]','獨向滄溟截眾流，等閒舞棹擲金鈎。',32,'全唐诗/poet.song.120000.json','["獨向滄溟截眾流，等閒舞棹擲金鈎。", "白雲不露烟波闊，橫笛一聲天地秋。"]'),
('ff2dafdd-aa4b-4c74-83fc-d291e44c3ec5','頌古三十一首  其二七','釋安永','宋','宋诗','song-poetry','','[]','前箭猶輕後箭深，無限平人被陸沉。',32,'全唐诗/poet.song.120000.json','["前箭猶輕後箭深，無限平人被陸沉。", "箇裏豁開天地眼，吹毛拈起任橫行。"]'),
('2e6d156d-989f-45af-b6dc-b771aa936bdf','頌古三十一首  其二八','釋安永','宋','宋诗','song-poetry','','[]','掀翻海岳求知己，雪刃橫身立太平。',32,'全唐诗/poet.song.120000.json','["掀翻海岳求知己，雪刃橫身立太平。", "野老不知堯舜力，鼕鼕打鼓祭江神。"]'),
('0ebe1d98-32a6-4757-89cf-ebb154f715a8','頌古三十一首  其二九','釋安永','宋','宋诗','song-poetry','','[]','電光影裏，緇素區分。',20,'全唐诗/poet.song.120000.json','["電光影裏，緇素區分。", "纖毫不犯，總教滅門。"]'),
('c86f7454-6191-4e8a-a51d-65d465c2624e','頌古三十一首  其三○','釋安永','宋','宋诗','song-poetry','','[]','九曲那容眨眼看，操舟誰解別波瀾。',32,'全唐诗/poet.song.120000.json','["九曲那容眨眼看，操舟誰解別波瀾。", "文殊曾展回天手，直得朝宗萬派乾。"]'),
('e45a22d7-1ab1-49ea-b8c9-d914fea34fb6','頌古三十一首  其三一','釋安永','宋','宋诗','song-poetry','','[]','擊碎髑髏，敲出骨節。',20,'全唐诗/poet.song.120000.json','["擊碎髑髏，敲出骨節。", "明眼人前，自彰醜拙。"]'),
('247f4fb8-7af5-459b-baee-36b4e608ca4b','偈','釋志清','宋','宋诗','song-poetry','','[]','天不能蓋，地不能載。',20,'全唐诗/poet.song.120000.json','["天不能蓋，地不能載。", "徧界徧空，成團成塊。"]'),
('161782ce-a928-43e5-92fe-dc1d27d3963c','和王龜齡惠詩','釋宗覺','宋','宋诗','song-poetry','','[]','少年詞賦客，昔與山翁游。',240,'全唐诗/poet.song.120000.json','["少年詞賦客，昔與山翁游。", "暫抑驊騮姿，聊伴鹽車留。", "幽坡賞春色，明月同高秋。", "君才如鮑照，顧我非湯休。", "木桃時一投，瓊瑶三四酬。", "可憐橫海鱗，尺水難沉浮。", "飄然拂袖去，形影那容求。", "早莫哦君詩，書空復搔頭。", "邇來三年餘，擬君薦經由。", "長篇忽見遺，頓覺驅煩愀。", "君馬何大駛，追蹤謫僊流。", "錦繡滿腸胃，詞人孰能儔。", "故將西子容，來貽嫫姆羞。", "行看復坐吟，終日如軥輈。", "安得君書齋，移來近前陬。", "論文與談笑，一釋老者憂。", "春禽晝聒聒，窗風夜颼颼。", "懷君不成寐，頻驚節物遒。", "君文已造妙，君德當慎修。", "謁帝明光宮，隨珠那暗投。"]'),
('b12ad747-65e6-49ba-bdc7-269937071fb5','題濟川亭','釋宗覺','宋','宋诗','song-poetry','','[]','高亭窺綠潤，古寺面蒼陰。',48,'全唐诗/poet.song.120000.json','["高亭窺綠潤，古寺面蒼陰。", "聞有遺仙事，應容過客尋。", "路危山背迥，雲重洞天深。", "一鳥不飛去，時能弄好音。"]'),
('a573dc2d-c0c1-4bad-ae8c-d8704382107e','過多福寺次王龜齡壁間韻','熊應亨','宋','宋诗','song-poetry','','[]','七尺枯藤手自摩，閒過僧寺坐橫坡。',64,'全唐诗/poet.song.120000.json','["七尺枯藤手自摩，閒過僧寺坐橫坡。", "花開曲徑霜前密，雲壓層城雨後多。", "田舍竹林分鷲嶺，山城蘆水漾魚波。", "禪床處處堆黄葉，獨剩寒松不改柯。"]'),
('f557c57b-68ef-4748-bf5a-e36ccf3517da','頌古四首  其一','釋行機','宋','宋诗','song-poetry','','[]','葉落崗頭一望長，幾莖喬木倚斜陽。',32,'全唐诗/poet.song.120000.json','["葉落崗頭一望長，幾莖喬木倚斜陽。", "曾經巴峻猿啼處，鐵打心肝寸斷腸。"]'),
('0ec2be86-d651-4498-a149-7f746be716d5','頌古四首  其二','釋行機','宋','宋诗','song-poetry','','[]','隔林彷彿聞機杼，知有人家在翠微。',32,'全唐诗/poet.song.120000.json','["隔林彷彿聞機杼，知有人家在翠微。", "及至入門親見了，元來只是小兒戲。"]'),
('f8939583-4261-4248-bdd4-bc2dcebfa06f','頌古四首  其三','釋行機','宋','宋诗','song-poetry','','[]','青蛇提起氣腥臊，幾箇男兒有痛毛。',32,'全唐诗/poet.song.120000.json','["青蛇提起氣腥臊，幾箇男兒有痛毛。", "直下血流猶未覺，舉頭還見鐵山高。"]'),
('e2950dd4-455b-4076-9c23-112512951c9a','頌古四首  其四','釋行機','宋','宋诗','song-poetry','','[]','東西南北無門戶，大地山河不覆藏。',32,'全唐诗/poet.song.120000.json','["東西南北無門戶，大地山河不覆藏。", "今夜碧天雲脚盡，一鈎月挂幾人腸。"]'),
('b2d4a017-6ad4-414e-b3ea-4b3715607e1c','送僧造普同塔','釋行機','宋','宋诗','song-poetry','','[]','珊珊玉骨本玲瓏，挂角羚羊不見蹤。',32,'全唐诗/poet.song.120000.json','["珊珊玉骨本玲瓏，挂角羚羊不見蹤。", "特地作亭圖甚麽，爲憐松竹引清風。"]'),
('8f9090d8-0e66-49b6-ad20-72e875ba8e2a','送育維那','釋行機','宋','宋诗','song-poetry','','[]','克賓一字入公門，有理難伸笑殺人。',32,'全唐诗/poet.song.120000.json','["克賓一字入公門，有理難伸笑殺人。", "隱靜不行興化令，他年誰道棒頭親。"]'),
('51f9b461-aada-4115-bbf3-b0b4b58f4c49','偈三首  其一','釋行機','宋','宋诗','song-poetry','','[]','地爐無火客囊空，雪似楊花落歲窮。',32,'全唐诗/poet.song.120000.json','["地爐無火客囊空，雪似楊花落歲窮。", "拾得斷麻穿壞衲，不知身在寂寥中。"]'),
('4948d606-308a-496e-92b8-7a486bbb2e34','偈三首  其二','釋行機','宋','宋诗','song-poetry','','[]','圓通不開生藥鋪，單單只賣死貓頭。',32,'全唐诗/poet.song.120000.json','["圓通不開生藥鋪，單單只賣死貓頭。", "不知那箇無思算，喫著通身冷汗流。"]'),
('d4f7ff61-5204-48df-846a-7565af0641cc','偈三首  其三','釋行機','宋','宋诗','song-poetry','','[]','仲秋八月旦，庭戶入新凉。',24,'全唐诗/poet.song.120000.json','["仲秋八月旦，庭戶入新凉。", "不露風骨句，愁人知夜長。"]'),
('da53888d-e8b8-4c74-8c71-88d9c8d113cd','留守舍人張公安國聞維筑亭爲題其榜曰朝陽既去而亭成復爲賦詩次韻','張維','宋','宋诗','song-poetry','','[]','日邊清切以文鳴，立對朝陽欲問程。',64,'全唐诗/poet.song.120000.json','["日邊清切以文鳴，立對朝陽欲問程。", "筆落生春變寒谷，詩來將喜破愁城。", "簷前水到乘槎便，天際山橫與檻平。", "准擬公歸道過此，小留觴詠集簪纓。"]'),
('5534c9a0-426a-4428-bf66-4032025cfc5f','題張公洞','張維','宋','宋诗','song-poetry','','[]','年來行樂與民同，探穴追蹤太史公。',64,'全唐诗/poet.song.120000.json','["年來行樂與民同，探穴追蹤太史公。", "幽洞初開名易著，蒼崖新刻句難工。", "風驅俗駕松扉外，雲鎖仙丹石室中。", "付與山僧司管鑰，勿教勝地草蒙茸。"]'),
('4ecea902-af88-4f3a-b073-a6c64ba893b9','次韻同經略舍人登七星山','張維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','列岫凌虛滃翠嵐，龍泓澄澈七星涵。',32,'全唐诗/poet.song.120000.json','["列岫凌虛滃翠嵐，龍泓澄澈七星涵。", "巖瞻好向西湖看，飛去何妨自嶺南。"]'),
('e5a7353e-db01-4549-a3f3-cf51c2567c5b','遊虎丘巖偶題壁韻叶因分字聯句','陳俊卿','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.120000.json','["無正文。"]'),
('42ba41f0-5df2-4676-bd18-9e18cfc60b77','贈林謙之','陳俊卿','宋','宋诗','song-poetry','','[]','走筆題詩問起居，近來導引復何如。',64,'全唐诗/poet.song.120000.json','["走筆題詩問起居，近來導引復何如。", "從教兩鬢霜無數，却要三田火有餘。", "示病想同摩詰病，讀書還著子雲書。", "梅霖十日宜高爽，試共登樓一豁舒。"]'),
('3a82d3b9-eef6-48cd-80f2-b8ceae38a439','示二子','陳俊卿','宋','宋诗','song-poetry','','[]','興來文字三杯酒，老去生涯萬卷書。',32,'全唐诗/poet.song.120000.json','["興來文字三杯酒，老去生涯萬卷書。", "遺汝子孫清白在，不須厦屋太渠渠。"]'),
('bbf6e19d-8332-4c53-81c1-41e08dd9d919','哭林艾軒','陳俊卿','宋','宋诗','song-poetry','','[]','出爲嶺嶠澄清使，歸作甘泉侍從臣。',64,'全唐诗/poet.song.120000.json','["出爲嶺嶠澄清使，歸作甘泉侍從臣。", "百擔有書行李重，千金無產橐中貧。", "經旬把臂言猶在，昨日題詩墨尚新。", "清曉訪君呼不起，寢門一慟淚沾巾。"]'),
('bddab2f9-ee03-41b7-bb52-66393f56da02','寄林子方','陳俊卿','宋','宋诗','song-poetry','','[]','雙闕門高襲慶餘，相望再世擁軺車。',64,'全唐诗/poet.song.120000.json','["雙闕門高襲慶餘，相望再世擁軺車。", "清名益重先君子，遠俗爭看行秘書。", "醫國十全姑小試，蠹民五瘴想先除。", "炎州莫作經年計，狗監傳聞誦子虛。"]'),
('cccb62fa-c2d5-42c8-bb60-c71822b3c21e','共樂堂','陳俊卿','宋','宋诗','song-poetry','','[]','共樂堂前花木深，登臨當暑豁塵襟。',64,'全唐诗/poet.song.120000.json','["共樂堂前花木深，登臨當暑豁塵襟。", "紅垂荔子千家熟，翠擁篔簹十畝陰。", "老退已尋居士服，清歡時伴醉翁吟。", "憑欄四望豐年稼，差慰平生憂國心。"]'),
('3a777d1b-2de2-4d5d-9c0c-66725c90d4aa','蔣山謝雨','陳俊卿','宋','宋诗','song-poetry','','[]','農事春郊閔雨時，乞靈奔走寶公祠。',64,'全唐诗/poet.song.120000.json','["農事春郊閔雨時，乞靈奔走寶公祠。", "鑪中沉水纔三祝，天外油雲已四垂。", "蔌蔌通宵茅屋冷，青青破曉麥田滋。", "更祈三日滂然澤，大作豐年遍海涯。"]'),
('835dace8-3e88-4977-9052-1bbec39218ab','修史堂','陳俊卿','宋','宋诗','song-poetry','','[]','流水三間屋，明公半席分。',48,'全唐诗/poet.song.120000.json','["流水三間屋，明公半席分。", "帝嘗招此老，天未喪斯文。", "人去留青竹，山空鎖白雲。", "升堂時想像，金石恍然聞。"]'),
('3db25986-bcb5-4e28-b8e6-09cea6a1e9d5','林元美司戶耕樂亭','陳俊卿','宋','宋诗','song-poetry','','[]','天地秘絕景，雅屬幽人居。',144,'全唐诗/poet.song.120000.json','["天地秘絕景，雅屬幽人居。", "卜筑俯清流，曠然心目舒。", "豈惟水澄碧，山色佳有餘。", "凉風左右來，竹柏相扶疎。", "亭中何所有，縹囊萬卷書。", "亭外何所有，青蒲映紅蕖。", "客來何所爲，高論唐虞初。", "文字共發越，琴槊一以娛。", "冬寒飽霜蟹，秋思多鱸魚。", "良田自種秫，酒甕春浮蛆。", "無事時痛飲，有時還荷鋤。", "試問田家樂，田家此樂無。"]'),
('1281b5aa-3787-4e7c-924b-98619897b8d2','句  其一','陳俊卿','宋','宋诗','song-poetry','','[]','吾方蹈孔孟，未暇師粲可。',12,'全唐诗/poet.song.120000.json','["吾方蹈孔孟，未暇師粲可。"]'),
('5d7f51a1-9da3-4114-94c7-50ceef743020','句  其二','陳俊卿','宋','宋诗','song-poetry','','[]','病深老迫宜歸去，莫作留侯范蠡看。',16,'全唐诗/poet.song.120000.json','["病深老迫宜歸去，莫作留侯范蠡看。"]'),
('37d9a165-4f56-49b6-b533-a2184e76d28e','句  其三','陳俊卿','宋','宋诗','song-poetry','','[]','海國民皆興禮義，潢池盜已息干戈。',16,'全唐诗/poet.song.120000.json','["海國民皆興禮義，潢池盜已息干戈。"]'),
('85e71577-a615-4147-b194-408cfccdc720','醉歌','徐珩','宋','宋诗','song-poetry','','[]','得誰釀法乃爾佳，連引數盃極口誇。',144,'全唐诗/poet.song.120000.json','["得誰釀法乃爾佳，連引數盃極口誇。", "須臾忘物亦忘我，是非榮辱不可加。", "兒童相隨拍手笑，阿翁醉也扶歸家。", "平生故人趙半刺，遣騎折送園中花。", "插花飲酒不待勸，夜如何其月欲斜。", "倒著接蘺自起舞，笛聲趁拍鼓三撾。", "陶陶兀兀意有得，小姬在傍雙髻丫。", "驅令磨墨具紙筆，滿幅大草飛龍蛇。", "婦云汝醉當止矣，明日酒醒不愧耶。"]'),
('1ed75b28-dc00-4655-a074-71026e4c9b10','贈閤門潘舍人','徐珩','宋','宋诗','song-poetry','','[]','清蹕聲中玉筍班，五雲光裏侍天顔。',64,'全唐诗/poet.song.120000.json','["清蹕聲中玉筍班，五雲光裏侍天顔。", "至尊端拱通明殿，上閤來從飯顆山。", "旄節行將千騎去，鬢鬚全未一根斑。", "朝迴兩袖香煙滿，應有詩留雉扇間。"]'),
('c858da18-db1c-4dfa-a2db-9870048eed21','和虞智父登金陵清谿閣','徐珩','宋','宋诗','song-poetry','','[]','葉脫林梢處處秋，壯懷易感更登樓。',64,'全唐诗/poet.song.120000.json','["葉脫林梢處處秋，壯懷易感更登樓。", "日斜鍾阜煙凝碧，霜落秦淮水慢流。", "人似仲宣思故國，詩如杜老到夔州。", "十年前作金陵夢，重撫欄干說舊遊。"]'),
('656e15d2-efb9-426b-9498-c51155a9e7d0','以水石菖蒲贈谷堂孫漕','徐珩','宋','宋诗','song-poetry','','[]','菖蒲體柔弱，孤生幽澗傍。',72,'全唐诗/poet.song.120000.json','["菖蒲體柔弱，孤生幽澗傍。", "澗深水不滋，短葉疎而黄。", "物亦有不幸，仁者爲悲傷。", "願因水石間，移植近窗光。", "探丸起九死，焦捲復翠長。", "草木固無知，此心未能忘。"]'),
('f0fb1dfd-61a7-4bc8-8847-1d92f6afca84','日暮望涇水','徐珩','宋','宋诗','song-poetry','','[]','導源經隴阪，屬汭貫嬴都。',48,'全唐诗/poet.song.120000.json','["導源經隴阪，屬汭貫嬴都。", "下瀨波常急，迴圻溜亦紆。", "毒流秦卒斃，泥糞漢田腴。", "獨有迷津客，懷歸軫暮途。"]'),
('48a65aa4-8f52-49aa-8dbd-276b6d8a709d','題黄子中南陂集','劉天麟','宋','宋诗','song-poetry','','[]','自歎苦吟詩不老，羨君詞氣凜橫秋。',32,'全唐诗/poet.song.120000.json','["自歎苦吟詩不老，羨君詞氣凜橫秋。", "爭如兀坐茅簷下，得見凌雲五鳳樓。"]'),
('fc427499-30e4-4c40-b456-c6f77c9d23fb','西陂','詹羽','宋','宋诗','song-poetry','','[]','野渡扁舟自在浮，慣來江上不驚鷗。',32,'全唐诗/poet.song.120000.json','["野渡扁舟自在浮，慣來江上不驚鷗。", "一竿釣破滄浪月，喚入蘆花不點頭。"]'),
('260f2880-ad52-4ac4-8604-d8cf5c035ebb','曹公泉','曹績','宋','宋诗','song-poetry','','[]','度嶺汗如濯，渴塵生客心。',24,'全唐诗/poet.song.120000.json','["度嶺汗如濯，渴塵生客心。", "清泉隨念應，乞與滌煩襟。"]'),
('7e25f7c6-e07a-4a74-bcf1-5d381497e46c','秋日憶次張弟','郭知虔','宋','宋诗','song-poetry','','[]','秋風吹落葉，獨客異鄉心。',48,'全唐诗/poet.song.120000.json','["秋風吹落葉，獨客異鄉心。", "生計憐吾拙，窮愁念汝深。", "面經三載隔，老惜二毛侵。", "飄泊南飛雁，何時返故林。"]'),
('1a117a12-18fc-4b33-ae5a-dc98099908c0','題水弄山','楊筠','宋','宋诗','song-poetry','','[]','曲曲溪流疊疊山，稻塍高下路回環。',32,'全唐诗/poet.song.120000.json','["曲曲溪流疊疊山，稻塍高下路回環。", "曉暾初射林霏落，一道炊煙紫翠間。"]'),
('51e9d214-7a94-4269-871b-34c6900aa018','題石藤二夫人廟','楊筠','宋','宋诗','song-poetry','','[]','古藤陰鎖石粼粼，死骨猶香廟像新。',32,'全唐诗/poet.song.120000.json','["古藤陰鎖石粼粼，死骨猶香廟像新。", "世上男兒輕失節，何顔祠下拜夫人。"]'),
('80e336f0-47d1-48cf-a769-e31c71b2ca57','景伯錄示太守湖上唱酬舍弟既賦二章輒亦次韻  其一','李益謙','宋','宋诗','song-poetry','','[]','鷗鷺驚飛去又回，藕花初爲使君開。',64,'全唐诗/poet.song.120000.json','["鷗鷺驚飛去又回，藕花初爲使君開。", "千山急雨催詩筆，四面清波映酒罍。", "暫倚高旌留勝賞，有懷別乘約重來。", "銀鈎灑落傳新句，二妙端知共一臺。"]'),
('d1f8829f-bfb3-4be0-b76d-19fc7727eb46','景伯錄示太守湖上唱酬舍弟既賦二章輒亦次韻  其二','李益謙','宋','宋诗','song-poetry','','[]','紅塵擾擾倦追陪，獨向湖山襟抱開。',64,'全唐诗/poet.song.120000.json','["紅塵擾擾倦追陪，獨向湖山襟抱開。", "每爲清風携枕席，幾因狂醉倒瓶罍。", "叢書久伴天隨隱，五袴今逢叔度來。", "更待海沂歌詠達，同看給札漢家臺。"]'),
('e87c5ddd-282d-46af-9844-7e66b393f3d9','景伯正字招東郊觀梅晚集茶院秀遠堂舉之舍弟有詩景伯和章見簡同賦  其一','李益謙','宋','宋诗','song-poetry','','[]','十里寒梅欲鬭妍，東郊尋勝喜聯翩。',64,'全唐诗/poet.song.120000.json','["十里寒梅欲鬭妍，東郊尋勝喜聯翩。", "漸看冰泮池塘外，又見春生島嶼邊。", "漁艇招招浮遠水，畬田漠漠起平川。", "惜無畫手王摩詰，只把君詩寫蜀牋。"]'),
('fdad47fd-be5c-40cf-93b1-8dee78ae68dc','景伯正字招東郊觀梅晚集茶院秀遠堂舉之舍弟有詩景伯和章見簡同賦  其二','李益謙','宋','宋诗','song-poetry','','[]','青春垂地風頭惡，寒色侵肌雪意酣。',64,'全唐诗/poet.song.120000.json','["青春垂地風頭惡，寒色侵肌雪意酣。", "路轉溪橋回馬足，行穿松逕得僧藍。", "聯裾正喜陪清賞，揮麈何妨共劇談。", "它日海邦傳盛事，詩仙曾此駐鸞驂。"]'),
('e4a07903-8b99-4de0-a4be-db18dc47e458','景伯正字按行外邑平遣繫囚既還出道中詩一編蔡丈有詩次韻','李益能','宋','宋诗','song-poetry','','[]','屬邑周行未覺勞，要觀鋩刃試豪曹。',64,'全唐诗/poet.song.120000.json','["屬邑周行未覺勞，要觀鋩刃試豪曹。", "氣蘇犴獄歌謠滿，興挾江山句律高。", "緩駕海邦聊展驥，指期仙嶺看浮鼇。", "秋來賦詠傳宮掖，三絕行聞帝語褒。"]'),
('ebd48137-954b-45ca-ba4a-f476ba978f43','往浙西別王龜齡','孫文昭','宋','宋诗','song-poetry','','[]','中原回首尚胡塵，世事徒驚日月新。',64,'全唐诗/poet.song.120000.json','["中原回首尚胡塵，世事徒驚日月新。", "羈旅不堪頻作別，壯懷雖在已甘貧。", "南來求友傳三益，西去論心有幾人。", "別後夢魂何處是，祇應來往慎江濱。"]'),
('f427a980-8f10-4e9f-bff6-0f18139d0bdf','婆餅焦','惠迪','宋','宋诗','song-poetry','','[]','夢破一聲婆餅焦，吳音未穩带春嬌。',32,'全唐诗/poet.song.120000.json','["夢破一聲婆餅焦，吳音未穩带春嬌。", "不禁風力遥飛去，却引餘音過別條。"]'),
('bda0a837-59d2-4b82-b1e9-35a7f5255e05','送客','惠迪','宋','宋诗','song-poetry','','[]','開懷有佳子，我別不忍別。',72,'全唐诗/poet.song.120000.json','["開懷有佳子，我別不忍別。", "連宵攬衣忙，就月歌數闋。", "歌長月欲落，酒盡情更切。", "凌晨□獨行，祖贈餘麯糵。", "昨語已如夢，今語無對說。", "待得歸來時，楊花滿天雪。"]'),
('e49cf2c6-0abf-417d-8a0f-0d9419acf96e','句','惠迪','宋','宋诗','song-poetry','','[]','小屋牽蘿補，高軒偃蓋過。',12,'全唐诗/poet.song.120000.json','["小屋牽蘿補，高軒偃蓋過。"]'),
('fff7a719-75ef-4a9a-9245-41e9e3823e90','聞僧舉五祖頌趙州露刀劍作偈','釋法全','宋','宋诗','song-poetry','','[]','鼓吹轟轟袒半肩，龍樓香噴益州船。',32,'全唐诗/poet.song.120000.json','["鼓吹轟轟袒半肩，龍樓香噴益州船。", "有時亦脚弄明月，踏破五湖波底天。"]'),
('8f48ac27-f164-4015-b960-f29d3e28d276','頌古十九首  其一','釋法全','宋','宋诗','song-poetry','','[]','昨夜深沙鑄鐵券，阿那律陀來合伴。',54,'全唐诗/poet.song.120000.json','["昨夜深沙鑄鐵券，阿那律陀來合伴。", "醉來相打見閻王，閻王握筆不能判。", "不能判，却相勸。", "彼此事同一家，更莫前思後算。"]'),
('20ce74b3-136b-4618-9249-c9a499f0bf2e','頌古十九首  其二','釋法全','宋','宋诗','song-poetry','','[]','布鼓當軒爲擊來，卧龍驚起出巖隈。',32,'全唐诗/poet.song.120000.json','["布鼓當軒爲擊來，卧龍驚起出巖隈。", "千峰秀色憑誰寫，一带澄江古鏡開。"]'),
('67dde3f0-958a-46b0-b59d-7ee7af81efa0','頌古十九首  其三','釋法全','宋','宋诗','song-poetry','','[]','徧身是，通身是，浄潔渾身涴却屎。',32,'全唐诗/poet.song.120000.json','["徧身是，通身是，浄潔渾身涴却屎。", "拽來露出猛風吹，誰教背手摸枕子。"]'),
('756b99c6-1a99-4047-916a-86e94c116e56','頌古十九首  其四','釋法全','宋','宋诗','song-poetry','','[]','亂撒明珠顆顆晶，走盤應不貴金聲。',32,'全唐诗/poet.song.120000.json','["亂撒明珠顆顆晶，走盤應不貴金聲。", "誰家女子能針線，一串穿來不剩星。"]'),
('c78a91c0-a70d-4b8a-88ec-b184072a8f47','頌古十九首  其五','釋法全','宋','宋诗','song-poetry','','[]','天高地厚尋常事，海闊山重更要論。',32,'全唐诗/poet.song.120000.json','["天高地厚尋常事，海闊山重更要論。", "霹靂震摧山鬼窟，獨携霜劍定乾坤。"]'),
('d722e649-17b5-481d-ab4f-50c6124c5eae','頌古十九首  其六','釋法全','宋','宋诗','song-poetry','','[]','當門一脈透長安，遊子空嗟行路難。',32,'全唐诗/poet.song.120000.json','["當門一脈透長安，遊子空嗟行路難。", "不是人前誇俏措，金鎚擊碎萬重關。"]'),
('493c3f20-a25d-441d-88cc-016d4445ec17','頌古十九首  其七','釋法全','宋','宋诗','song-poetry','','[]','日暖風和鶯囀新，柳垂金線繫東君。',32,'全唐诗/poet.song.120000.json','["日暖風和鶯囀新，柳垂金線繫東君。", "東君不惜無私力，一點花紅一點春。"]'),
('3e7a251d-e475-49ed-95b1-2e0621125aa3','頌古十九首  其八','釋法全','宋','宋诗','song-poetry','','[]','狗子佛性無，斫額路上逢子湖。',60,'全唐诗/poet.song.120000.json','["狗子佛性無，斫額路上逢子湖。", "業識性在遭一口，大地全無碧眼胡。", "狗子佛性有，春風吹動千株柳。", "知而故犯可憐生，一一面南看北斗。"]'),
('3889e56c-7d16-4342-9270-59d9b0353bc6','頌古十九首  其九','釋法全','宋','宋诗','song-poetry','','[]','東司上不說佛法，喚來與伊劈面踏。',32,'全唐诗/poet.song.120000.json','["東司上不說佛法，喚來與伊劈面踏。", "不用重論報佛恩，將此深心奉塵剎。"]'),
('ecb218dc-2c50-4c04-bc25-828c2dc4e5d4','頌古十九首  其一○','釋法全','宋','宋诗','song-poetry','','[]','相逢把手上高峰，四顧寥寥天宇空。',32,'全唐诗/poet.song.120000.json','["相逢把手上高峰，四顧寥寥天宇空。", "一曲漁歌人不會，蘆花飛起渡頭風。"]'),
('f9baf69e-2999-4362-be7c-588ab21bbaa2','頌古十九首  其一一','釋法全','宋','宋诗','song-poetry','','[]','驢覷井，井覷驢，冬瓜葉上長葫蘆。',32,'全唐诗/poet.song.120000.json','["驢覷井，井覷驢，冬瓜葉上長葫蘆。", "會不得，莫踟躕，定盤星上絕錙銖。"]'),
('e77c1f60-06ee-4b7d-ae91-b99bc6382d13','頌古十九首  其一二','釋法全','宋','宋诗','song-poetry','','[]','鉢裏飯，桶裏水，狗子咬人不露齒。',32,'全唐诗/poet.song.120000.json','["鉢裏飯，桶裏水，狗子咬人不露齒。", "堪笑韶陽老古錐，倒地至今猶未起。"]'),
('8314ba89-f098-49b1-b949-a7630febd81d','頌古十九首  其一三','釋法全','宋','宋诗','song-poetry','','[]','七里灘頭多蛤子，太陽一出口俱開。',32,'全唐诗/poet.song.120000.json','["七里灘頭多蛤子，太陽一出口俱開。", "平生肝膽雖然露，狡鶻何曾逐臭來。"]'),
('892eb06d-996c-4ceb-bd40-f33a718d308c','頌古十九首  其一四','釋法全','宋','宋诗','song-poetry','','[]','耳裏種田，滿口含烟。',26,'全唐诗/poet.song.120000.json','["耳裏種田，滿口含烟。", "鍾馗解舞十八拍，張老乘槎上九天。"]'),
('e9e1f6e6-79c9-4e8c-9b17-9d027efd2439','頌古十九首  其一五','釋法全','宋','宋诗','song-poetry','','[]','石火光中爛熳遊，白拈臨濟未同儔。',32,'全唐诗/poet.song.120000.json','["石火光中爛熳遊，白拈臨濟未同儔。", "掀反華岳連天黑，幾箇知身在御樓。"]'),
('0208b3d7-4e93-4645-8849-eebbddd35bb4','頌古十九首  其一六','釋法全','宋','宋诗','song-poetry','','[]','八十翁翁著繡靴，踏開幽洞笑呵呵。',32,'全唐诗/poet.song.120000.json','["八十翁翁著繡靴，踏開幽洞笑呵呵。", "傍人指點忘歸路，不覺腰間爛斧柯。"]'),
('a17e71a5-4a71-4c93-8d10-78255b5a38ba','頌古十九首  其一七','釋法全','宋','宋诗','song-poetry','','[]','西天人不會唐言，旱地雷聲徹大千。',32,'全唐诗/poet.song.120000.json','["西天人不會唐言，旱地雷聲徹大千。", "九年面壁無人會，玉兔金烏火裏旋。"]'),
('f8e6c154-d8db-4750-82bb-de7625333f51','頌古十九首  其一八','釋法全','宋','宋诗','song-poetry','','[]','馬轉牛回豈足誇，爛泥中刺當行家。',32,'全唐诗/poet.song.120000.json','["馬轉牛回豈足誇，爛泥中刺當行家。", "霜刃一揮全意氣，坐令千載定龍蛇。"]'),
('86d89f06-c71f-42f6-9586-fdc165ee8bc8','頌古十九首  其一九','釋法全','宋','宋诗','song-poetry','','[]','幾回霑水又拖泥，年老心孤不自知。',32,'全唐诗/poet.song.120000.json','["幾回霑水又拖泥，年老心孤不自知。", "遊子不歸空悵望，一溪流水落花隨。"]'),
('67799b0d-1d00-4c7c-8def-ae2645ce2b1e','彭思王廟','任續','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','背僊眠兮芳洲，蕩兩槳兮碧流。',143,'全唐诗/poet.song.120000.json','["背僊眠兮芳洲，蕩兩槳兮碧流。", "陟崔嵬兮拜神宮，跨汗漫兮俯文虹。", "浩唱兮擊鼓絲，陽阿兮屢舞。", "降神焚兮百和，尊瑶觴兮綠醑。", "九關闢兮杳雲旗，回風下兮帝子來。", "周覽兮故國，我與民兮相思。", "靈容兮有穆，笑燦然兮扁祥。", "風雨暘時兮歲事豐，厲鬼回兮畢方逐。", "包洞庭兮二江，扞崇山兮五嶽。", "揚靈兮報祀，與山川兮長久。"]'),
('6b0d2b33-e10d-43e1-ad75-665e627536dc','賦玩珠巖','任續','宋','宋诗','song-poetry','','[]','山林自空闃，遊人事幽討。',264,'全唐诗/poet.song.120000.json','["山林自空闃，遊人事幽討。", "岫幌與雲關，來跡可堪掃。", "艮維矗孤峰，玉簪倚天杪。", "桂水琉璃碧，洄洑下縈繞。", "谽谺巖穴深，虬龍雙夭矯。", "坤倪露幽秘，造化殫奇巧。", "勝概畜眼無，何方覓蓬島。", "悠悠世俗情，是非苦膠擾。", "水中蟹何罪，徒勞慍心悄。", "人厄困無妄，礫石埋深窈。", "風月幾年恨，山光慘蘿蔦。", "星郎太嶽孫，長城隱南表。", "戎旃整且暇，高情恣登眺。", "郊坰擁小隊，一見顔色愀。", "舊觀俄頃復，洞戶天重曉。", "傷心日月遒，人世幾番老。", "山川不相似，歲久依然好。", "呂巖標强名，往事人能道。", "孟公謾驚座，子夏冠非小。", "桃符錄餘慶，邲戰城濮兆。", "冥數今乃驗，常情定誰考。", "哦詩紀貞石，聊侑芳尊醥。"]'),
('2408a404-919b-4bb3-9c4d-ebfc33883bfa','答郡守趙師夔','金梁之','宋','宋诗','song-poetry','','[]','王侯門戶懶開顔，斗酒千錢一笑間。',64,'全唐诗/poet.song.120000.json','["王侯門戶懶開顔，斗酒千錢一笑間。", "無雪可欺青檜老，有天難管白雲閑。", "丹霄作客曾騎鶴，紫府爲家不買山。", "京口相逢又相別，隻琴孤劍幾時還。"]'),
('5a927348-1876-44f4-8666-86167a00b134','郡侯雪天開宴即席以填字韻索詩','金梁之','宋','宋诗','song-poetry','','[]','昨夜嫦娥弄玉纖，也應掐月作花鈿。',32,'全唐诗/poet.song.120000.json','["昨夜嫦娥弄玉纖，也應掐月作花鈿。", "爲嫌梅影太清瘦，幾片飛來疎處填。"]'),
('d3bb1def-46f5-410b-bf4a-ef65ba1700d6','贈郡士張夢錫赴南宮試','金梁之','宋','宋诗','song-poetry','','[]','秧針刺水麥鋒齊，漠漠平沙白鷺飛。',32,'全唐诗/poet.song.120000.json','["秧針刺水麥鋒齊，漠漠平沙白鷺飛。", "盡道春光已歸去，清香猶有野薔薇。"]'),
('c62457a2-bf45-4899-ae83-d808499850a6','句','金梁之','宋','宋诗','song-poetry','','[]','寄語月溪朱逸士，他年同賞水仙花。',16,'全唐诗/poet.song.120000.json','["寄語月溪朱逸士，他年同賞水仙花。"]'),
('487f6550-414c-4462-841f-cd5a123382d8','送別湖北漕李秘監仁甫','林光朝','宋','宋诗','song-poetry','','[]','文字眇煙雲，過眼徒浩浩。',168,'全唐诗/poet.song.120000.json','["文字眇煙雲，過眼徒浩浩。", "所有未見書，惜哉吾已老。", "子雲客長安，陳迹如一掃。", "同叔向來人，我生苦不早。", "亦聞青城山，斯翁爲有道。", "瞿塘不可上，秋夢長顛倒。", "白日來西崑，一見自應好。", "縱談百代前，至竟非枯槁。", "多爲開口笑，明月生懷抱。", "黄鶴有高樓，恍如事幽討。", "攬轡逢道州，聽書下下考。", "周南勿留滯，掇拾供史藁。", "分手重酸辛，璠璵眾所寶。", "十日不得面，何爲太草草。"]'),
('102cbc7b-fb77-47d7-921b-db893e594ea5','送別姚國博知處州分韻得綠字','林光朝','宋','宋诗','song-poetry','','[]','銅盤白露下，松桂凈如沐。',180,'全唐诗/poet.song.120000.json','["銅盤白露下，松桂凈如沐。", "孌彼菊花團，西風吹醽醁。", "長安多別離，此別苦不足。", "人物如使君，容易等潘陸。", "一自海東頭，清飚起謠俗。", "館下欲何言，聯翩如破竹。", "功名不徒爾，無乃相迫逐。", "雙日訪延英，行矣公勿卜。", "括蒼煙雨前，寒光貫巖腹。", "大叫出銀甖，邂逅聚百族。", "要携三月糧，所厭惟一掬。", "幸心忽開張，何曾畏笑僇。", "單父勿長吁，來者猶可續。", "道旁有抵璧，天下輕結綠。", "一夕洲渚言，令我沉心曲。"]'),
('56229540-921c-424b-a50e-db74c1234b5b','代陳季若上倉使','林光朝','宋','宋诗','song-poetry','','[]','大塊始開鑿，媧皇爲補天。',288,'全唐诗/poet.song.120000.json','["大塊始開鑿，媧皇爲補天。", "天平雷雨正，后稷誨之田。", "大浸十二歲，流金復七年。", "幸哉堯湯民，以手摩撫然。", "徂丘虐焰起，秦俗相焚煎。", "官租奪以半，飽食何夤緣。", "自從漢道昌，敦樸乃其先。", "初開常平議，聚粟如源泉。", "年登穀價賤，散以大農錢。", "旱潦或艱食，用之如轉圜。", "悠悠百王心，皎皎三代前。", "井田日以壞，此法當磨鎸。", "公侯希世珍，秀色媚長川。", "官學有根株，誦詩三百篇。", "風土無隱情，是爲大夫賢。", "摶飯哺赤子，當食長爾憐。", "江東百萬戶，彫俗生春妍。", "持節閩嶺初，有如病者痊。", "劉晏取予術，夷吾輕重權。", "義倉有粟腐，物價敢喧闐。", "斯助阜民政，南風吹五絃。", "晝日公侯門，客車動百千。", "下吏走塵土，從容愧執鞭。", "豈不隨吹噓，譬彼乘風船。"]'),
('eb0b72ac-7e68-4831-a2fe-bbf4925ca566','石渠行送別福建參議李著作器之','林光朝','宋','宋诗','song-poetry','','[]','我來石渠五十六，雙鬢如蓬腰未曲。',160,'全唐诗/poet.song.120000.json','["我來石渠五十六，雙鬢如蓬腰未曲。", "豈爲健筆有徐庾，自數來時六十五。", "誰解辛苦續子虛，長安有客四十餘。", "已成老翁不肯去，青藜當戶夜讀書。", "東觀丈人起遐想，無爲歲月空踟躕。", "去作諸侯老賓客，可無綠水兼紅蕖。", "我家東下纔百里，釣螺一曲清無滓。", "草堂爲筑荔枝斜，濯錦江頭有如是。", "子思子方道爲尊，南國佳人如秋雲。", "不知公侯有朱箔，要問常州李著作。"]'),
('f2174cba-b518-48e8-a8f8-e83515f3a3f6','資中行奉寄臨邛守宇文郎中','林光朝','宋','宋诗','song-poetry','','[]','銅駝陌上生秋草，前者刻石今如掃。',194,'全唐诗/poet.song.120000.json','["銅駝陌上生秋草，前者刻石今如掃。", "儋邊半紙半糢糊，下牀三日成悲惱。", "蒼史萌芽何可見，要從筆意生秦漢。", "欲將奇字問何人，所守一家如小篆。", "是中變幻隨形模，鐘鎛鼎鬲匜盤盂。", "如何兩京到魏晉，搜盡蒼崖惟此書。", "即今原隸見顛末，仍於畫上分錙銖。", "燕然有年固可紀，筆勢豈得先黄初。", "中郎袖手欲無作，正始不逮況其餘。", "幸哉一見俱抵掌，翩翩如反古石渠。", "且說金陵佛屋何年燈，晉分隋張猶青熒。", "忽聽荒雞還自起，資中之刻不徒爾。"]'),
('c97e8a15-d98b-4958-be23-658f8da76145','鞭春行','林光朝','宋','宋诗','song-poetry','','[]','轆轤罥寒田雀饑，江梅落蛀兔脚肥。',64,'全唐诗/poet.song.120000.json','["轆轤罥寒田雀饑，江梅落蛀兔脚肥。", "枯腸一夜轉雙轂，眼光吹上蝦蟆衣。", "巖腹新晴山鬼哭，女媧墳外春風歸。", "繭村紙簾大如蓆，拆拆藜杖金雀飛。"]'),
('2db82eba-20f2-4ece-9328-f713c97178d2','癡頑不識字歌許叔節來詩有此句因以名篇','林光朝','宋','宋诗','song-poetry','','[]','平生讀書，如風過耳。',202,'全唐诗/poet.song.120000.json','["平生讀書，如風過耳。", "歲月共流轉，如磨復如蟻。", "一如人嚼蠟，而不見其味。", "又如弄孤杵，連夜不成米。", "又如過羊腸，十步復一止。", "年頭月尾無一是，咄咄癡頑不識字。", "見君詩，舌如黐，愧我爲人師。", "怪怪奇奇，如懸崖萬仞龍盤古樹枝。", "又如生馬不施鞚而馳，又如錦苔封漫峴山千年墮淚碑。", "又如玉關客，血上老犀衣。", "盧仝孟郊骨已朽，眼睛頭顱何人相傳授。", "與君往還歲月久，比來春風入我牖，便覺巖前草木件件有生意。", "跨蹇驢，出古寺，欲訪子雲問難字。"]'),
('a5736602-86d1-4504-956e-bfa136f5c5ca','乞竹雞','林光朝','宋','宋诗','song-poetry','','[]','疏籬短短花枝闌，鳩婦不鳴天雨寒。',182,'全唐诗/poet.song.120000.json','["疏籬短短花枝闌，鳩婦不鳴天雨寒。", "鳩婦離家三百日，亦有姊妹依故山。", "黄糧不肯啄，欲去羽衣殘。", "主人一見一憐汝，抱取東家竹雞來戲聚。", "孤村落日不相識，各各哀鳴求其主。", "兩鳥勿驚遽，低頭聽我語。", "鳩婦入我家，必殺入我口。", "牀頭瓶罌無餘粒，養汝一到十日後。", "東堂數竹夾新蹊，兒童牢落惟愛一竹雞。", "堂心有眢井，饑則哺其泥。", "主人緣窗安浄几，丹碧相依安用此竹雞。", "竹雞慎勿傍人飛，我屋三間沉白蟻。"]'),
('b4c91f1b-3b50-4b6b-99c8-428f582b2fb0','冬至','林光朝','宋','宋诗','song-poetry','','[]','橫枝凍雀昨夜死，水底黏魚吹不起。',100,'全唐诗/poet.song.120000.json','["橫枝凍雀昨夜死，水底黏魚吹不起。", "小伶切玉孤鳳愁，九寸之管傳生意。", "舞雩山下逢丈人，植杖無語空逡巡。", "再拜丈人欲識桑麻生長力，鬼蝶翻覆梅花春。", "我於萬物亦一物，何時春風到肌骨。", "空山鐵鏑年月深，一語不破天地心。"]'),
('a21aa86d-a794-4da5-884d-7f7613d2a534','徐廣文生朝','林光朝','宋','宋诗','song-poetry','','[]','盤古一笑鴻濛開，神馬負圖從天來。',160,'全唐诗/poet.song.120000.json','["盤古一笑鴻濛開，神馬負圖從天來。", "八卦旋轉六十四，黄鍾是爲元氣胎。", "雷斧未動百泉縮，江上早見春風回。", "况當九日得陽數，太白之精隨斗魁。", "徐卿有子何絕奇，熊羆驚夢初得之。", "珠庭犀角照宇宙，清飚忽忽生桂枝。", "筆落猶如千鈞弩，異科暫失韓吏部。", "絳帳初隨吾道東，遂令小邦變齊魯。", "孔席豈是三年淹，蓬萊畫閣鋪牙籤。", "他年欲數中書考，再拜祝公長不老。"]'),
('98962e46-c1e5-463f-a416-f5f98cb5a37b','丞相特進觀文南陽公挽詞','林光朝','宋','宋诗','song-poetry','','[]','一相頻虛位，千齡要實才。',48,'全唐诗/poet.song.120000.json','["一相頻虛位，千齡要實才。", "廟謨從此定，邊鎖未應開。", "東閣嘗先到，西州重一哀。", "傳家惟儉德，何處著樓臺。"]'),
('0f5fced6-aa20-42e0-9f02-af6d1f7a4732','吏部尚書林公梅卿挽詞','林光朝','宋','宋诗','song-poetry','','[]','百紙梅花賦，聲名出渚東。',48,'全唐诗/poet.song.120000.json','["百紙梅花賦，聲名出渚東。", "向來惟李賀，勝處是揚雄。", "繞屋看書带，逢人說刺桐。", "尚書舊時履，只合步春風。"]'),
('a84bbe40-28e8-4330-a24c-211adfb1e2a5','挽桂林戴別乘敦常','林光朝','宋','宋诗','song-poetry','','[]','杖屨何年別，杉松古道旁。',48,'全唐诗/poet.song.120000.json','["杖屨何年別，杉松古道旁。", "城山秋月盡，南嶺暮雲長。", "古調愁難合，孤根幸勿傷。", "欲將數行淚，重至鄭公鄉。"]'),
('bb33d94d-808b-4441-add1-13e68da5b558','挽方天貺','林光朝','宋','宋诗','song-poetry','','[]','長者雖云歿，流風尚爾存。',48,'全唐诗/poet.song.120000.json','["長者雖云歿，流風尚爾存。", "宗盟修里巷，家法在兒孫。", "馬鬣迷新壟，鳩枝戀故園。", "年年春色好，錦障爲誰翻。"]'),
('15aa9882-e4a4-46ec-914d-a7a682cba818','東宮生日六首 壬辰','林光朝','宋','宋诗','song-poetry','','[]','北闕雲爲堞，東明玉作宮。',120,'全唐诗/poet.song.120000.json','["北闕雲爲堞，東明玉作宮。", "猗蘭迎曉日，仙掌倚晴空。", "笙律隨鳴鳳，朝儀趁彩虹。", "黄麾初入仗，青桂自成叢。", "冠屨分前後，圖書考異同。", "商盤如目擊，羲畫自心通。", "慈燕來三殿，驩謠在九功。", "長秋傳夜飲，京兆報年豐。", "奕奕還嘉祐，綿綿想建隆。", "庶僚何所祝，再拜續維熊。"]'),
('0be69fde-1216-4786-811c-3da0be490830','東宮生日六首 癸巳','林光朝','宋','宋诗','song-poetry','','[]','昭代璿源遠，高秋寶月前。',120,'全唐诗/poet.song.120000.json','["昭代璿源遠，高秋寶月前。", "神光浮蜀道，瑞氣貫秦川。", "銀榜應如舊，金莖若箇邊。", "龍樓清晝出，鶴禁彩雲連。", "妙選衣冠藪，旁開道德淵。", "重爻分九六，曲禮盡三千。", "歲閏緣長曆，霜清欲上弦。", "每看禖燕日，已入夢熊篇。", "沆瀣通三殿，笙鸞共一天。", "東明到西極，作頌自年年。"]'),
('10dd781f-6c50-4649-942a-523389245add','東宮生日六首 甲午','林光朝','宋','宋诗','song-poetry','','[]','仙掌秋容媚，銅樓曉色遲。',120,'全唐诗/poet.song.120000.json','["仙掌秋容媚，銅樓曉色遲。", "猗蘭成漢殿，苞竹入周詩。", "鼎卜卿雲合，郊禖彩仗移。", "隆興乾道日，建武永平時。", "詹事開新府，長秋綴舊儀。", "禮經猶下問，易道本生知。", "世子家爲法，文王我所師。", "誕彌重海潤，清賞一天慈。", "九月黄金蕊，千齡白玉巵。", "遥聞三殿喜，高頌走天涯。"]'),
('1472a105-3626-44b0-a13a-20f0e1689da0','東宮生日六首 乙未','林光朝','宋','宋诗','song-poetry','','[]','應律隨豳雅，旋杓建戌方。',120,'全唐诗/poet.song.120000.json','["應律隨豳雅，旋杓建戌方。", "前星迎霽色，重日麗晨光。", "笙管青霞外，宮庭碧玉傍。", "本支周道盛，羽翼漢圖昌。", "左右人皆正，刑名學未遑。", "編年聽司馬，說禮付高堂。", "天樂來三殿，人心繫八荒。", "黄華秋更媚，皓月閏偏長。", "清賞新奎壁，承華舊典章。", "維熊千歲祝，英略似君王。"]'),
('4a740ded-25c4-473f-a1de-dc7c7fbb63ea','東宮生日六首 丙申','林光朝','宋','宋诗','song-poetry','','[]','正氣來嵩岱，祥光集斗牛。',120,'全唐诗/poet.song.120000.json','["正氣來嵩岱，祥光集斗牛。", "青葱開玉宇，髣髴見銅樓。", "盤錯歸三輔，沉潜在九疇。", "有光文字館，仍繫帝王州。", "鐘鼓于胥樂，笙鸞獨上浮。", "清臺天似水，甲觀月如鈎。", "屢拜椒花夕，長逢桂葉秋。", "孝思維繼舜，家法要從周。", "賦爲游麟作，官因洗馬留。", "願同眉壽祝，使者敢停輈。"]'),
('0ec19fa4-45e5-4587-a66b-3433a81e69ba','東宮生日六首 丁酉','林光朝','宋','宋诗','song-poetry','','[]','僊掌晴煙外，龍樓曉日傍。',120,'全唐诗/poet.song.120000.json','["僊掌晴煙外，龍樓曉日傍。", "漢圖元自定，周曆一何長。", "胄席緣三老，奎文在六章。", "高禖曾鬰鬰，喬桂自蒼蒼。", "冠屨來儲禁，規模出上方。", "名官分庶子，說禮繼高堂。", "孌彼黄花月，依然碧玉牆。", "至尊飛壽斝，太上引天香。", "景運千齡協，先秋九日凉。", "銅扉供帳少，儉德似君王。"]'),
('ba5b15ee-0910-42ad-bb24-42b1d14c39f3','次韻奉酬趙校書子直','林光朝','宋','宋诗','song-poetry','','[]','雁塔新題墨未乾，去年燈火向秋闌。',64,'全唐诗/poet.song.120000.json','["雁塔新題墨未乾，去年燈火向秋闌。", "趣看天祿青藜杖，怕著王孫紫綺冠。", "好在三山尋浩渺，何如一紙問平安。", "觚稜放月無人到，玉糝初成許共餐。"]'),
('79ef8a71-52df-41cd-9256-8aea49127261','次韻呈胡侍郎邦衡','林光朝','宋','宋诗','song-poetry','','[]','聲教從今已遠覃，翩翩作者問誰堪。',64,'全唐诗/poet.song.120000.json','["聲教從今已遠覃，翩翩作者問誰堪。", "石經猶有中郎蔡，金匱曾誇太史談。", "至竟銀鈎并鐵畫，相傳海北到天南。", "諸生考古頭渾白，禹穴何時更許探。"]'),
('4415d041-23fa-4d1d-8a97-7839ae2c6555','九日同出真珠園再用前韻','林光朝','宋','宋诗','song-poetry','','[]','來自清源葛已覃，君王問獵我猶堪。',64,'全唐诗/poet.song.120000.json','["來自清源葛已覃，君王問獵我猶堪。", "百年耆舊如重見，九日登臨得縱談。", "才子不知汾水上，仙人長在大江南。", "明珠照夜應無數，要是層波更好探。"]'),
('02138230-b48d-49c0-b3d0-bc3fa7c02722','送別傅郎中安道持節閩中','林光朝','宋','宋诗','song-poetry','','[]','忽然鄉思若爲收，莫到三茅最上頭。',64,'全唐诗/poet.song.120000.json','["忽然鄉思若爲收，莫到三茅最上頭。", "二月東甌看負弩，一天南蕩想行舟。", "過家上冢從今數，落絮飛花合晝游。", "料得甘泉來奏計，定應前席莫遲留。"]'),
('20820f68-d3c9-4345-b8bd-f6914523ed18','八月十五日道出南昌寄龔帥實之兼呈程泰之劉文潜二漕','林光朝','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','未應雙井即塵埃，似此衣冠得幾回。',64,'全唐诗/poet.song.120000.json','["未應雙井即塵埃，似此衣冠得幾回。", "國子先生還並駕，洪都新府却重開。", "再三爲問滕王閣，第一須登孺子臺。", "定向此中脩翫事，江邊不道故人來。"]'),
('ac710ca8-f8ba-4ebd-aaf6-f5a5037adb2e','閏月九日登越王臺次韻經略敷文所寄詩','林光朝','宋','宋诗','song-poetry','','[]','閑陪小隊出山椒，爲有吳歌雜楚謠。',64,'全唐诗/poet.song.120000.json','["閑陪小隊出山椒，爲有吳歌雜楚謠。", "縱道菊花如昨日，要看湯餅作三朝。", "千重嶺海供橫槊，一带風煙聽采樵。", "憑仗折衝如此好，不應東去更乘軺。"]'),
('1c415647-a36f-43b4-af5c-9dfe5b3a5b18','再次前韻','林光朝','宋','宋诗','song-poetry','','[]','却趁秋旻別九韶，扶胥直下聽風謠。',64,'全唐诗/poet.song.120000.json','["却趁秋旻別九韶，扶胥直下聽風謠。", "瀾翻對酒還終夕，火急催詩在詰朝。", "南國更逢陶令菊，西江莫扞楚人樵。", "自應幕下文書少，節制如今屬漢軺。"]'),
('affa66f7-b196-4e24-b257-74f2cace17eb','前歲過真陽初識子欽今道出曲江不忍遽分手偶成長句以志兩處山川人物之勝亦少慰別來耿耿耳','林光朝','宋','宋诗','song-poetry','','[]','秋崖一夕卷炎蒸，那更揮斤爲斲冰。',64,'全唐诗/poet.song.120000.json','["秋崖一夕卷炎蒸，那更揮斤爲斲冰。", "碧落舊尋燒藥竈，白芒長對讀書燈。", "相期大庾何多日，似出浮屠向上層。", "縱有分張吾未老，定從臺閣看飛騰。"]'),
('0c74bdc6-eb4f-4ea5-a0d7-a4e005d1bce4','送別奉常林使君黄中易守延平','林光朝','宋','宋诗','song-poetry','','[]','去時胡不到瓜時，上日多應柳絮飛。',64,'全唐诗/poet.song.120000.json','["去時胡不到瓜時，上日多應柳絮飛。", "卧轍只緣滕壤少，懷章須要越人肥。", "三千儀禮非綿蕝，五十行春尚綵衣。", "莫愛傳經似齊魯，石渠長是待公歸。"]'),
('f20c7bac-f0fe-4d89-bdb3-a5a160a5eb40','枕疾逾旬蒙丞相訪問仍辱寵示名篇輒搜枯腸次嚴韻以塞來使','林光朝','宋','宋诗','song-poetry','','[]','丞相嚴裝似燕居，爲憐消渴到相如。',64,'全唐诗/poet.song.120000.json','["丞相嚴裝似燕居，爲憐消渴到相如。", "病多得艾三年遠，歌雜成琴十日餘。", "綠野忽傳春草句，白頭還對朵雲書。", "若爲追逐園林勝，百轉愁腸亦少舒。"]'),
('53561fc3-63c1-41b5-9d71-e16c7b07e2c8','次韻賀邱國鎮致仕','林光朝','宋','宋诗','song-poetry','','[]','桃花流水是家鄉，洛下才名四十强。',64,'全唐诗/poet.song.120000.json','["桃花流水是家鄉，洛下才名四十强。", "自有赤松堪辟穀，那能白首更爲郎。", "案頭貝葉忘言久，江上蓴羹引興長。", "解后却成香火社，好將詩句細商量。"]'),
('03611d03-cebf-4b4f-a6df-1ddd14ba4e57','芹齋詩','林光朝','宋','宋诗','song-poetry','','[]','春風芹下足遲留，白鳥平田憶舊游。',64,'全唐诗/poet.song.120000.json','["春風芹下足遲留，白鳥平田憶舊游。", "說盡軒裳還過眼，讀殘書卷復從頭。", "偶逢隱几何須問，不到投簪便擬休。", "平世聲名如皦日，欲將何地置巢由。"]'),
('47df5d3d-a5f0-4e56-8933-dd5987f62005','奉題游洋張明府流香亭時以薦章數下涉秋月馬首且欲西矣因以寄意云','林光朝','宋','宋诗','song-poetry','','[]','封題青李數緋桃，處分園林意自豪。',64,'全唐诗/poet.song.120000.json','["封題青李數緋桃，處分園林意自豪。", "旋出篇章陪樂府，更憑花木續離騷。", "酴醾架下提春榼，薝蔔林中滴夜槽。", "却是秋風生馬耳，未應老大笑牛刀。"]'),
('aa5723c4-7ec9-4cd7-9b07-1b6453828ef4','送別陳侍郎應求知泉州','林光朝','宋','宋诗','song-poetry','','[]','百片牙旗水面長，蔡邕題在刺桐鄉。',64,'全唐诗/poet.song.120000.json','["百片牙旗水面長，蔡邕題在刺桐鄉。", "十年杯酒開雲榭，一樣官銜過洛陽。", "我亦携家緣送客，誰能掃地自焚香。", "野橋衝臘寒梅白，莫要登臨憶侍郎。"]'),
('40576745-53f2-4013-b5ef-1e074c651a50','傅使君安道再有治莆之命取道城外還泉南得來書云已出十里','林光朝','宋','宋诗','song-poetry','','[]','何事風流舊使君，江邊聽說下朱旛。',64,'全唐诗/poet.song.120000.json','["何事風流舊使君，江邊聽說下朱旛。", "逢迎要問平津邸，準擬來呼垤澤門。", "竹馬已喧明月浦，籃輿却出杏花村。", "不知錦瑟流傳徧，欲愈頭風好細論。"]'),
('4a4b4e79-b84e-4068-b931-6c001d29df90','挽李制幹子誠  其一','林光朝','宋','宋诗','song-poetry','','[]','千金治產似孫吳，珠箔銀觥只自如。',64,'全唐诗/poet.song.120000.json','["千金治產似孫吳，珠箔銀觥只自如。", "問我長風當夕起，數他極浦落帆初。", "自知汗簡今千軸，更說生犀有幾株。", "赤壁當年遇黄蓋，周郎何惜借吹噓。"]'),
('1a53aee2-a731-43a7-abd5-52a98802137b','挽李制幹子誠  其二','林光朝','宋','宋诗','song-poetry','','[]','文字紛紛更問兵，秋燈束髮尚青熒。',64,'全唐诗/poet.song.120000.json','["文字紛紛更問兵，秋燈束髮尚青熒。", "便令三子成門戶，却許諸孫說典型。", "隔水忽傳朝露曲，行人長數夕陽亭。", "河東健筆惟諸薛，梅子崗邊爲勒銘。"]'),
('736e7d25-c389-417f-a453-2947c65a3278','別方次雲','林光朝','宋','宋诗','song-poetry','','[]','姑蘇臺上姑蘇館，共說南山竹火爐。',32,'全唐诗/poet.song.120000.json','["姑蘇臺上姑蘇館，共說南山竹火爐。", "湖上相逢又相別，不知何處說姑蘇。"]'),
('cbf504f0-2f8b-4352-8784-1f24b17c6731','代陳季若上張帥  其一','林光朝','宋','宋诗','song-poetry','','[]','一樣官儀漢代新，乘時大手與經綸。',32,'全唐诗/poet.song.120000.json','["一樣官儀漢代新，乘時大手與經綸。", "東南自古衣冠地，桐柏山前淮水春。"]'),
('4cc2a451-c16c-440c-8a7f-333385800da9','代陳季若上張帥  其二','林光朝','宋','宋诗','song-poetry','','[]','峨峨雙闕晝煙橫，玉籙金箱記姓名。',32,'全唐诗/poet.song.120000.json','["峨峨雙闕晝煙橫，玉籙金箱記姓名。", "況有曲江家舊渚，小虹橋外柳花輕。"]'),
('52a277c3-b009-4b07-b566-e8e8cb5cf726','代陳季若上張帥  其三','林光朝','宋','宋诗','song-poetry','','[]','晉公當日只平淮，何事都人尚爾懷。',32,'全唐诗/poet.song.120000.json','["晉公當日只平淮，何事都人尚爾懷。", "客有昌黎韓吏部，獨將大筆掃蒼苔。"]'),
('3f6dba4d-153d-442b-aed7-fd5512ca5c49','代陳季若上張帥  其四','林光朝','宋','宋诗','song-poetry','','[]','長陪綵仗下蓬萊，萬歲聲中霽色開。',32,'全唐诗/poet.song.120000.json','["長陪綵仗下蓬萊，萬歲聲中霽色開。", "自是北門須卧護，雙旌迢遞日邊來。"]'),
('2210da6f-6dd0-45f1-9d6d-fdba8003b51f','代陳季若上張帥  其五','林光朝','宋','宋诗','song-poetry','','[]','柳堤九曲暗青絲，畫戟叢中晝影遲。',32,'全唐诗/poet.song.120000.json','["柳堤九曲暗青絲，畫戟叢中晝影遲。", "傳說姑蘇新樂府，只緣太守例能詩。"]'),
('08143707-5d5f-4a47-8c72-02383ed75710','代陳季若上張帥  其六','林光朝','宋','宋诗','song-poetry','','[]','銅柱參天桂葉稠，公侯遺愛在南州。',32,'全唐诗/poet.song.120000.json','["銅柱參天桂葉稠，公侯遺愛在南州。", "繩橋竹屋連溪曲，大貝明珠盡海頭。"]'),
('1be80971-8bf1-423a-9061-aca6c60372b1','代陳季若上張帥  其七','林光朝','宋','宋诗','song-poetry','','[]','駘蕩春風散百城，釣鼇江上棹歌聲。',32,'全唐诗/poet.song.120000.json','["駘蕩春風散百城，釣鼇江上棹歌聲。", "官軍不遣征徭少，燒盡柴爐說太平。"]'),
('6f62631c-ace9-4cab-82fb-8030696a12ab','代陳季若上張帥  其八','林光朝','宋','宋诗','song-poetry','','[]','天邊草木舊知名，爲道潢池莫弄兵。',32,'全唐诗/poet.song.120000.json','["天邊草木舊知名，爲道潢池莫弄兵。", "野市旋收黄犢去，明時火急趁春耕。"]'),
('71faed04-838d-4d00-ade2-532a3b6ba6b8','代陳季若上張帥  其九','林光朝','宋','宋诗','song-poetry','','[]','欲將玉律播平康，長見單于拜未央。',32,'全唐诗/poet.song.120000.json','["欲將玉律播平康，長見單于拜未央。", "相國正須如治郡，春風隨處有甘棠。"]'),
('78dd1520-a16e-489c-8f00-85febc806624','代陳季若上張帥  其一○','林光朝','宋','宋诗','song-poetry','','[]','南牆鉅竹拂青煙，正在空齋簿領前。',32,'全唐诗/poet.song.120000.json','["南牆鉅竹拂青煙，正在空齋簿領前。", "欲向韓門借餘潤，乞將白璧種藍田。"]'),
('369d4b70-cb1e-4053-b055-bee894790aee','直甫見示次雲乞豫章集數詩偶成二小絕因以自喻  其一','林光朝','宋','宋诗','song-poetry','','[]','修水佳人白玉欄，花前何似妾容顔。',32,'全唐诗/poet.song.120000.json','["修水佳人白玉欄，花前何似妾容顔。", "從來未省傷春意，猶自樓頭畫遠山。"]'),
('2c1af715-72ed-4901-bf33-ded79de7f75b','直甫見示次雲乞豫章集數詩偶成二小絕因以自喻  其二','林光朝','宋','宋诗','song-poetry','','[]','莫怪騷人太頡頏，曾聞阿母語劉郎。',32,'全唐诗/poet.song.120000.json','["莫怪騷人太頡頏，曾聞阿母語劉郎。", "神仙本自無言說，尸解由來最下方。"]'),
('b60ac5a1-b384-4297-9506-3fbd0673d7b6','吳容州仲一挽詞','林光朝','宋','宋诗','song-poetry','','[]','竹屋繩橋自有村，牛山簫笛不堪聞。',32,'全唐诗/poet.song.120000.json','["竹屋繩橋自有村，牛山簫笛不堪聞。", "碑前更問何年月，爲借容州舊使君。"]'),
('97807131-ec51-418a-9416-2e9b754796cb','挽方通判良翰  其一','林光朝','宋','宋诗','song-poetry','','[]','樓櫓千重鐵作門，不堪聚米更重論。',32,'全唐诗/poet.song.120000.json','["樓櫓千重鐵作門，不堪聚米更重論。", "居延歲月那相似，一聽悲歌一斷魂。"]'),
('aad15882-070b-47f4-b63e-65e988329dd5','挽方通判良翰  其二','林光朝','宋','宋诗','song-poetry','','[]','得錢終日走燕寺，抱膝經年動越吟。',32,'全唐诗/poet.song.120000.json','["得錢終日走燕寺，抱膝經年動越吟。", "想得長安西望眼，只應黄鵠見歸心。"]'),
('9ed734e0-1bf8-422c-af56-69566545ce3a','挽方通判良翰  其三','林光朝','宋','宋诗','song-poetry','','[]','達者淵明自挽歌，新墳數尺奈愁何。',32,'全唐诗/poet.song.120000.json','["達者淵明自挽歌，新墳數尺奈愁何。", "雞林賈客無從問，收拾篇章有幾多。"]'),
('98645c58-8aaa-466d-8999-aac953caf29c','挽方通判良翰  其四','林光朝','宋','宋诗','song-poetry','','[]','九死穹廬我未甘，後來勿使隴西慚。',32,'全唐诗/poet.song.120000.json','["九死穹廬我未甘，後來勿使隴西慚。", "明時節義多傳述，柱下何人是老聃。"]'),
('9c60614f-120b-47ea-83e3-b2a1264babea','挽林通判德溥  其一','林光朝','宋','宋诗','song-poetry','','[]','豈爲長者畏時名，梁楚何從得此聲。',32,'全唐诗/poet.song.120000.json','["豈爲長者畏時名，梁楚何從得此聲。", "只隔螺江衣带水，自應別駕舊廉平。"]'),
('843e4a02-dd83-4b58-a6f6-cfc2d4a29cde','挽林通判德溥  其二','林光朝','宋','宋诗','song-poetry','','[]','噫嗚雙柩出平川，五月黄梅欲雨天。',32,'全唐诗/poet.song.120000.json','["噫嗚雙柩出平川，五月黄梅欲雨天。", "長愧江南徐孺子，隻雞斗酒是何年。"]'),
('8d51975d-8c84-4061-98f9-868b6cd9bc5e','哭徐刪定德襄  其一','林光朝','宋','宋诗','song-poetry','','[]','修文巷裏莫春前，欲上旗亭問客船。',32,'全唐诗/poet.song.120000.json','["修文巷裏莫春前，欲上旗亭問客船。", "忽有短牋無寄處，漁梁却在淚痕邊。"]'),
('229f7ffa-de2b-4fa1-88d6-102532ecf854','哭徐刪定德襄  其二','林光朝','宋','宋诗','song-poetry','','[]','忽然白晝自生哀，立馬橋東喚不回。',32,'全唐诗/poet.song.120000.json','["忽然白晝自生哀，立馬橋東喚不回。", "驚起河波理殘夢，十年燈火上心來。"]'),
('ff529704-6978-428f-8d1b-faacdb40b0b4','哭伯兄鵲山處士蒿里曲  其一','林光朝','宋','宋诗','song-poetry','','[]','殘雲衰草趁人愁，生即團欒死便休。',32,'全唐诗/poet.song.120000.json','["殘雲衰草趁人愁，生即團欒死便休。", "悲泣聲中裁此曲，雞啾山外鵲山頭。"]'),
('9d765314-58b9-4ed1-997a-9e8affca28e5','哭伯兄鵲山處士蒿里曲  其二','林光朝','宋','宋诗','song-poetry','','[]','長記藜牀發問初，翩翩出語自無餘。',32,'全唐诗/poet.song.120000.json','["長記藜牀發問初，翩翩出語自無餘。", "斯翁胸腹平如水，不在塵埃數卷書。"]'),
('344aa3f0-ecd7-440d-b9ee-c1a427177c70','哭伯兄鵲山處士蒿里曲  其三','林光朝','宋','宋诗','song-poetry','','[]','桐棺三寸更何疑，却取江楓短作碑。',32,'全唐诗/poet.song.120000.json','["桐棺三寸更何疑，却取江楓短作碑。", "惟有一般蒿里曲，長簫欲斷更教吹。"]'),
('9b63af32-190b-43d0-9986-dad151e79a10','道桐廬有詩示成季','林光朝','宋','宋诗','song-poetry','','[]','此是灘頭處士家，我從何日離天涯。',32,'全唐诗/poet.song.120000.json','["此是灘頭處士家，我從何日離天涯。", "木棉高長雲成絮，瞿麥平鋪雪作花。"]'),
('a93823ef-5bf7-4469-9174-5cb3dbea7bd1','答人問忠恕而已矣','林光朝','宋','宋诗','song-poetry','','[]','南人偏識荔支奇，滋味難言只自知。',32,'全唐诗/poet.song.120000.json','["南人偏識荔支奇，滋味難言只自知。", "剛被北人來借問，香甜兩字且酬伊。"]'),
('01b29a58-a8e7-4992-817f-bb72c10d3586','答人問仁者安仁','林光朝','宋','宋诗','song-poetry','','[]','千年古道萬年堤，老牯循循不解迷。',32,'全唐诗/poet.song.120000.json','["千年古道萬年堤，老牯循循不解迷。", "牧子不知何處在，亂山荒草鷓鴣啼。"]'),
('e6541ce2-8df9-48e1-983d-7cc1be1255a6','生女','林光朝','宋','宋诗','song-poetry','','[]','貧家生一女，蟋蟀催寒杵。',70,'全唐诗/poet.song.120000.json','["貧家生一女，蟋蟀催寒杵。", "富家生一女，煖風來玉樹。", "富家生女纔及筓，阿官門前筑新堤。", "貧家不生女，飯牛小兒安得妻。", "荆釵玉璫各隨分，醉中之天無高低。"]'),
('88cd222a-9f0c-4b48-a88b-36914346cf3f','乞貓','林光朝','宋','宋诗','song-poetry','','[]','寧可時時被鼠煎，狂貓一夜不成眠。',32,'全唐诗/poet.song.120000.json','["寧可時時被鼠煎，狂貓一夜不成眠。", "廣南六月官軍到，見說人家斷火煙。"]'),
('8a11bee2-380b-4f87-968e-d6d698018009','同張明府遊國清湖','林光朝','宋','宋诗','song-poetry','','[]','一夕湖頭春欲動，便從湖尾穿蒲弄。',66,'全唐诗/poet.song.120000.json','["一夕湖頭春欲動，便從湖尾穿蒲弄。", "層波赤鯉不易得，縱有笭箵何所用。", "未應索句如索逋，昨者浮家仍有無。", "不然汗漫十日走重湖，更數大孤連小孤。"]'),
('c16f5e71-d182-45b6-8ced-6eaa3c5d63b7','城山國清塘','林光朝','宋','宋诗','song-poetry','','[]','燭龍醉倒不開眼，遮空萬里雲張繖。',112,'全唐诗/poet.song.120000.json','["燭龍醉倒不開眼，遮空萬里雲張繖。", "小舟塘外日溶溶，漁歌忽斷荷花風。", "倚巖僧舍扃深戶，我來跋涉拳肩股。", "喘停更促短筇上，怪石周遭卧萬鼓。", "況是秋風到此山，惟有孤鴻時往還。", "勞勞百年共纏縛，不似青山長自閑。", "古人古人嗟已遠，長歌商頌歸來晚。"]'),
('0675f38c-e22c-4279-9fdc-3facb56ce78c','送夾漈先生赴召','林光朝','宋','宋诗','song-poetry','','[]','別墅生涯富古今，凝流夢卜苦追尋。',64,'全唐诗/poet.song.120000.json','["別墅生涯富古今，凝流夢卜苦追尋。", "一封細札三家市，萬卷新書四海心。", "北闕龍吟清晝永，東臯猿嘯白雲深。", "滿懷經濟今休靳，聞道蒼生渴傅霖。"]'),
('2ead9300-85ff-4864-924a-492a2246c6d2','上何著作晉之','林光朝','宋','宋诗','song-poetry','','[]','曾向東南識大名，幾年懷想浙濤聲。',64,'全唐诗/poet.song.120000.json','["曾向東南識大名，幾年懷想浙濤聲。", "眾人欲殺定誰惜，與世不諧空自清。", "浩氣養成天地小，宦情都付羽毛輕。", "三山依約誅茅日，頭白歸來笑李生。"]'),
('186784f0-4546-466d-972c-411b716dac37','題張元鼎風雨齋','孫介','宋','宋诗','song-poetry','','[]','張侯好兄弟，韡韡棠棣芳。',120,'全唐诗/poet.song.120000.json','["張侯好兄弟，韡韡棠棣芳。", "筑室聽風雨，書史堆滿牀。", "牀前竹千挺，竹外花兩行。", "舉頭見青山，秀色臨我傍。", "客來具雞黍，亦復陳壺觴。", "坐與塵土隔，淡然風味長。", "我久倦行役，萬里歸故鄉。", "相過飯三日，笑語成清狂。", "百年幾別離，兩鬢各已蒼。", "此會苦難復，此歡不可忘。"]'),
('52948d2f-5c92-47f5-8815-fb6fe1e943f4','欣欣篇','孫介','宋','宋诗','song-poetry','','[]','欣欣雪齋叟，年少本孤寒。',144,'全唐诗/poet.song.120000.json','["欣欣雪齋叟，年少本孤寒。", "愁懷厄羈寓，兀坐起長嘆。", "慷慨念前世，聖門真可觀。", "鄒人息邪說，吏部回狂瀾。", "鈍金須砥礪，曲木待繩彈。", "幸哉得三男，父子聊自歡。", "爛舌不令閉，濡毫無使乾。", "高天揭懸象，絕嶂飛流湍。", "取捨狥三益，行藏推四端。", "鶯友新擇木，鵷雛初放官。", "言辭凜冰雪，節操森琅玕。", "神祇儻終祐，騫翥亦何難。"]'),
('d6f757a9-3849-4f79-afb6-67160af4e0e0','雨凉夜坐口占','孫介','宋','宋诗','song-poetry','','[]','雨陣四五合，回風掃千軍。',48,'全唐诗/poet.song.120000.json','["雨陣四五合，回風掃千軍。", "舉頭映微月，滿空行白雲。", "煩歊一洗盡，危坐清夜分。", "讀書意未已，悠然有餘欣。"]'),
('f35b1ca4-8f84-4e10-9f5b-f0e46d00bc16','丁未孟秋夜月明如中秋因思范公守南陽賞月及坡公赤壁之游皆七月望也作短歌記之','孫介','宋','宋诗','song-poetry','','[]','先生赤壁舟中賦，老子百花洲上歌。',160,'全唐诗/poet.song.120000.json','["先生赤壁舟中賦，老子百花洲上歌。", "古人不負此明月，今我當如此月何。", "連宵風雨暑欲盡，碧玉萬里誰新磨。", "冰盤無聲出海底，蕩漾六合生金波。", "早秋便得許奇絕，探借八月清光多。", "天公賜我美無價，樽酒不設羞嫦娥。", "人生看月幾時足，百年寒暑如飛梭。", "兩公却與月長在，聲名萬古流江河。", "夢生羽翼不可逐，想象風景空吟哦。", "洞簫長笛亦何有，拂衣起舞聊婆娑。"]'),
('d10c61ff-d111-40db-b737-5ee9d302db99','用兒子應時宿龍泉寺遇雪詩韻','孫介','宋','宋诗','song-poetry','','[]','扁舟趨郡去，携手復同歸。',48,'全唐诗/poet.song.120000.json','["扁舟趨郡去，携手復同歸。", "款話僧宜訪，登山志欲飛。", "詩能歌白雪，心合念黄扉。", "莫作兒童語，豐兇有政機。"]'),
('21cce3f9-4743-4362-b677-0984185250f1','答僧道隆惠老融水墨一紙','孫介','宋','宋诗','song-poetry','','[]','破林霜後月，煙景夜微茫。',48,'全唐诗/poet.song.120000.json','["破林霜後月，煙景夜微茫。", "妙寄筆墨外，靜涵山水光。", "古融韻可想，老隆意所將。", "慚我無瓊琚，報以永不忘。"]'),
('fdeaf761-707a-4aea-8463-ae38232f9f8e','丁未仲夏賞月','孫介','宋','宋诗','song-poetry','','[]','詩成二十年，今夜月重圓。',48,'全唐诗/poet.song.120000.json','["詩成二十年，今夜月重圓。", "兩姓包三樂，同寮慶十全。", "笑談諧素願，賓主謝高天。", "莫逆無勞約，俱祈得永延。"]'),
('b36ef1f7-4829-4745-84b6-1e0fb3f4572f','夜坐偶成','孫介','宋','宋诗','song-poetry','','[]','墮甑誰能顧，虛舟進所如。',48,'全唐诗/poet.song.120000.json','["墮甑誰能顧，虛舟進所如。", "無涯身世事，有味聖賢書。", "髮短猶禁櫛，園荒可廢鋤。", "萊衣幸無恙，何必問其餘。"]'),
('f926be94-c4a5-46a7-b865-c37cc0a0e313','送錢叔儀使君之南安','孫介','宋','宋诗','song-poetry','','[]','使君心事玉無瑕，游戲功名髮未華。',64,'全唐诗/poet.song.120000.json','["使君心事玉無瑕，游戲功名髮未華。", "要省文書繙貝葉，故從江嶺訪梅花。", "春風早趁人千里，勝日相思天一涯。", "喚取名郎著蘭省，不須留及兩年瓜。"]'),
('42dc27d7-1ce5-4072-999c-cf00700a3d23','偕同人登虞山乾元宮','孫介','宋','宋诗','song-poetry','','[]','塵囂咫尺愧山林，勝日追凉得共臨。',64,'全唐诗/poet.song.120000.json','["塵囂咫尺愧山林，勝日追凉得共臨。", "千里江湖堪送目，一軒松竹更論心。", "清風便自生秋意，小酌何妨到夕陰。", "歸路蟬聲滿溪谷，爲君倚蓋一微吟。"]'),
('d8512edc-d142-46ce-b094-b79ba18e24cd','乾道乙酉鬻田訓子有作','孫介','宋','宋诗','song-poetry','','[]','顔回猶自給糜飦，蘇子初無二頃田。',64,'全唐诗/poet.song.120000.json','["顔回猶自給糜飦，蘇子初無二頃田。", "知慕聖師瞠若後，豈令恭嫂倨如前。", "筆耕得利寧分地，學祿中居總藉天。", "卜相既云隳祖業，請令同力奮雙拳。"]'),
('cf92b4c1-452f-4a69-af66-56168e07e66d','仲子生日','孫介','宋','宋诗','song-poetry','','[]','尋常得子要佳晨，何幸生朝在仲春。',64,'全唐诗/poet.song.120000.json','["尋常得子要佳晨，何幸生朝在仲春。", "樂事賞心隨處處，仁風和氣似親親。", "天恩有庇容團聚，家訓無須旋卜鄰。", "杯酒獻酬更祝頌，不須黄老拱星辰。"]'),
('4cbbae9a-bc1c-46a2-a13b-7792518dfb02','縣作鹿鳴會屈致冷副端席半出詩侑一獻次其韻','孫介','宋','宋诗','song-poetry','','[]','早嘆朝陽一鳳鳴，幾多風奏動延英。',64,'全唐诗/poet.song.120000.json','["早嘆朝陽一鳳鳴，幾多風奏動延英。", "只今故里誇閒適，得使諸生拜老成。", "妙句獨先歌白雪，歡顔親自酌烏程。", "鹿鳴故事雖榮觀，此段邦人分外榮。"]'),
('0a369d11-0717-45c7-a4cd-367c2f82f2cd','壬寅正月幼子黄巖尉任將滿予與家眾先歸幼子獨留官舍三月作詩八句寄之','孫介','宋','宋诗','song-poetry','','[]','三年隨汝作初官，父子同知涉世難。',64,'全唐诗/poet.song.120000.json','["三年隨汝作初官，父子同知涉世難。", "饕祿粗欣便老懶，還家仍慮厄饑寒。", "生來賦分皆前定，天下何時得舉安。", "慈孝睽離懷問膳，試憑雙鯉祝加餐。"]'),
('90c9e8ec-437e-45db-b312-2c0c26bbe3b6','乙巳冬十月隨幼男赴海陵丞中途遇交代有開正視事之請既抵官舍有作','孫介','宋','宋诗','song-poetry','','[]','整棹姚江到海陵，稽徊四十日行程。',64,'全唐诗/poet.song.120000.json','["整棹姚江到海陵，稽徊四十日行程。", "相逢既諾交承約，少待何妨信義明。", "戚戚已無終歲慮，琅琅先有誦書聲。", "夫妻白首皆天幸，三樂無慚好弟兄。"]'),
('44466cb0-5b59-4cb7-a3ba-ec2cef640d36','雨後','孫介','宋','宋诗','song-poetry','','[]','落日矯烏雲，疾風豗白浪。',24,'全唐诗/poet.song.120000.json','["落日矯烏雲，疾風豗白浪。", "雨聲西南來，勢劇萬馬壯。"]'),
('3683b47c-5c14-4af2-9856-733a8d3bfebe','江上','孫介','宋','宋诗','song-poetry','','[]','灘頭鳴榔去，偃仰醉霜月。',24,'全唐诗/poet.song.120000.json','["灘頭鳴榔去，偃仰醉霜月。", "意倦早歸來，風波渺愁絕。"]'),
('a1a75bc0-b683-49c3-b7e8-012ba934b960','淳熙戊戌在家聚徒期以秋冬隨子赴任作詩二絕示諸生  其一','孫介','宋','宋诗','song-poetry','','[]','爲學須當及少年，莫言愚智盡由天。',32,'全唐诗/poet.song.120000.json','["爲學須當及少年，莫言愚智盡由天。", "青春若不勤耕種，秋熟徒嗟有廢田。"]'),
('f2f962c7-2ea3-44de-9474-785e4eea49a6','淳熙戊戌在家聚徒期以秋冬隨子赴任作詩二絕示諸生  其二','孫介','宋','宋诗','song-poetry','','[]','此去相從有半年，分携恐在暮秋天。',32,'全唐诗/poet.song.120000.json','["此去相從有半年，分携恐在暮秋天。", "若能早夜思精進，他日生涯勝買田。"]'),
('6547bf3b-55e0-49e0-9788-1acc15c3ce2c','雨後','孫介','宋','宋诗','song-poetry','','[]','呼童捲簾收架書，簷溜忽斷雲蕭疎。',32,'全唐诗/poet.song.120000.json','["呼童捲簾收架書，簷溜忽斷雲蕭疎。", "山光水影凈如拭，一川秋意生芙蕖。"]'),
('d6795aa5-72b4-405c-846d-b339a87c90d4','句','孫介','宋','宋诗','song-poetry','','[]','哭願吾皇不共天。',8,'全唐诗/poet.song.120000.json','["哭願吾皇不共天。"]'),
('5d8ba003-bcb4-4637-8c55-969517041cdd','書王十朋述懷詩後','劉鎮','宋','宋诗','song-poetry','','[]','山北山南春雨足，漠漠柔桑秀如沃。',32,'全唐诗/poet.song.120000.json','["山北山南春雨足，漠漠柔桑秀如沃。", "儂家荆婦幾時歸，西疇獨自驅黄犢。"]'),
('3c646c41-80a6-40cd-9cb6-f57812e2e0d4','夜聽雙瀑聯句','劉鎮','宋','宋诗','song-poetry','','[]','蕭然山閣間，此興何悠哉。',72,'全唐诗/poet.song.120000.json','["蕭然山閣間，此興何悠哉。", "子晉不復見，月白空蕭臺。", "夜靜雙瀑喧，遥聞疑雨來。", "澗壑生清風，襟宇捐纖埃。", "飛鳴撼半空，暗想飄瓊瑰。", "前觀阻步屧，側耳成徘徊。"]'),
('a1045d2d-2529-4a7c-b6a0-866c34241a8b','對月聯句','劉鎮','宋','宋诗','song-poetry','','[]','與君坐階除，遥望海上月。',48,'全唐诗/poet.song.120000.json','["與君坐階除，遥望海上月。", "試舉太白杯，借問幾圓缺。", "人生易分散，動作隔年別。", "今宵對嬋娟，莫放酣歌絕。"]'),
('6052ceaf-8a4f-4313-8e5d-b4f33e31d806','句','劉鎮','宋','宋诗','song-poetry','','[]','須知失馬事，莫廢獲麟書。',12,'全唐诗/poet.song.120000.json','["須知失馬事，莫廢獲麟書。"]'),
('8d488c63-87eb-4391-8cc1-2d4ea3bc8a21','句','黄輔','宋','宋诗','song-poetry','','[]','許國一心如鐵勁，闔門百口等毛輕。',16,'全唐诗/poet.song.120000.json','["許國一心如鐵勁，闔門百口等毛輕。"]'),
('ab0dfd11-6435-40f8-b234-c2c97508ab28','廣惠寺','蔡清臣','宋','宋诗','song-poetry','','[]','雲中老樹冷蕭蕭，溪上僧歸倚畫橈。',32,'全唐诗/poet.song.120000.json','["雲中老樹冷蕭蕭，溪上僧歸倚畫橈。", "誰爲秋風乘興去，松窗先聽富陽潮。"]'),
('2a696096-259e-4215-9475-0657d9e44441','瀛巖','高襲明','宋','宋诗','song-poetry','','[]','溫台萬丘壑，走遍成重胝。',144,'全唐诗/poet.song.120000.json','["溫台萬丘壑，走遍成重胝。", "佳山落床頭，咫尺反不知。", "我聞野老說，山乃神所移。", "蓬萊本三峰，一峰今失之。", "上干雲霓秀，下壓鰲背欹。", "夜半見海日，紫暈開咸池。", "魑魅看老木，狂鼯向人啼。", "危亭無遺棟，絕壁無舊題。", "夫子勇我過，竦身敢獨躋。", "我病不能從，夢寐常追隨。", "秋風海上來，霜清鱸正肥。", "行尋越溪鞅，肅此塵外鞿。"]'),
('a450ef49-ae22-450b-b22f-dbe13230d3e0','句','戴之邵','宋','宋诗','song-poetry','','[]','愁絕江梅開嶺岸，不知失脚到南塘。',16,'全唐诗/poet.song.120000.json','["愁絕江梅開嶺岸，不知失脚到南塘。"]'),
('d0e91ab0-a3f6-46da-a188-fe1e8fddf7ad','思高人','張椿齡','宋','宋诗','song-poetry','','[]','仙人昔是瑶池客，珮玉鳴鑾生羽翮。',96,'全唐诗/poet.song.120000.json','["仙人昔是瑶池客，珮玉鳴鑾生羽翮。", "騎鯨千載說白雲，弱水三萬那可隔。", "蓬瀛深處乃其家，無限真仙衣絳霞。", "相呼酌醴勸蟠桃，安期大棗端如瓜。", "龍吟虎嘯眾樂奏，神芝瑞草生奇葩。", "願將此意踵太古，自然之道非特誇。"]'),
('c7a7bae6-5b54-4de5-b30f-959d9c96f93e','寄故人','張椿齡','宋','宋诗','song-poetry','','[]','浮生難百歲，能得幾日月。',48,'全唐诗/poet.song.120000.json','["浮生難百歲，能得幾日月。", "漸缺口中牙，將衰鬢邊髮。", "人情不久長，翻手成胡越。", "急急早歸來，從今好休歇。"]'),
('e680e2ba-b87c-4e9c-a626-d48ea9387cb4','思方外友','張椿齡','宋','宋诗','song-poetry','','[]','我聞仙人隱塵寰，带索不整輕雲寒。',144,'全唐诗/poet.song.120000.json','["我聞仙人隱塵寰，带索不整輕雲寒。", "練氣蕭蕭顔如丹，寫詩賦詠鏘琅玕。", "自言富貴無所待，一嘯萬古神情歡。", "嗟哉世故散淳樸，那識五體存真官。", "殘形滲漉虧靈藥，夙夕不愧精神單。", "仙芝混成生恍惚，道在此身端可觀。", "離明坎兌發變化，大似百瀆還海湍。", "光輝便可揖玄上，胡用木鉆鉆石盤。", "亙古虛無阡陌闊，從君跨鶴而乘鸞。"]'),
('838829a5-a0b3-4191-9f81-64f9f79cebd1','坐黄岡廣福禪房','郭昂','宋','宋诗','song-poetry','','[]','愛此禪栖靜，清凉境自偏。',48,'全唐诗/poet.song.120000.json','["愛此禪栖靜，清凉境自偏。", "詫人拳怪樹，留客笑幽蓮。", "草暖蛙喧夏，林昏鳥夢烟。", "風塵吾未免，兀坐愧安禪。"]'),
('0be9afc2-63b6-4525-94fd-e1520ef20a82','環珠洞','呂愿中','宋','宋诗','song-poetry','','[]','朝野樂昇平，園林窮勝討。',264,'全唐诗/poet.song.120000.json','["朝野樂昇平，園林窮勝討。", "快雨洗塵埃，秋山浄如埽。", "游魚聚江灣，饑烏集木杪。", "羣芳鬰崢嶸，一水翠繚繞。", "雲頭蒼狗變，龍蛇亂夭矯。", "巖洞真奇崛，造物逞天巧。", "近在堂奧間，超然類三島。", "暫舍簿書忙，何時脫紛擾。", "靜聽黄鸝鳴，一聲還復悄。", "纚維去咫尺，涉步即幽窈。", "新岸暗蒼苔，喬木蔽蘿蔦。", "山腹有遺祠，隱然見華表。", "筍輿訪崇臺，空曠遊遐眺。", "八桂困樵蘇，歎息心爲愀。", "任侯三蜀秀，冰壺湛春曉。", "有藥駐朱顔，可以長不老。", "雄篇頃刻成，舉座悉稱好。", "戛玉副鳴球，士夫善傳道。", "五嶺類觀東，一覽眾山小。", "呂巖何興廢，事固有前兆。", "新詩刻翠珉，異日可稽考。", "玩珠紀勝遊，聊復醉清醥。"]'),
('9e3158a9-522e-4805-b797-6c09fa4469a4','遊東觀','呂愿中','宋','宋诗','song-poetry','','[]','郊原同按轡，杖屨陟青冥。',48,'全唐诗/poet.song.120000.json','["郊原同按轡，杖屨陟青冥。", "山色混林樾，溪光照斗星。", "螺峰高插戟，兔徑曲穿庭。", "□□一聲遠，千巖特地青。"]'),
('a50b29d3-43e1-4f56-a78b-e2e7e0cc1800','訪顔氏讀書巖','呂愿中','宋','宋诗','song-poetry','','[]','洞口微雲恣卷舒，石巖相對一蘧廬。',64,'全唐诗/poet.song.120000.json','["洞口微雲恣卷舒，石巖相對一蘧廬。", "賦才晉宋多夷曠，好景古今難貯儲。", "茗碗已驚浮雪浪，齋厨俄聽響鯨魚。", "子雲識字終何用，且讀人間未見書。"]'),
('da1be400-9029-4db1-ad3f-1332ddf5e9b2','假守呂叔恭游中隱巖無名洞坐客鄱陽朱國輔云此洞未有名因公而題欲名曰呂公巖予未敢披襟而劉子思陳朝彥皆曰甚當戲書五十六字鑱於石壁間紹興甲戌季春七日','呂愿中','宋','宋诗','song-poetry','','[]','護田綠水轉山樊，滴翠羣峰列巨杉。',64,'全唐诗/poet.song.120000.json','["護田綠水轉山樊，滴翠羣峰列巨杉。", "洞外僧藍侵斗漢，澗邊人跡隔仙凡。", "深深雲谷春常在，寂寂松扉夜不緘。", "此處得名爰自我，要須題作呂公巖。"]'),
('470a23d5-a5c9-4f1f-bdd3-a62ef88d3df1','郡守呂叔恭以甲戌季春七日遊中隱岩山水膏肓之興未已後兩日再拉機宜劉子思監州朱國輔經屬陳朝彥同至新洞所見愈奇真所謂倒餐甘蔗聊書五十六字','呂愿中','宋','宋诗','song-poetry','','[]','爽塏虛明小洞天，巉巖垂乳類鋒銛。',64,'全唐诗/poet.song.120000.json','["爽塏虛明小洞天，巉巖垂乳類鋒銛。", "薰風習習來三面，夏雨蕭蕭欠一檐。", "指顧羣山勞應接，徘徊歸騎縱觀瞻。", "門前綠水泓澄浄，底處應須是谷簾。"]'),
('5ace7e03-ac51-4d5e-8989-40a6f69df2b0','華景洞','呂愿中','宋','宋诗','song-poetry','','[]','斯洞名華景，纍纍乳石懸。',120,'全唐诗/poet.song.120000.json','["斯洞名華景，纍纍乳石懸。", "虛崖疑月窟，絕頂瞰江湍。", "巖底金仙寺，峰頭玉井蓮。", "地形居眾外，氣象偉無前。", "徙杖觀初日，歸輿觸暝烟。", "蔽林排翠幄，封徑簇花鈿。", "爽致資清賞，鎸題記昔年。", "猿啼聲應谷，雲破月侵筵。", "策蹇追華駟，鳴髇指墜鳶。", "誰人能畫此，爲倩老龍眠。"]'),
('9a3bb4d6-9d4d-4038-9a67-933deb9aee7e','北牖洞','呂愿中','宋','宋诗','song-poetry','','[]','南窗聊寄傲，北牖有凉風。',24,'全唐诗/poet.song.120000.json','["南窗聊寄傲，北牖有凉風。", "巖洞幽深處，結茅容老翁。"]'),
('294ae292-1436-40ce-8026-7f5723705331','嘉蓮洞','呂愿中','宋','宋诗','song-poetry','','["\u534e\u5c71"]','羃羃烟雲鎖洞關，旁開六戶類連環。',32,'全唐诗/poet.song.120000.json','["羃羃烟雲鎖洞關，旁開六戶類連環。", "芙蓉未是仙家瑞，更約同登太華山。"]'),
('5681506f-aa0c-4afc-8a41-53dda5cfd29f','朝陽洞','呂愿中','宋','宋诗','song-poetry','','[]','半世觀山鬢已皤，欲求釣艇老漁蓑。',32,'全唐诗/poet.song.120000.json','["半世觀山鬢已皤，欲求釣艇老漁蓑。", "杖藜又過烟霞洞，聞說當年爛斧柯。"]'),
('1bfe8e9b-265a-464a-ac77-1270d6e6e391','白雀洞','呂愿中','宋','宋诗','song-poetry','','[]','洞中石燕可長生，白雀何因浪得名。',32,'全唐诗/poet.song.120000.json','["洞中石燕可長生，白雀何因浪得名。", "無限好山難買得，世間奚用孔方兄。"]'),
('8b614a9e-0092-4deb-afe5-0db3aeeffa8d','夕陽洞','呂愿中','宋','宋诗','song-poetry','','[]','怪底浮屠不宿桑，直搜巖竇意徜徉。',32,'全唐诗/poet.song.120000.json','["怪底浮屠不宿桑，直搜巖竇意徜徉。", "洞中日月未嘗老，何事仙家有夕陽。"]'),
('9fbbceff-3807-4c70-ad79-593a80548a5f','南華洞','呂愿中','宋','宋诗','song-poetry','','[]','亂崖深峭水淙幽，六夏來遊儼似秋。',32,'全唐诗/poet.song.120000.json','["亂崖深峭水淙幽，六夏來遊儼似秋。", "安得蘧蘧一覺夢，倚巖栩栩訪莊周。"]'),
('65cfaaff-c7dc-409a-9efd-8d7ef17fabae','假守睢陽呂愿中叔恭機宜祥符劉襄子思通守鄱陽朱良弼國輔經屬建安陳廷傑朝彥因祈晴乘興遊中隱巖留題以記勝游','呂愿中','宋','宋诗','song-poetry','','[]','坎止流行但信緣，嶠南風景異山川。',32,'全唐诗/poet.song.120000.json','["坎止流行但信緣，嶠南風景異山川。", "偶因乘興穿山腹，始悟壺中別有天。"]'),
('e73eb84a-5129-4f5d-b0e3-06eaa1426254','劉仙巖','呂愿中','宋','宋诗','song-poetry','','[]','平明小隊出郊墟，盡日登臨據隼旟。',32,'全唐诗/poet.song.120000.json','["平明小隊出郊墟，盡日登臨據隼旟。", "聞道仙人尸解去，尚應猶學世間書。"]'),
('86a561f3-cb25-4479-a18a-2dcc7b0440a4','題元巖','呂愿中','宋','宋诗','song-poetry','','[]','崒嵂倚空蹲怪石，輪囷夾道卧長松。',32,'全唐诗/poet.song.120000.json','["崒嵂倚空蹲怪石，輪囷夾道卧長松。", "白龍應已沖天去，巖竇巋然有故蹤。"]'),
('fd2789a5-6b8a-4a5b-9a04-1336ecb5ac6f','半湯泉','呂愿中','宋','宋诗','song-poetry','','[]','郡境水多沸，陳村泉類湯。',24,'全唐诗/poet.song.120000.json','["郡境水多沸，陳村泉類湯。", "人情尚冰炭，地脈亦炎凉。"]'),
('4af08ba3-ee50-421a-8ae0-4351f1e51f22','句','慶書記','宋','宋诗','song-poetry','','[]','人從曉月殘邊去，路入雲山瘦處行。',16,'全唐诗/poet.song.120000.json','["人從曉月殘邊去，路入雲山瘦處行。"]'),
('2bda3026-c448-4988-82a8-743f16f8164a','挽王學正  其一','葉大年','宋','宋诗','song-poetry','','[]','書劍當年游上都，賢關蟲篆校諸儒。',64,'全唐诗/poet.song.120000.json','["書劍當年游上都，賢關蟲篆校諸儒。", "文華燦燦九苞鳳，俊氣駸駸千里駒。", "妙質競誰揮堊漫，白頭空此死樵蘇。", "遺編殘稿應猶在，搔首令人益嘆吁。"]'),
('1c928ce6-749f-44f6-8f2f-e064ec15b0f5','挽王學正  其二','葉大年','宋','宋诗','song-poetry','','[]','遺文膾炙在吾鄉，賦罷誰能少薦揚。',64,'全唐诗/poet.song.120000.json','["遺文膾炙在吾鄉，賦罷誰能少薦揚。", "聲跡有妻先蝶夢，行藏無子付洴方。", "雲蘿煙蔓新泉宅，秋月春花舊野堂。", "交倡絲牋真翰墨，幾人知爲寶巾箱。"]'),
('4338d65b-7925-4ed6-a64a-ccaea468baba','喜雨偈  其一','釋了思','宋','宋诗','song-poetry','','[]','熇熇炎威遍野飄，流金爍石土山焦。',32,'全唐诗/poet.song.120000.json','["熇熇炎威遍野飄，流金爍石土山焦。", "精誠不作軒雷轉，孰與人間濟槁苗。"]'),
('c4079120-68cd-4b42-81a4-4f056451ef4c','喜雨偈  其二','釋了思','宋','宋诗','song-poetry','','[]','救旱無方種種求，老龍誰識隱巖湫。',32,'全唐诗/poet.song.120000.json','["救旱無方種種求，老龍誰識隱巖湫。", "茅山居士興慈願，一叱風雲四百州。"]'),
('d38a99ad-6210-437d-9192-2fffd703518b','喜雨偈  其三','釋了思','宋','宋诗','song-poetry','','[]','衲子相逢競喜忻，應期甘雨一番新。',32,'全唐诗/poet.song.120000.json','["衲子相逢競喜忻，應期甘雨一番新。", "了知潤物無窮意，祇在維摩此念真。"]'),
('a5295010-76cb-4a91-b100-beae2a7499cd','喜雨詩  其一','張昭遠','宋','宋诗','song-poetry','','[]','試將丹懇□青霄，還話田疇萬里焦。',32,'全唐诗/poet.song.120000.json','["試將丹懇□青霄，還話田疇萬里焦。", "不是湫龍解興雨，元來滴滴自心苗。"]'),
('a4fa6b8f-5b34-4cb3-8468-98cd3f6d373b','喜雨詩  其二','張昭遠','宋','宋诗','song-poetry','','[]','禱旱何妨抵死求，分明在處有神湫。',32,'全唐诗/poet.song.120000.json','["禱旱何妨抵死求，分明在處有神湫。", "只消一念精誠格，立使風雷布九州。"]'),
('398e49ec-9b01-4575-b438-663ad1a6adce','喜雨詩  其三','張昭遠','宋','宋诗','song-poetry','','[]','幽谷從來分外清，那堪雨過月華新。',32,'全唐诗/poet.song.120000.json','["幽谷從來分外清，那堪雨過月華新。", "行將高謝浮名事，卜筑巖旁效子真。"]'),
('eea26f27-a819-4f26-a432-d5b52c98b5ad','和題觀音石壁','朱賞','宋','宋诗','song-poetry','','[]','今古相逢世所稀，神仙與我說天機。',32,'全唐诗/poet.song.120000.json','["今古相逢世所稀，神仙與我說天機。", "吾家後裔知消息，不落凡間笑白衣。"]'),
('21484687-319b-4dfd-8bf7-12d356c39ad9','白菖蒲聯句','釋智嵩','宋','宋诗','song-poetry','','[]','惟不識泥土，堆根抱玉泉。',24,'全唐诗/poet.song.120000.json','["惟不識泥土，堆根抱玉泉。", "雖離巖谷伴，也則翠千年。"]'),
('69d0319b-059f-4682-9f84-1888914023ab','賦虹霓','釋智嵩','宋','宋诗','song-poetry','','[]','水染青紅带一條，和雲和雨繫天腰。',32,'全唐诗/poet.song.120000.json','["水染青紅带一條，和雲和雨繫天腰。", "玉皇爲厭皇宮倦，故築空中萬丈橋。"]'),
('e7a9fc30-37f1-43f4-a48a-dc1cd990ae01','題朱賞門','紹興卜者','宋','宋诗','song-poetry','','[]','澗水涓涓繞洞崖，洞邊時有小桃開。',32,'全唐诗/poet.song.120000.json','["澗水涓涓繞洞崖，洞邊時有小桃開。", "四邊環合疑無路，爲問東風何處來。"]'),
('06b89609-31fa-4624-95b6-c6030e5dc9ed','題觀音石壁','紹興卜者','宋','宋诗','song-poetry','','[]','金紫玉青世所稀，牡丹花下探天機。',32,'全唐诗/poet.song.120000.json','["金紫玉青世所稀，牡丹花下探天機。", "仙遊秀水真消息，身傍御爐香滿衣。"]'),
('42de06e0-8d74-4449-a28d-c7f17d367532','贈陽大明','紹興道人','宋','宋诗','song-poetry','','[]','陽君真確士，孝行動穹壤。',72,'全唐诗/poet.song.120000.json','["陽君真確士，孝行動穹壤。", "皇上憐其艱，七夕遣回往。", "逡巡藥頑石，遺子爲饋享。", "子既不我受，吾亦不汝强。", "風埃難少留，願子志勿爽。", "會當首鼠記，青雲看反掌。"]'),
('49fd63b6-6dfa-40d2-bae1-1757e00ab49b','題壁','錢氏','宋','宋诗','song-poetry','','[]','落日西風照楚關，斷魂殘魄弔衰顔。',384,'全唐诗/poet.song.120000.json','["落日西風照楚關，斷魂殘魄弔衰顔。", "自從鴻鵠分飛後，無復鴛鴦並枕間。", "腕玉瘦寬金縷袖，鬢蟬慵掠翠雲鬟。", "秋天冬暮風雪寒，對鏡懶把金蟬簇。", "夢魂夜夜到君邊，覺來寂寞鴛衾獨。", "此時行坐閑紗窗，忍淚含情眉黛蹙。", "古人惜別日三秋，不知君去幾多宿。", "山高水闊三千里，名利使人復爾耳。", "昔年曾撥伯牙絃，未遇知音莫怨天。", "去年又奏相如賦，漢殿依前還不遇。", "時人不知雙字訛，平川倏忽風波起。", "當時南宮報罷音，教妾沉吟杵中心。", "爲君滴下紅粉淚，紅羅帳裏濕鴛衾。", "憤憤調琴蟬鵲噪，默默吟詩怨桂林。", "千調萬撥不成曲，爭奈胸中氣相掬。", "千思萬想不成詩，心如死灰誰得知。", "料得君心當此際，事國繁華閑田地。", "朝朝暮暮望君歸，日在東隅月在西。", "碧落翩翩飛雁過，青山切切子規啼。", "望盡一月復一月，不見音容寸腸結。", "又聞君自河東來，夜夜不教紅燭滅。", "雞鳴犬唳側耳聽，寂寂不聞車馬音。", "自此知君無定止，一片情懷冷如水。", "既無黄耳寄家書，也合隨時寄雁魚。"]'),
('e4ac79f1-8c2d-448d-ac68-7fc4e6ecfb27','白雲歌贈白雲道人','連久道','宋','宋诗','song-poetry','','[]','君不見白雲萬頃還□去，來去誰能留得住。',67,'全唐诗/poet.song.120000.json','["君不見白雲萬頃還□去，來去誰能留得住。", "去處放他秋月明，來時寒破太虛路。", "等閑爲雨復爲晴，玄空一點元青青。", "道人何異白雲意，此心了然游杳冥。"]'),
('40682d30-757a-479b-945e-153d1eed90e8','洞霄琳宮  其一','連久道','宋','宋诗','song-poetry','','[]','玲瓏萬狀石欺玉，開闔千層秀結峰。',64,'全唐诗/poet.song.120000.json','["玲瓏萬狀石欺玉，開闔千層秀結峰。", "尚有炎蒸疑夏日，未令新爽洗秋容。", "龍翔鳳舞來天目，水秀山明鞏帝封。", "新見錢塘王氣好，中原我欲指迷蹤。"]'),
('0d5e7e0f-93da-4998-9fa2-f22f2e413839','洞霄琳宮  其二','連久道','宋','宋诗','song-poetry','','[]','棲真已得尋西洞，神應誰能辨雨鍾。',64,'全唐诗/poet.song.120000.json','["棲真已得尋西洞，神應誰能辨雨鍾。", "水奏五音鳴玉鳳，山回九鎖踞蒼龍。", "古杉疑復天台去，怪石時從福地供。", "它日重游應更好，擬登天柱最高峰。"]'),
('721bba62-89d4-4b08-9332-799a9892bbcf','翠微亭  其一','連久道','宋','宋诗','song-poetry','','[]','湧壁千尋古面顔，仰憑天柱俯仙關。',32,'全唐诗/poet.song.120000.json','["湧壁千尋古面顔，仰憑天柱俯仙關。", "松間琱鏤軒墀月，未許詩人見一□。"]'),
('58f3e7a5-a965-4906-891b-80b0482bae22','翠微亭  其二','連久道','宋','宋诗','song-poetry','','[]','行迹年來酬□希，獨□巖壑有深期。',32,'全唐诗/poet.song.120000.json','["行迹年來酬□希，獨□巖壑有深期。", "□□道士能相屬，請和空山木落詩。"]'),
('43ad5ead-7254-477f-b143-658c161cafd9','寓天台水南四首  其一','林憲','宋','宋诗','song-poetry','','[]','小雨淒暮春，入夜寒更作。',48,'全唐诗/poet.song.120000.json','["小雨淒暮春，入夜寒更作。", "泠泠竹間風，振我衣袂薄。", "野田鳴流泉，密樹紛翠幄。", "躡屐徐我行，長懷付寥廓。"]'),
('5df62d1e-62b9-454e-b3ed-4b9d1a653054','寓天台水南四首  其二','林憲','宋','宋诗','song-poetry','','[]','懷古不知寒，洗心忘百憂。',48,'全唐诗/poet.song.120000.json','["懷古不知寒，洗心忘百憂。", "怡然方寸地，得與賢聖遊。", "南澗兮泉甘，北山兮雲幽。", "彼紛兮何之，茲盤兮吾留。"]'),
('632c583f-e6fd-4dd8-a132-a1ed9590be22','寓天台水南四首  其三','林憲','宋','宋诗','song-poetry','','[]','春雨暗前山，春雲行遠林。',48,'全唐诗/poet.song.120000.json','["春雨暗前山，春雲行遠林。", "月落雞犬靜，誰聞梁甫吟。", "巍巍兮高山，泠泠兮好音。", "誰聞梁甫吟，惟恐山不深。"]'),
('d20c221f-d2c5-49b8-9284-b2d6fe6c0238','寓天台水南四首  其四','林憲','宋','宋诗','song-poetry','','[]','夔皋不著書，周召不决科。',48,'全唐诗/poet.song.120000.json','["夔皋不著書，周召不决科。", "端坐廟堂上，四海臻泰和。", "此道固如是，後來文藝多。", "嗒然空山中，獨抱明良歌。"]'),
('5aa256ff-50ba-4327-b189-680870e6707f','天台萬年山羅漢樹','林憲','宋','宋诗','song-poetry','','[]','羅漢嶺頭羅漢樹，開闢餘工所鍾聚。',304,'全唐诗/poet.song.120000.json','["羅漢嶺頭羅漢樹，開闢餘工所鍾聚。", "百圍直上摩紫霄，鐵剝犀空自無蠹。", "積年魔怪不敢棲，暫過鸞凰却回顧。", "初晴偃榦礙雲霓，欲雨蟠根起煙霧。", "聲回浪吼東海鯨，影落雲侵石橋路。", "氣陵太古化兒驚，勢壓羣材梓人懼。", "陽開陰閉資指南，地弼天承賴撐拄。", "凡斤俗斧遠遯逃，黛色蒼皮未須疏。", "巖靈樹異如相語，傑葉豪柯翠雲覆。", "冰霜坐閱無古今，合抱雲仍仰雄據。", "豈同澗梓與壑柟，未歷千年隨草腐。", "我來駭識天下奇，斗酒澆之共軒翥。", "行人莫擬明堂柱，險徑無來萬牛處。", "盛時要用真棟梁，宜使巇危可平騖。", "指呼刊鑿動六丁，匠氏仍煩修月戶。", "輔隆廣厦蔽蒼生，何止增華萬年趣。", "懸崖黯慘陰風吐，振谷徘徊忽號怒。", "纖梢嘯舞山雨來，石走雷轟鬼神怖。", "未容造次搜奇句，五百尊師所呵護。"]'),
('52c043f1-86a7-4c3b-94a9-94e96339e112','丹丘書懷','林憲','宋','宋诗','song-poetry','','[]','靈鳳山前花片飛，讀書窗下碧雲棲。',64,'全唐诗/poet.song.120000.json','["靈鳳山前花片飛，讀書窗下碧雲棲。", "斷崖流水春不盡，苦竹紋禽日夜啼。", "禽聲不歇日欲暮，一點青燈照環堵。", "鏌铘挂壁龍影寒，默坐焚香聽春雨。"]'),
('5d28efec-1099-4793-a2ff-13381841fe32','梅花二首  其一','林憲','宋','宋诗','song-poetry','','[]','凌晨汲山泉，盥洗甫云暇。',48,'全唐诗/poet.song.120000.json','["凌晨汲山泉，盥洗甫云暇。", "徐行修竹間，小立疏梅罅。", "尖風耿薄日，色影寒相射。", "幽香定有無，紋禽踏花卸。"]'),
('cfe6887c-a36c-46e4-a55a-3a3719623bfc','梅花二首  其二','林憲','宋','宋诗','song-poetry','','[]','池邊石陂陀，水光上梅梢。',48,'全唐诗/poet.song.120000.json','["池邊石陂陀，水光上梅梢。", "石上古隸字，蘚剝風蕭騷。", "樹老花秀發，冰生香動摇。", "只恐字磨滅，不愁花寂寥。"]'),
('4aa804a5-4326-4749-9908-97b3b5b3fafc','台州兜率寺淳熙三年孟春作  其一','林憲','宋','宋诗','song-poetry','','[]','一榻江色近，夜氣欲空濛。',48,'全唐诗/poet.song.120000.json','["一榻江色近，夜氣欲空濛。", "柔櫓晚潮上，寒燈深樹中。", "四山杳煙霧，月華忽陵空。", "我亦眾念息，簾影空玲瓏。"]'),
('bb7dd9ee-6e59-4117-b338-5c37dbd019c1','台州兜率寺淳熙三年孟春作  其二','林憲','宋','宋诗','song-poetry','','[]','春江潑天明，蕭寺踞山塢。',48,'全唐诗/poet.song.120000.json','["春江潑天明，蕭寺踞山塢。", "荒階下鳥雀，古木颯風雨。", "徐行石苔花，徙倚望江渚。", "日暮山更寒，簷頭鈴自語。"]'),
('de95680f-aa68-44ba-8cd3-6aeb67076aa6','台州兜率寺淳熙三年孟春作  其三','林憲','宋','宋诗','song-poetry','','[]','寺門闞南江，江勢浩相嚮。',50,'全唐诗/poet.song.120000.json','["寺門闞南江，江勢浩相嚮。", "風雲互吞吐，山色豁林⿰木養。", "潮頭捲飛煙，白雨挾春漲。", "中夜鵝鶩喧，誰家海船上。"]'),
('490f6b45-44d3-4dae-b66e-0000a7a298d7','台州兜率寺淳熙三年孟春作  其四','林憲','宋','宋诗','song-poetry','','[]','月色半古寺，蟲聲雜疏鐘。',48,'全唐诗/poet.song.120000.json','["月色半古寺，蟲聲雜疏鐘。", "江城繚山色，星斗摇空濛。", "徐行不自覺，徙倚樹影中。", "忽然變煙雨，江上東南風。"]'),
('13e5723e-1f46-4ee0-82bd-3f9732de0b2a','台州兜率寺淳熙三年孟春作  其五','林憲','宋','宋诗','song-poetry','','[]','老樹半藤蘿，野色入窗戶。',48,'全唐诗/poet.song.120000.json','["老樹半藤蘿，野色入窗戶。", "空明浮屋梁，蕭爽發幽趣。", "晚凉進微風，平江瀉煙露。", "露久山月來，蟬聲發高樹。"]'),
('f8f368ee-c1a9-4e0c-b89f-dfacc276ad69','使君沈虞卿宗丞命賦郡圃羅漢樹其樹葉如楊梅經冬不彫生子若羅漢然使君云奇特古怪前所未見也','林憲','宋','宋诗','song-poetry','','[]','參雲亭前羅漢樹，非檜非杉獨雄據。',384,'全唐诗/poet.song.120000.json','["參雲亭前羅漢樹，非檜非杉獨雄據。", "蒼皮剝落珊瑚寒，錯節輪囷海花蠹。", "修圓佛指葉沃光，刺歷蝦筒槎倒豎。", "銅柯不受鴟蝮穿，翠葆還容藤蔓附。", "藏牙斂翼方屈蟠，奮鬣張鱗忽馳騖。", "突如破浪六鼇迴，蜿若驚雷蟄蛟煦。", "摩空颼颼永夏凉，薄霧慘慘晚秋雨。", "白猨叫月時出沒，紫鳳棲煙乍飛舉。", "開花瑣碎兒女笑，結子模糊羅漢具。", "威儀莊肅初入定，向背跏趺欣共住。", "蒙頭大似安禪時，瞑目還同摩頂處。", "得非天台五百仙，此地鉢提曾得度。", "偶然一念落樹石，不覺形骸成布露。", "何時收拾過石橋，未免根株伴龍顧。", "更疑地主屈將軍，開闢巖荒肇城宇。", "剪除魔怪迎道猷，飛錫半千此焉駐。", "神通墮在造化中，千載英靈飛不去。", "犀堅久矣耐風霆，樗散非徒免斤斧。", "盆山秀聳不足論，猊座婆娑通一路。", "崢嶸下笑桃李繁，奇怪應須鬼神護。", "使君自是名世才，善政報成多暇豫。", "悠然領客上參雲，篆隸傳觀酒深注。", "平生好古邱壑會，指樹軒渠命之賦。", "我無文章光燄長，搜攪經時乏佳趣。"]'),
('395478f9-e84f-4c39-ad9b-a3c78e8049a7','台州郡治十二詩太守尤延之命賦 雙巖堂','林憲','宋','宋诗','song-poetry','','[]','兩崖玉巉然，秀色真可餐。',48,'全唐诗/poet.song.120000.json','["兩崖玉巉然，秀色真可餐。", "嵐煙落窗几，慘澹雲水閒。", "幽人美清夜，和月凭欄干。", "天空山影直，八表生晴寒。"]'),
('60b8e3af-d35e-4f0e-8d1f-ea7c767780b4','台州郡治十二詩太守尤延之命賦 參雲亭','林憲','宋','宋诗','song-poetry','','[]','孤雲不可攀，浩氣相與遥。',48,'全唐诗/poet.song.120000.json','["孤雲不可攀，浩氣相與遥。", "著亭翠微頂，飛簷侵泬寥。", "紫麟迂遠駕，黄鵠回扶摇。", "雲收天籟息，亭影摩重霄。"]'),
('63356af5-e245-4515-8c1d-35fe9e5ce651','台州郡治十二詩太守尤延之命賦 凝思堂','林憲','宋','宋诗','song-poetry','','[]','遠思八表外，澹然何所凝。',48,'全唐诗/poet.song.120000.json','["遠思八表外，澹然何所凝。", "蒼巖窅空闃，修竹風泠泠。", "秋老竹亦瘦，月上巖更清。", "手持玉如意，天豁河漢明。"]'),
('e378ebe2-513b-4cac-81a9-9a5a265093b4','台州郡治十二詩太守尤延之命賦 玉霄亭','林憲','宋','宋诗','song-poetry','','[]','蜿蜒龍顧山，霄漢在人境。',48,'全唐诗/poet.song.120000.json','["蜿蜒龍顧山，霄漢在人境。", "古亭壓虛無，雲氣倒天景。", "天澄碧芙蕖，一葉一亭影。", "凝然千葉上，有客動深省。"]'),
('96982aaf-4586-424c-bdfa-a74be99cd16c','台州郡治十二詩太守尤延之命賦 霞起堂','林憲','宋','宋诗','song-poetry','','[]','赤城在何處，明霞坐中起。',48,'全唐诗/poet.song.120000.json','["赤城在何處，明霞坐中起。", "大千無色界，向背五雲裏。", "羽人跨丹鳳，千載一來止。", "嚥漱餐泰和，瓊田結珠蕊。"]'),
('d87569c5-5b45-4c0a-9fda-a09bde4beb68','台州郡治十二詩太守尤延之命賦 樂山堂','林憲','宋','宋诗','song-poetry','','[]','茲堂雖不華，三面受山色。',48,'全唐诗/poet.song.120000.json','["茲堂雖不華，三面受山色。", "直東接溟海，雲霧時振翮。", "幾年蕪穢深，一日洞天折。", "悠然舒嘯中，自得仁所宅。"]'),
('39ad170f-e9c4-496c-bec6-f456e4c33218','台州郡治十二詩太守尤延之命賦 靜鎮堂','林憲','宋','宋诗','song-poetry','','[]','天下本無事，智者欣有作。',48,'全唐诗/poet.song.120000.json','["天下本無事，智者欣有作。", "誰能此堂上，靜坐對寥廓。", "魚游鳥翔回，千里受真樂。", "從渠錦繡腸，天壤自卜度。"]'),
('51402724-7284-4df2-83a5-f68c68c8bacd','台州郡治十二詩太守尤延之命賦 匿峰亭','林憲','宋','宋诗','song-poetry','','[]','千嶺隨指顧，一峰不可匿。',48,'全唐诗/poet.song.120000.json','["千嶺隨指顧，一峰不可匿。", "如何超逸士，勘破造化跡。", "隱然胸中奇，盤礴巖煙碧。", "夜半秋月寒，人境俱峻極。"]'),
('2af1dc74-1995-4a5e-8585-a24e81ad6d68','台州郡治十二詩太守尤延之命賦 清平閣','林憲','宋','宋诗','song-poetry','','[]','飲濁斯貴清，路險斯貴平。',48,'全唐诗/poet.song.120000.json','["飲濁斯貴清，路險斯貴平。", "明明古君子，日用無非誠。", "寒潭寒徹底，坦道安無傾。", "日用儻如此，政化天與成。"]'),
('846184c8-cde3-431b-9f00-f2bfe8bb0e1e','台州郡治十二詩太守尤延之命賦 君子堂','林憲','宋','宋诗','song-poetry','','[]','古人不可逢，豈徒慕其名。',48,'全唐诗/poet.song.120000.json','["古人不可逢，豈徒慕其名。", "茲堂號君子，想像勞我情。", "高山仰後世，作者追前聲。", "何處見文簡，堂虛風更清。"]'),
('410f9405-762a-4c75-8b7a-cedc6e411dc1','台州郡治十二詩太守尤延之命賦 駐目亭','林憲','宋','宋诗','song-poetry','','[]','郡齋多勝覽，隨處山拱揖。',48,'全唐诗/poet.song.120000.json','["郡齋多勝覽，隨處山拱揖。", "一亭更留人，小立雲百級。", "峰巒方獻狀，霾霧且無集。", "是中頗空洞，不礙山色入。"]'),
('da4002bd-d537-4b54-9622-505cdb26cd78','台州郡治十二詩太守尤延之命賦 節愛堂','林憲','宋','宋诗','song-poetry','','[]','聖人定規模，用節民自愛。',48,'全唐诗/poet.song.120000.json','["聖人定規模，用節民自愛。", "後來巧施爲，民害深可慨。", "先生壽正脈，吾道燦然在。", "揭以榜屋梁，流風萬千載。"]'),
('b976dfd8-5f37-4148-85be-62e0ac3cdb3a','題國清寺清音亭','林憲','宋','宋诗','song-poetry','','[]','水從東塔來，却打西澗過。',48,'全唐诗/poet.song.120000.json','["水從東塔來，却打西澗過。", "八萬四千偈，爲我細說破。", "困來石上眠，夢繞泉石閒。", "山鬼按玉徽，山靈鏗佩環。"]'),
('873ff724-8a02-4639-9998-375bcb000f54','題國清寺清音亭  其一','林憲','宋','宋诗','song-poetry','','[]','水從東塔來，却打西澗過。',24,'全唐诗/poet.song.120000.json','["水從東塔來，却打西澗過。", "八萬四千偈，爲我細說破。"]'),
('abc0b2b4-091d-499b-b8e2-c7852036b9a6','題國清寺清音亭  其二','林憲','宋','宋诗','song-poetry','','[]','困來石上眠，夢繞泉石閒。',24,'全唐诗/poet.song.120000.json','["困來石上眠，夢繞泉石閒。", "山鬼按玉徽，山靈鏗佩環。"]'),
('c620921c-8403-4d86-a635-294079460168','浮江探梅','林憲','宋','宋诗','song-poetry','','[]','清游可以愈宿疾，梅花自能來好人。',32,'全唐诗/poet.song.120000.json','["清游可以愈宿疾，梅花自能來好人。", "嗅花徐步沙磧裏，天風液液回三春。"]'),
('b0dfff8d-9ba0-4bc5-b965-decaaead0205','梁源異松圖行爲台州趙別駕作','林憲','宋','宋诗','song-poetry','','[]','座中忽覺林樾幽，怪松墮前驚兩眸。',416,'全唐诗/poet.song.120000.json','["座中忽覺林樾幽，怪松墮前驚兩眸。", "孤根蟠錯湧鱗鬣，百榦奮躍紛戈矛。", "千歲之柯海波捲，十畝之陰嵐靄浮。", "上雲變幻舞鸞鵠，下風哮吼搏蛟虯。", "影入月窟兔縮距，聲撼水府鯨掉頭。", "初夏花黄醍醐結，四時芽茁紺綠抽。", "噓晴噀雨莽奇怪，摇山盪海寒颼飀。", "天開地闢何日種，陰慘陽舒謾神搜。", "鄉閭諷誦喜輒應，僧伽護愛訶不休。", "得非孔明廟前銅柯柏，元氣淋漓鍾此夫焉廋。", "得非道者庵邊隔世植萬本，倫魁飛來排斡予交樛。", "安得此松據此地，輪囷傲蹇無侶儔。", "我嘗兩賦羅漢樹，詩人許我不但楊與尤。", "一在天台匿峰千嶺頂，芘覆方廣之寺瀑布流。", "一與郡治參雲亭對峙，白猿啼蹶忽驚紫鳳留。", "因知三台氣忠厚，何但當代人材優。", "至於樹木亦豪偉，歲寒動足光林丘。", "問諸故老考初始，或云五季方栽培。", "黄宋惡跡寺傍廟，野僧無知但包羞。", "又云道人梁君隱唐末，建立鼎竈結茅深巖陬。", "與二道伴王與白，赤鉛紫汞火候卦氣周。", "千日丹成各昇舉，捨庵爲寺答應求。", "後人誕謾附名號，妄蹤狂躅何悠悠。", "當時丹氣蒸山一鄉植物茂，丹液入根獨此偃蓋稠。"]'),
('e24b60ad-6893-4e45-820c-b8c1dda245f0','梅花','林憲','宋','宋诗','song-poetry','','[]','野梅空山中，正爲照人開。',48,'全唐诗/poet.song.120000.json','["野梅空山中，正爲照人開。", "如何綠窗底，疏映带蒼苔。", "頗似古君子，無人自不諧。", "竹徑酒初醒，一信清香來。"]'),
('39fe5dde-4cfe-45d6-9ea3-f207ca052332','芭蕉','林憲','宋','宋诗','song-poetry','','[]','芭蕉我所愛，明潔而中虛。',24,'全唐诗/poet.song.120000.json','["芭蕉我所愛，明潔而中虛。", "禪房富靈根，頗似人清臞。"]'),
('0791c747-52f4-41bb-b22d-8505f37a041c','讀陶詩作','林憲','宋','宋诗','song-poetry','','[]','吾觀淵明詩，了不在言賦。',156,'全唐诗/poet.song.120000.json','["吾觀淵明詩，了不在言賦。", "有如太和氣，周行不停駐。", "時與春爲風，融夷物華布。", "而未見用力，萬物向榮處。", "時與秋爲月，浩然無點注。", "江山滋清絕，宇宙靡纖汙。", "乃知淵明詩，本不在詩故。", "邂逅吐所有，氣象隨所寓。", "乞食不爲拙，華軒不爲慕。", "歸來不爲高，折腰不爲沮。", "羲皇平步超，無懷貞雅素。", "簡澹豈能盡，學者漫馳步。", "獨有無絃琴，明明一斑露。"]'),
('6f5872c7-8fd8-428c-8419-a3fbc6bd0c5f','天台道中  其一','林憲','宋','宋诗','song-poetry','','[]','月色在野水，雲痕澹前林。',48,'全唐诗/poet.song.120000.json','["月色在野水，雲痕澹前林。", "籃輿轉松竹，襟袖翠靄深。", "燈火見仍隱，機杼有遺音。", "境靜眾念息，泠然發微吟。"]'),
('118a8dc2-a97d-45b9-bf40-99a14da88c55','天台道中  其二','林憲','宋','宋诗','song-poetry','','[]','驕雲壓長郊，飛電見林嵨。',48,'全唐诗/poet.song.120000.json','["驕雲壓長郊，飛電見林嵨。", "震霆挾回風，捲海過白雨。", "東皇發生意，萬物情可睹。", "門外小草色，嫩綠亦軒舞。"]'),
('a1a00d56-67b6-4a7d-bd1e-a09648f9f5f0','姑蘇道中  其一','林憲','宋','宋诗','song-poetry','','[]','理棹出盤門，蓬窗掛秋曉。',48,'全唐诗/poet.song.120000.json','["理棹出盤門，蓬窗掛秋曉。", "蘆花一溪雨，淅瀝秋欲老。", "念世多閒愁，居山未爲好。", "寒坐櫓不鳴，蛩聲亂衰草。"]'),
('7240e050-dd03-4928-9051-af81d1ae59cd','姑蘇道中  其二','林憲','宋','宋诗','song-poetry','','[]','愁來雨聲悲，愁去雨聲好。',48,'全唐诗/poet.song.120000.json','["愁來雨聲悲，愁去雨聲好。", "忽然扣舷歌，雲霧生縹緲。", "日夕風雨寒，園林闃如掃。", "靜坐觀物化，榮謝亦草草。"]'),
('f80a0aa5-ab5f-4adf-9fb8-7d8687b07b24','雪巢即事','林憲','宋','宋诗','song-poetry','','[]','幽居閟古寺，隙地滋春綠。',48,'全唐诗/poet.song.120000.json','["幽居閟古寺，隙地滋春綠。", "汲水延晚花，推窗數新竹。", "嘉蔬喜晨餐，小雨昨夜足。", "儻使多暇時，終甘食無肉。"]'),
('60ee2d17-1b05-42a9-8068-1e2b06527307','雪巢三首  其一','林憲','宋','宋诗','song-poetry','','[]','居閑我所願，謀拙人所慮。',48,'全唐诗/poet.song.120000.json','["居閑我所願，謀拙人所慮。", "平淡固可嘉，饑來欲誰訴。", "八十日彭澤，四十年鄭圃。", "前賢去就意，三復成喜懼。"]'),
('c3fd221e-0c3f-4ae8-9762-e919677abfc0','雪巢三首  其二','林憲','宋','宋诗','song-poetry','','[]','採蘭以紉佩，不久香消歇。',48,'全唐诗/poet.song.120000.json','["採蘭以紉佩，不久香消歇。", "何如深林中，歲寒自時節。", "清芳御微風，幽態含皎月。", "世或無騷人，寧甘伴冰雪。"]'),
('0602fe82-ce6a-456e-b490-d4a045d535e6','雪巢三首  其三','林憲','宋','宋诗','song-poetry','','[]','凡草占眼界，鑿池松竹間。',48,'全唐诗/poet.song.120000.json','["凡草占眼界，鑿池松竹間。", "寒添一方月，香潤九畹蘭。", "蓼蘋稍自出，鷗鷺去亦還。", "水雲萬里趣，不待涉江山。"]'),
('6a813a4d-c32d-4942-bdbc-e704c148e6a0','遊芮灣東山庵','林憲','宋','宋诗','song-poetry','','[]','晴暾上疏林，石徑鋪松影。',48,'全唐诗/poet.song.120000.json','["晴暾上疏林，石徑鋪松影。", "挽衣涉寒澗，捫蘿過重嶺。", "閑花裊幽妍，冶葉發青炯。", "欲訪隱者居，雞聲出煙暝。"]'),
('209f7342-24a4-4392-a4e4-1c8ac66a8089','李才翁懶窩  其一','林憲','宋','宋诗','song-poetry','','[]','鴞鳴夜沉沉，蛩語露泥泥。',48,'全唐诗/poet.song.120000.json','["鴞鳴夜沉沉，蛩語露泥泥。", "飛雲带月來，投我襟袖裏。", "心自徹太虛，痱纇忽一洗。", "世念儻盡消，萬法亦聊爾。"]'),
('ccaf1ded-fb25-4d31-a671-fbf58230d1bf','李才翁懶窩  其二','林憲','宋','宋诗','song-poetry','','[]','幽人肯一杯，受用今夜月。',48,'全唐诗/poet.song.120000.json','["幽人肯一杯，受用今夜月。", "携手步虛庭，履遍沙界雪。", "疏林寂無聲，細蟲吟自切。", "浩蕩天宇開，虛襟共明潔。"]'),
('16ca2d7e-f585-4f6e-86e9-e8e132aeeaa8','李才翁懶窩  其三','林憲','宋','宋诗','song-poetry','','[]','終日雲氣厚，寖寖雨將傾。',48,'全唐诗/poet.song.120000.json','["終日雲氣厚，寖寖雨將傾。", "如何纔入夜，月輪皎如冰。", "雲去露飛灑，星稀天熨平。", "正恐中秋節，未必如許清。"]'),
('ea3cf54a-5093-4f99-a1c1-2e751c408880','李才翁懶窩  其四','林憲','宋','宋诗','song-poetry','','[]','山林日月長，城市炎凉急。',48,'全唐诗/poet.song.120000.json','["山林日月長，城市炎凉急。", "方看夏太清，已覺秋淅瑟。", "因之念故山，鶴歸松露滴。", "收足否願餘，此舟徒役役。"]'),
('e5734eea-605c-4ca1-b3b1-aa059c404029','李才翁懶窩  其五','林憲','宋','宋诗','song-poetry','','[]','風雨日蕭瑟，軒窗浸虛凉。',48,'全唐诗/poet.song.120000.json','["風雨日蕭瑟，軒窗浸虛凉。", "清燈閃復定，寒漏爲之長。", "老覺世念少，病須藥物良。", "晨興滌顫手，供此一瓣香。"]'),
('8cbe6f4d-dd4a-4a33-928b-ff6af697119d','李才翁懶窩  其六','林憲','宋','宋诗','song-poetry','','[]','長鑱長長柄，矮窗矮矮欞。',48,'全唐诗/poet.song.120000.json','["長鑱長長柄，矮窗矮矮欞。", "西風已踰月，胡能不淒清。", "晴空舞皓鶴，夜氣紛流螢。", "木葉不自覺，無風輒秋聲。"]'),
('fa218170-348c-4979-ae75-b15a0261b0cf','李才翁懶窩  其七','林憲','宋','宋诗','song-poetry','','[]','月華浴沆瀣，天容注琉璃。',48,'全唐诗/poet.song.120000.json','["月華浴沆瀣，天容注琉璃。", "皎如大圓鏡，照徹清境暉。", "繁星歛芒曜，群動生霏微。", "塵世寧有此，玉虛樓觀低。"]'),
('b594aef8-1294-44a9-94b6-f75067aadd9c','李才翁懶窩  其八','林憲','宋','宋诗','song-poetry','','[]','簷雀樂儔侶，砌蛩相叫吟。',48,'全唐诗/poet.song.120000.json','["簷雀樂儔侶，砌蛩相叫吟。", "如何片雲外，一點征遥禽。", "望極杳無伴，細聽有遺音。", "遲遲去却返，啟我懷故林。"]'),
('3587182c-7d9d-483f-a9f6-0dcc1b011031','兜率寺作  其一','林憲','宋','宋诗','song-poetry','','[]','歸雲薄如霧，徐行江上山。',48,'全唐诗/poet.song.120000.json','["歸雲薄如霧，徐行江上山。", "徘徊印松竹，輕風約之還。", "悠然渡江去，餘影猶闌斑。", "白鳥更自在，幾點落遠灘。"]'),
('928fa6b2-f2cc-4f06-8437-fede94c6b045','兜率寺作  其二','林憲','宋','宋诗','song-poetry','','[]','月色到江上，角聲過山來。',48,'全唐诗/poet.song.120000.json','["月色到江上，角聲過山來。", "山城半綠樹，佳處仍樓臺。", "古屋翠微頂，疏簷宜晚開。", "隱几月入座，山長潮信回。"]'),
('afe4cf5a-fddf-4e9f-9f09-c01c2691de46','句  其一','林憲','宋','宋诗','song-poetry','','[]','桃花飛後楊花飛，楊花飛後無可飛。',16,'全唐诗/poet.song.120000.json','["桃花飛後楊花飛，楊花飛後無可飛。"]'),
('e8d5806c-5d5c-4452-b8a4-021726fb31d4','句  其二','林憲','宋','宋诗','song-poetry','','[]','天空霜無影。',6,'全唐诗/poet.song.120000.json','["天空霜無影。"]'),
('23b756ba-b3da-4339-bd69-91412ff53658','句  其三','林憲','宋','宋诗','song-poetry','','[]','一夜相思笑玉川。',8,'全唐诗/poet.song.120000.json','["一夜相思笑玉川。"]'),
('2d816679-bde2-4bbc-8e5a-fee500f7d5e8','句  其四','林憲','宋','宋诗','song-poetry','','[]','絕無聲色動凡情。',8,'全唐诗/poet.song.120000.json','["絕無聲色動凡情。"]'),
('58bd5e35-186b-43c5-aca2-4f6d626ea93c','偈頌三十首  其一','釋印肅','宋','宋诗','song-poetry','','[]','捏不成團撥不開，何須南岳又天台。',32,'全唐诗/poet.song.120000.json','["捏不成團撥不開，何須南岳又天台。", "六根門首無人用，惹得胡僧特地來。"]'),
('03d9208e-3beb-4052-90e1-4831eb36bf07','偈頌三十首  其二','釋印肅','宋','宋诗','song-poetry','','[]','乍雨乍晴寶象明，東西南北亂雲深。',32,'全唐诗/poet.song.120000.json','["乍雨乍晴寶象明，東西南北亂雲深。", "失珠無限人遭劫，幻應權機爲汝清。"]'),
('cdab1772-6ee7-417a-8fe3-2c9a1c55efae','偈頌三十首  其三','釋印肅','宋','宋诗','song-poetry','','[]','三界唯心唯佛解，萬法唯識更誰知。',96,'全唐诗/poet.song.120000.json','["三界唯心唯佛解，萬法唯識更誰知。", "迷悟本無權立化，恰如黄葉止兒啼。", "涅槃生死猶如夢，十聖三賢是阿誰。", "有物先天無相貌，言詮不及體阿彌。", "祇這阿彌是汝心，不勞逐相外邊尋。", "三僧祇劫隨時立，心心心即是如今。"]'),
('9b8f626c-2857-48aa-ba2c-80846ad895a6','偈頌三十首  其四','釋印肅','宋','宋诗','song-poetry','','[]','邪法如冰霜，正道若太陽。',90,'全唐诗/poet.song.120000.json','["邪法如冰霜，正道若太陽。", "杲日麗天無不照，冰霜仁消洋。", "佛說三乘十二部，會來只是一醫方。", "長年有病不尋藥，五千餘卷枉施張。", "魔王眷屬成群隊，朝夕巴歌作道場。", "唯有普菴真實要，同音異口贊吾皇。"]'),
('b9cf0d85-2ef1-46ef-a1dd-a7f2f985999e','偈頌三十首  其五','釋印肅','宋','宋诗','song-poetry','','[]','稽首摩耶大肚皮，無憂樹下手攀枝。',32,'全唐诗/poet.song.120000.json','["稽首摩耶大肚皮，無憂樹下手攀枝。", "母子至今無覓處，落花啼鳥示全機。"]'),
('5bf0467b-220e-4ca8-ab9e-dd50132d9e1e','偈頌三十首  其六','釋印肅','宋','宋诗','song-poetry','','[]','普禮三身四智佛，一念阿僧祇劫中。',128,'全唐诗/poet.song.120000.json','["普禮三身四智佛，一念阿僧祇劫中。", "身心一如遍法界，法身不滅壽無窮。", "一月六旬權準則，一年四會表參同。", "妄念不生無損益，五千連貫贈寰中。", "所得未嘗圖別用，共成進納續宗風。", "初法難傳憂不信，黄梅五百獨盧公。", "如今箇箇堪分付，報國資家理不窮。", "莫道祖師西土出，剎那自肯即心通。"]'),
('b1cac75e-a192-4ca9-ac1a-3cce5ba12330','偈頌三十首  其七','釋印肅','宋','宋诗','song-poetry','','[]','今日不知來日事，貪嗔癡愛度朝昏。',32,'全唐诗/poet.song.120000.json','["今日不知來日事，貪嗔癡愛度朝昏。", "披毛戴角更相互，豈識修真般若門。"]'),
('dd90b7cd-423b-4d50-b7e3-2be2f81eb0b6','偈頌三十首  其八','釋印肅','宋','宋诗','song-poetry','','[]','明朝遍入孤峰裏，是處尋求不見師。',64,'全唐诗/poet.song.120000.json','["明朝遍入孤峰裏，是處尋求不見師。", "自古上賢難出手，爲伊不肯淡工夫。", "垂經留教五千卷，迷人看著轉迷途。", "凡夫貪愛將爲事，少得曹溪這老盧。"]'),
('48cb63fe-c23c-4e34-936b-1d6a15d060e9','偈頌三十首  其九','釋印肅','宋','宋诗','song-poetry','','[]','普菴真實不問錢，只要離塵脫業纏。',32,'全唐诗/poet.song.120000.json','["普菴真實不問錢，只要離塵脫業纏。", "一聞千悟方堪委，何須苦苦學神仙。"]'),
('adf6c9b9-8e79-4e05-bb85-e86437d1a842','偈頌三十首  其一○','釋印肅','宋','宋诗','song-poetry','','[]','佛法無多子，久長難得人。',60,'全唐诗/poet.song.120000.json','["佛法無多子，久長難得人。", "念念堅不退，堪作了事身。", "不渭心外覓，堂堂本法靈。", "十方佛共證，更不費精神。", "普菴如是道，何患不圓成。"]'),
('de44d2d1-27a0-4ae9-b3cd-8eb38bf878cb','偈頌三十首  其一一','釋印肅','宋','宋诗','song-poetry','','[]','若無一切心，何用一切法。',288,'全唐诗/poet.song.120000.json','["若無一切心，何用一切法。", "佛說一切法，爲除一切心。", "若人解實相，於中無虛誑。", "說與不說同，是即名最上。", "實相未全融，語默空花同。", "而復結空果，後進不能通。", "何故不能通，緣師指落空。", "依妄不歸實，師子墮邪宗。", "二妄相依墮，带累千萬箇。", "因一人道虛，萬類皆招禍。", "不了却自心，只管說他過。", "將謂佛法僧，也似陳行貨。", "倒牀喫不得，苦痛忍難過。", "曉夕無把捉，又見火輪磨。", "始悔我自錯，無福轉加禍。", "未得將爲得，未證將爲證。", "妄想一剎那，果招沙劫病。", "皆是自欺心，不依佛慧命。", "六度未能圓，五戒猶未定。", "口說一切無，貪嗔轉增盛。", "人問道如何，胡應全無性。", "此不見性種，三界魔民蟲。", "眾生若遭遇，萬劫墮貧窮。", "自壞他亦壞，自聾他亦聾。"]'),
('1f4d7c82-326c-40ee-9ff7-b7662729242e','偈頌三十首  其一二','釋印肅','宋','宋诗','song-poetry','','[]','空花水月，一納無餘。',24,'全唐诗/poet.song.120000.json','["空花水月，一納無餘。", "迷時四生六道，悟時一顆明珠。"]'),
('7190e46a-1fe9-4fb2-869e-19375461e0e8','偈頌三十首  其一三','釋印肅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','箇箇跨金毛獅子，人人騎獨步象王。',108,'全唐诗/poet.song.120000.json','["箇箇跨金毛獅子，人人騎獨步象王。", "文殊即是普賢，釋迦倒騎佛殿。", "羅漢不奈安身，普菴鼻孔遼天。", "笑時只道善財癡，百一十城在這裏。", "摩耶腹內造樓臺，一口吸盡西江水。", "試問參方知不知，靈光運用從何起。", "直須堅密處安身，釋迦寶殿真如理。"]'),
('7c7db55c-a074-4992-8433-b56777555a28','偈頌三十首  其一四','釋印肅','宋','宋诗','song-poetry','','[]','打折達磨西來脚，莫令有誤本來人。',383,'全唐诗/poet.song.120000.json','["打折達磨西來脚，莫令有誤本來人。", "當處得心非向背，九年面壁寂光明。", "庭中立雪憨癡漢，海裏口乾渴愛津。", "如今大有心顛倒，夢寐胡諍學道人。", "且向自心中體究，於斯如實更證明。", "須觀古德皆如是，萬莫瞞心自發輕。", "誑謗定招無間業，未全本覺且依經。", "修行未了身依口，莫學提綱沒量人。", "對病用醫須有意，指權歸實救迷情。", "迷悟不同誰解意，三乘猶尚未全明。", "不契一乘爲外道，經生持戒不知。", "徒勞南北與東西，滿口文章不合義。", "不曾親近正知見，色見聲聞弄識神。", "髑髏幾度皮消殞，林下追尋沒一人。", "妄把玄詮爲事會，五千救網變成塵。", "看經須用錢財雇，佛事全憑鐃鈸音。", "餕餡餅皮紗布絹，豬羊犬馬折經金。", "僧俗一同輪苦趣，辜負牟尼古佛心。", "致使類多賢行少，仁慈鮮矣足孤貧。", "榮華富貴千無一，菩薩神仙不降生。", "如麻似粟人頭面，殺盜貪嗔勝畜心。", "不管剎那沉劫海，且徒眼下樂精神。", "背善惡臨無解處，燒香合掌告觀音。", "大慈大悲來救苦，須臾命斷嘆悲深。"]'),
('fe36475e-2e11-43fd-a0ad-c5fec40ad30d','偈頌三十首  其一五','釋印肅','宋','宋诗','song-poetry','','[]','眾生本是佛，悟了一體同。',286,'全唐诗/poet.song.120000.json','["眾生本是佛，悟了一體同。", "若人不達本，逐末走西東。", "君子當務本，本立佛性同。", "通一萬事畢，終不被塵籠。", "非塵體不動，本實理含融。", "先天唯此物，今古學無蹤。", "難了意在處，塞頑空色空。", "本無有指，妄言色空。", "若得妄消歇，真體者何窮。", "真體非形相，不離形相中。", "幻質皆虛僞，大智發於中。", "幻盡覺圓滿，心光寥廓通。", "此通無對待，天地在其中。", "森羅并萬像，影現一鏡中。", "鏡中實我體，寂湛印倥侗。", "若能同道者，與理本相同。", "唯守性清浄，眼耳若盲聾。", "情忘兼想盡，忽覺己身空。", "自了本無物，强以道言通。", "此法滯諸學，皆幻質相容。", "若離一切相，形體外靈通。", "左右逢其源，煩不入胸中。", "我尚不可得，非我何可得。", "眷屬猶如夢，非冤不遇逢。"]'),
('a7a9061d-7f3a-43c7-8f61-7e6cf7ad65d8','偈頌三十首  其一六','釋印肅','宋','宋诗','song-poetry','','[]','自從達解本心光，陳見解者希相許。',160,'全唐诗/poet.song.120000.json','["自從達解本心光，陳見解者希相許。", "今蒙大士墜名香，妙明寂照揮倫楮。", "清風匝地意何窮，自這賢儒誰伴侶。", "自傷嗟，憑誰語，若問吾男歸何處。", "普菴達本不曾生，水月空花無實據。", "不離當處常湛然，覓即知君不可取。", "此靈都是祖宗因，因果歷然隨誰聚。", "如今依舊復來生，何必自迷求解注。", "今古誰曾得久長，唯有法身鎮常住。", "不消追拔與看經，三界唯心須了義。"]'),
('5d290b58-be18-4eec-be85-6ea435d89f89','偈頌三十首  其一七','釋印肅','宋','宋诗','song-poetry','','[]','失却本來面目，箇箇日南長至。',290,'全唐诗/poet.song.120000.json','["失却本來面目，箇箇日南長至。", "先祖時節苦臨，處處笙歌樂醉。", "也參禪，亦詳義，也貧窮，亦富貴。", "蒙頭塞耳有誰知，大地茫茫沒巴鼻。", "智悲同運，野店橫溪。", "頭頭物物，實理希奇。", "悟本誰悟，迷是誰迷。", "家家觀世音，戶戶禮牟尼。", "亨老總不知，都料斫木底。", "不因這三門，如何在這裏。", "老師本無節，世間如夢寐。", "我今夢中說，說者覺如義。", "若有未覺者，好蓋令飽睡。", "等待睡惺時，自己難迴避。", "恐彼少鹽醋，米麵并豆豉。", "我擊木童兒，汝定知來意。", "每人與一飽，大家要了利。", "冬日莫更歇，臘盡相將至。", "如人各上山，努力爭先勢。", "時節莫瞞心，早歸歡喜地。", "堅箇彌勒樓，露出真慈氏。", "了知生死即涅槃，自性如空包天地。", "試問空空空不知，不知知處法不二。"]'),
('a9dff09f-8b7a-41e5-ad21-4120ddbc79ee','偈頌三十首  其一八','釋印肅','宋','宋诗','song-poetry','','[]','誰道凡情不作佛，咦，大丈夫，休分別，百億塵勞從此訣。',41,'全唐诗/poet.song.120000.json','["誰道凡情不作佛，咦，大丈夫，休分別，百億塵勞從此訣。", "今朝酒醒何處，楊柳岸曉風殘月。"]'),
('f24a0b24-cfaa-4f4a-b650-07db0e17cc26','偈頌三十首  其一九','釋印肅','宋','宋诗','song-poetry','','[]','佛是西天之梵語，此土將覺義以同名。',369,'全唐诗/poet.song.120000.json','["佛是西天之梵語，此土將覺義以同名。", "心迷不覺屬眾生，心轉覺時一切佛。", "佛開口處爲言教，化導迷心轉覺心。", "眾生開口成寐語，沙魘群迷叫不醒。", "迷悟不同希達者，諸佛方便救迷情。", "情忘想盡明心者，海藏琅函不可輕。", "在在處處堪聞演，共祝吾皇亙古今。", "臣忠子孝那邊靜，風雨調和物物成。", "是非一體元無二，佛與眾生不出心。", "我今圓滿如來藏，唯願眾生發信心。", "等與如來同受用，一聞千悟永瞻欽。", "這回針芥若不遇，剎那失足墜幽冥。", "閻公問汝將何答，未免刀山火燄林。", "地獄皆因心不悟，一十八界杳難尋。", "八萬四千城可畏，鐵圍無間苦呻吟。", "箇中不遇佛光照，萬劫無由得出輪。", "忉利諸天因業墜，後聞天皷復超升。", "人生有限空花相，光陰迅速豈堪停。", "古人究道如救頭，後士無依豈不驚。", "一失人身難再復，榮華富貴苦來臨。", "如今自有非他事，性水澄清理甚深。", "海印森羅融萬象，湛然無古亦無今。", "化無所化知無二，自肯隨心了此經。"]'),
('69dac9a7-6b77-47bb-aa70-a8796807b8ff','偈頌三十首  其二○','釋印肅','宋','宋诗','song-poetry','','[]','化藏經語，結般若因，度有緣眾。',105,'全唐诗/poet.song.120000.json','["化藏經語，結般若因，度有緣眾。", "一卷一千，共亦不共。", "纔出頭來，便得受用。", "此經無價，擬議不中。", "除非自肯，破塵了夢。", "見佛不空，塔成無縫。", "半偈捨身，古今尊重。", "劫火不燒，魔不能動。", "佛祖皆宗，天龍普供。", "萬莫放過，千億珍重。"]'),
('603547ed-ba7a-4146-a411-f3ae4a70bfb5','偈頌三十首  其二一','釋印肅','宋','宋诗','song-poetry','','[]','如如方契色非空，若也解空空非色。',64,'全唐诗/poet.song.120000.json','["如如方契色非空，若也解空空非色。", "十二部詮如說夢，百千萬佛若空花。", "涅槃生死杳無蹤，本來面目非非相。", "大開喜捨破微塵，了取功勛無盡藏。"]'),
('1e0faf85-d80a-40f1-8d20-2e82a1280ced','偈頌三十首  其二二','釋印肅','宋','宋诗','song-poetry','','[]','閑步遊南陌，惟便野興多。',24,'全唐诗/poet.song.120000.json','["閑步遊南陌，惟便野興多。", "傍花看蝶舞，近柳聽鶯歌。"]'),
('9a8153d4-9471-402d-8957-28549b10b23d','偈頌三十首  其二三','釋印肅','宋','宋诗','song-poetry','','[]','顯老明禪，入理深淵。',160,'全唐诗/poet.song.120000.json','["顯老明禪，入理深淵。", "文殊爲體，妙用普賢。", "鳳山得旨，妙契南源。", "三株樹下，坐斷雲烟。", "金剛作眼，鼻孔遼天。", "言談諷詠，草木皆鮮。", "欽風久矣，偶睹惠然。", "如天甘露，沃我心田。", "希有希有，世外金仙。", "老婆心切，示我窺鞭。", "自知本有，久被塵纏。", "普光明殿，海印俱全。", "彌勒閣中，了了何言。", "常在不欠，觸目無邊。", "一毫頭上，妙絕偏圓。", "含融法界，本體現前。"]'),
('20f7852e-b883-4a4a-8067-ef7cc2b15500','偈頌三十首  其二四','釋印肅','宋','宋诗','song-poetry','','[]','圓應牛，經劫沒人收。',227,'全唐诗/poet.song.120000.json','["圓應牛，經劫沒人收。", "若不遇人，虛度春秋。", "如今橫穿鼻孔，水草皆休。", "有時放，有時收。", "隨分納些些，自性優游。", "獨奈何，勞別討，混跡應不迷流。", "不許犯他苗稼，也犁他田丘。", "飽飲雪山肥膩，一頓更不他求。", "眉毛眼睫，動轉綢繆。", "試問溈山水牯牛，有甚風流。", "向左膊上書字，著甚來由。", "任你千般引□，不肯回頭。", "不如卧雲枕月，運氣常周。", "假使銀蹄金角，氣射斗牛。", "居吾腹內，不得出頭。", "吞底乃刀山劍樹，業到解散枯髏。", "誰知體如巨海，妄起浮漚。", "風擊漚生，漚滅何愁。", "湛然智海喻真牛，圓應頭頭豈用修。"]'),
('3d1ab5f4-94ac-4d9d-9bfb-82323b375928','偈頌三十首  其二五','釋印肅','宋','宋诗','song-poetry','','[]','顛倒夢想忽然破，直入孤峰常獨坐。',298,'全唐诗/poet.song.120000.json','["顛倒夢想忽然破，直入孤峰常獨坐。", "不曾相見與相親，祇麽巍巍迎達磨。", "東西露柱滿添湯，南北石頭快推磨。", "到與不到俱喫茶，萬里清風同唱和。", "快活快活也大哥，達磨達磨真老婆。", "多時尋覓覓不見，却來草裏念摩訶。", "幾年相伴急走過，新羅低頭覓不見，舉首又蹉過。", "今日無知知，不是强揚播。", "若有知知者，未免番成禍。", "四七二三不立形，歷劫三祇祇這箇。", "從古迄今食不餐，肚脹氣均常不餓。", "傷嗟捉月夜猿癡，往復疲勞多退墮。", "不知古佛只傳心，除了此心無別可。", "師子子，不消多，直下無心唱哩囉。", "拈却眼來作鼻孔，呵呵大笑探禪河。", "無量劫來風泡子，至今汩沒和巴歌。", "稽首寶積佛，敬禮阿彌陀。", "普菴此來無箇事，大家相勸演若多。", "元來不識頭依舊，何須苦苦更波波。"]'),
('5e55c027-e5e6-4c91-9551-7d57e5923afe','偈頌三十首  其二六','釋印肅','宋','宋诗','song-poetry','','[]','善者多魔自古今，佛魔一體只空心。',208,'全唐诗/poet.song.120000.json','["善者多魔自古今，佛魔一體只空心。", "心迷不覺慳成賊，心悟回頭便捨金。", "莫怪迷心心怕賊，賊心對面也難尋。", "三途地獄因斯得，奉報須防仁不仁。", "不是道人先注脚，免他來喜去沈吟。", "一年三百六十日，夢想顛倒不曾息。", "耳聞眼見善菴名，更莫邪言喧戲劇。", "思量生死大驚神，唯了本心稱第一。", "暫時忽聽本無心，解脫沉淪千萬億。", "寄語諸人莫蹈虛，勾闌不穩莫稍依。", "莫令墮入深坑下，未免先當說與伊。", "來往任觀心不住，聲香味觸且隨時。", "孤峰獨特誰爲伴，塵世忙然我道奇。"]'),
('0389a93d-e91f-401d-aff4-b9fb44b4f2bd','偈頌三十首  其二七','釋印肅','宋','宋诗','song-poetry','','[]','離諸名色相，實見如來藏。',156,'全唐诗/poet.song.120000.json','["離諸名色相，實見如來藏。", "能轉語成經，本心非榜樣。", "說有即是無，說無無伎倆。", "不會自轉經，依語成妄想。", "夢裏推木輪，信施誰酬償。", "不出牛馬羊，入他闌圈養。", "一文四箇字，還足連他喪。", "悟者發真機，迷者墮鐵網。", "佛教空無相，妙契合無上。", "天鼓解說經，懺悔罪無量。", "有無空不空，真實不虛誑。", "圓信六神通，不刻天龍像。", "只麽轉心經，箇中誰擬向。"]'),
('82c2024a-429d-4666-9a12-78022d17dd62','偈頌三十首  其二八','釋印肅','宋','宋诗','song-poetry','','[]','妄執迷流不肯休，所以今生逐女流。',64,'全唐诗/poet.song.120000.json','["妄執迷流不肯休，所以今生逐女流。", "如今眼界渾塵染，幾時安穩見來秋。", "莫誤前途成業網，目連成佛已綢繆。", "開心放曠依兒得，不著高峰見毗丘。"]'),
('30e5786c-9d51-42c2-9ff2-cd115ea221d9','偈頌三十首  其二九','釋印肅','宋','宋诗','song-poetry','','[]','臘月三十夜，髑髏自相罵。',144,'全唐诗/poet.song.120000.json','["臘月三十夜，髑髏自相罵。", "閻老索飯錢，汝等怕不怕。", "龜毛敲兔角，五彩虛空畫。", "正當恁麽時，摩尼誰著價。", "大年初一日，道閑却成急。", "自拜夢中人，妄想從誰立。", "唯我知不知，今古希相識。", "張三李四歌，草木空祇揖。", "日月轉眼睛，歷劫不曾停。", "三賢與十聖，枉費苦精神。", "常思達磨老，九年守少林。", "如今意不盡，瓦礫即真金。"]'),
('4dc2000e-4eed-4759-b13b-f56bd05ebcc2','偈頌三十首  其三○','釋印肅','宋','宋诗','song-poetry','','[]','出家無易事，了道亦非難。',168,'全唐诗/poet.song.120000.json','["出家無易事，了道亦非難。", "各自要努力，如人擔上山。", "累劫負償命，此生莫等閑。", "遇時若不順，展轉落讎關。", "佛與人方便，度人及登山。", "布身而填險，爲眾代艱難。", "荷擔如來者，莫道不當番。", "汝逆和尚順，明朝報愈艱。", "汝見有福者，擁從物如山。", "在處皆如是，因修得世間。", "若爭人我相，不如快下山。", "若酬自己債，豈用學燒丹。", "相逢無別有，動不是風幡。", "前後都還却，獨坐大雄山。"]'),
('ff0b0f39-dee2-43ef-baa7-1a08f3268361','偈頌三十首  其三一','釋印肅','宋','宋诗','song-poetry','','[]','時人須警覺，應道不癡顛。',264,'全唐诗/poet.song.120000.json','["時人須警覺，應道不癡顛。", "苦牛并急馬，也只少他錢。", "今生還不足，來生又喫鞭。", "道人雖無事，不忍哭蒼天。", "今古論如是，豈可向愚言。", "無我無錢質，此處靜悄然。", "顯跡靈光在，夢然一炷烟。", "普菴何處去，分明在目前。", "須當如是體，可學老婆禪。", "莫住空花相，謗佛結深冤。", "以善能銷惡，以順和逆顛。", "以道資頑狠，以心助普賢。", "以師爲心本，以念於無緣。", "以身如父母，以力報愚賢。", "出家爲佛子，動靜自光鮮。", "超凡并越聖，真實不堪言。", "曾經千萬劫，碎身報未圓。", "我今排次定，更莫聽胡喧。", "順我大家吉，逆我眾無緣。", "孤峰無覓處，三千遍大千。", "此時思一偈，虛空應不得。", "非是我做作，真如體自然。"]'),
('f8c1c0e6-127f-4e7e-8c3c-c3a70f150d23','偈頌十四首  其一','釋印肅','宋','宋诗','song-poetry','','[]','雪人通身却喫罵，兔角拄杖三十下。',60,'全唐诗/poet.song.120000.json','["雪人通身却喫罵，兔角拄杖三十下。", "龜毛索子釣虛空，道理本來非晝夜。", "元不借□□，寶所誰知價。", "一道常光即我心，逼塞虛空無縫罅。"]'),
('cb61e074-28fe-4d9e-9747-1cecc048eca6','偈頌十四首  其二','釋印肅','宋','宋诗','song-poetry','','[]','大家同受用此且富貴，不妨普菴一穴真風水。',168,'全唐诗/poet.song.120000.json','["大家同受用此且富貴，不妨普菴一穴真風水。", "乾坤巽，本無位。", "二十四向絕遮欄，非舌頭人云心地。", "也無賤，也無貴，眼耳鼻舌通身意。", "無限山人不識龍，從前總是虛勞費。", "千峰萬峰連不斷，左右逢源無別水。", "榮華富貴幾遭埋，益子蔭孫無變己。", "驀直下，無忌諱，司馬頭陀沒意智。", "隨機設化謾留名，箇箇趁獐失即麂。", "更迷己，寒靜清明爭掛紙。", "豈知空界現圓融，不顧淺深撈水底。"]'),
('f7d99944-b4ea-4d3a-9529-439377d1a75c','偈頌十四首  其三','釋印肅','宋','宋诗','song-poetry','','[]','若得橋行心亦行，莫教孤負見貧僧。',32,'全唐诗/poet.song.120000.json','["若得橋行心亦行，莫教孤負見貧僧。", "不因通濟何如此，暗室千年忽遇燈。"]'),
('2d340811-73cf-46f9-b785-dc4744991a0a','偈頌十四首  其四','釋印肅','宋','宋诗','song-poetry','','[]','不因孤露妄難休，大□既成難悉婺。',88,'全唐诗/poet.song.120000.json','["不因孤露妄難休，大□既成難悉婺。", "江烟梅雨却知音，□出頭人有何極。", "師子兒，無畏力。", "滿目相知不相識，枯木寒灰唯我知。", "浩浩資深源汲汲，翹松野鶴表吾師。", "吾師心兮心常寂，常寂光中饒益人。"]'),
('29ffdf3d-913a-4d8a-b913-8f1c4d193a2e','偈頌十四首  其五','釋印肅','宋','宋诗','song-poetry','','[]','化彼三千七十士，唯恐迷流增嫉妬。',80,'全唐诗/poet.song.120000.json','["化彼三千七十士，唯恐迷流增嫉妬。", "不患寡而患不均，後代綿綿常貴富。", "我道無心粥飯緣，饑餐渴飲全無措。", "一家有事百家憂，心浄還如佛浄土。", "廬陵米價也尋常，一粒破時全體露。"]'),
('f2aea5e8-e520-46c6-a039-4d7c83f27c7b','偈頌十四首  其六','釋印肅','宋','宋诗','song-poetry','','[]','實相無空無不空，將不空執尚違宗。',160,'全唐诗/poet.song.120000.json','["實相無空無不空，將不空執尚違宗。", "一多無位誰分別，萬象森羅一鏡中。", "菴本非菴開不開，靈知自性即如來。", "尋源窮處烟霞伴，南嶺風光近日回。", "上無片瓦下無錐，被喧卜靜了無依。", "多求欲叩無心者，既了無心豈是非。", "若將色見普菴人，未免隨流不契津。", "千里無來同受用，縱橫妙用自家珍。", "莫怪渠儂不出頭，了心非相永無求。", "相逢誰覺夢中夢，浪靜閑乘般若舟。"]'),
('713f7249-c8c4-4c7a-81f7-845cf5d831fa','偈頌十四首  其七','釋印肅','宋','宋诗','song-poetry','','[]','君不見爛柯仙，一局知他幾度年。',78,'全唐诗/poet.song.120000.json','["君不見爛柯仙，一局知他幾度年。", "自出洞來誰作對，未曾學手早贏先。", "高不高，玄不玄，默然輕轉不能言。", "得失都盧無箇事，一時收拾華堂前。", "若人要問消息，落落真風印碧天。"]'),
('16ee61ba-6710-4605-8076-98a496563ebd','偈頌十四首  其八','釋印肅','宋','宋诗','song-poetry','','[]','老盧得法非僧相，龐老通明豈離家。',32,'全唐诗/poet.song.120000.json','["老盧得法非僧相，龐老通明豈離家。", "大事未成俱業網，除非了本是生涯。"]'),
('dbc161ee-1b4e-407a-8762-748d6195f607','偈頌十四首  其九','釋印肅','宋','宋诗','song-poetry','','[]','心月孤圓時，光非十五六。',108,'全唐诗/poet.song.120000.json','["心月孤圓時，光非十五六。", "迷者以圓觀，智者應妙觸。", "印危崖，鑑川陸，一性圓通無委曲。", "了非心外逐塵緣，下坂不走天然速。", "誰道速，有佛之處不得住，無佛之處一時足。", "時來鐵解放光明，運至石頭成白玉。", "幸逢施主大開張，古佛慧命汝今續。"]'),
('3b28bb36-34fe-47c2-8caa-64be58478b7d','偈頌十四首  其一○','釋印肅','宋','宋诗','song-poetry','','[]','隴西達士重標立，萬行圓明道果成。',32,'全唐诗/poet.song.120000.json','["隴西達士重標立，萬行圓明道果成。", "舉目含靈俱是佛，應無所住得其心。"]'),
('88f36a05-e060-4056-82d2-8345ceea92b3','偈頌十四首  其一一','釋印肅','宋','宋诗','song-poetry','','[]','驪珠一顆印千峰，越古騰今處處通。',80,'全唐诗/poet.song.120000.json','["驪珠一顆印千峰，越古騰今處處通。", "元禪道貫纖毫絕，方知佛法不曾窮。", "孤雲片片標心法，野鶴翹松表自容。", "千眼難觀誰解見，赤幡直下起清風。", "妙覺十方無影像，靈知三界絕行蹤。"]'),
('8cd032ca-14f2-4637-a173-b6d63a001e31','偈頌十四首  其一二','釋印肅','宋','宋诗','song-poetry','','[]','迷指不見月，兩處大誵訛。',60,'全唐诗/poet.song.120000.json','["迷指不見月，兩處大誵訛。", "來叩普菴老，真心豈奈何。", "除非君自肯，陽春白雪歌。", "毛端如來識，言說用閑多。", "情忘并想盡，不斷這摩訶。"]'),
('64190703-f162-4539-b8a8-2d1b5efbe656','偈頌十四首  其一三','釋印肅','宋','宋诗','song-poetry','','[]','一輪秋月映悲風，數和松音標此意。',32,'全唐诗/poet.song.120000.json','["一輪秋月映悲風，數和松音標此意。", "因緣究竟莫勞神，時節到來無不備。"]'),
('b8bcc434-960c-42ea-9c99-4ca617d9c5ad','偈頌十四首  其一四','釋印肅','宋','宋诗','song-poetry','','[]','木匠休愁無酒肉，大家免得落群魔。',52,'全唐诗/poet.song.120000.json','["木匠休愁無酒肉，大家免得落群魔。", "但管來年了，應教不動波。", "隨心做箇殿，別事莫多羅。", "更有一般好，只箇阿彌陀。"]'),
('65335796-8af2-499a-b5ef-0bea0beac37a','靈濟橋語','釋印肅','宋','宋诗','song-poetry','','[]','此渡若非橋，不放眾生過。',254,'全唐诗/poet.song.120000.json','["此渡若非橋，不放眾生過。", "過去現在佛，并西來達磨。", "皆是接群迷，直指人這箇。", "如今人不知，顛倒成患禍。", "堅執有爲功，善惡爭揚播。", "學道不識心，所以塵不破。", "若悟即本心，永劫無退墮。", "說法非干舌，山河大地和。", "行脚不曾移，舉步無空過。", "如斯妙性空，方與人擔荷。", "大用這無心，非福亦非禍。", "於中無妄作，不異阿彌陀。", "法界無別物，一菩提爲座。", "修橋布路爲含靈，轉凡成聖如行貨。", "遊戲菩提誰得知，只恐迷情却放過。", "大丈夫，莫放過，提起眉毛來繼和。", "大家拍手渡橋來，方笑普菴只這箇。", "咄，開口全音只我聞，桃花含笑亂紛紛。", "心非遍界真成妄，意浄情忘法法真。"]'),
('04671190-4a22-4937-a0a1-7a902cb1a835','造袁州浮橋語','釋印肅','宋','宋诗','song-poetry','','[]','普菴教化修浮橋，信心自肯大豐饒。',176,'全唐诗/poet.song.120000.json','["普菴教化修浮橋，信心自肯大豐饒。", "解脫皆因不思議，度人無量永逍遥。", "秀江千古源何極，非干今日與明朝。", "一生補處誰知有，萬德咸歡寂體寥。", "蚊子眼中藏剎土，紅燈焰裏熱眉毛。", "毫髮虛空全不漏，海山相擊浪滔滔。", "石牛喫盡張公粟，木女垂絲釣巨鰲。", "新羅國打西川鼓，東震旦拋北越刀。", "孔自孔，毛自毛，針劄不入大雄豪。", "妄想顛倒蘇公盛，未解撐船弄竹篙。", "豈在文言多卜度，德山拄杖不敲槽。"]'),
('8e0125ef-d58b-49b9-beec-8a32937beb8c','萬載縣橋疏','釋印肅','宋','宋诗','song-poetry','','[]','萬載洪機一發，直得耳聾眼瞎。',60,'全唐诗/poet.song.120000.json','["萬載洪機一發，直得耳聾眼瞎。", "放身通濟仁心，度盡微塵佛剎。", "勸英賢，須特達，百億龍天齊鑒察。", "大開寶藏施珠珍，箇裏無私一毫髮。"]'),
('3cb601fa-c91b-4945-9d0a-6caed1a8b596','修城東合浦橋','釋印肅','宋','宋诗','song-poetry','','[]','自性圓融不礙爲，浮雲枯木任風吹。',64,'全唐诗/poet.song.120000.json','["自性圓融不礙爲，浮雲枯木任風吹。", "莫怪道人無伎倆，猶如浮木歇盲龜。", "應化非真不逆心，有無俱遣道須成。", "相逢便肯無空過，合浦橋邊驗果因。"]'),
('a4689ed9-d436-430c-a600-4d8fc2fe812d','加頌蜀僧雪頌  其一','釋印肅','宋','宋诗','song-poetry','','[]','庭前雪子落紛紛，妙觸靈明應普門。',32,'全唐诗/poet.song.120000.json','["庭前雪子落紛紛，妙觸靈明應普門。", "不是藥山無用處，權令龐老警兒孫。"]'),
('5d009e45-2b0a-4e92-9121-32b24bf438a6','加頌蜀僧雪頌  其二','釋印肅','宋','宋诗','song-poetry','','[]','總是吾家入道門，無說說中聞不聞。',32,'全唐诗/poet.song.120000.json','["總是吾家入道門，無說說中聞不聞。", "步步透關田地穩，須彌𨁝跳撞崑崙。"]'),
('a950e383-15be-45fd-9ac2-eaf7a2581e38','加頌蜀僧雪頌  其三','釋印肅','宋','宋诗','song-poetry','','[]','行人到此宜迴首，此物元來處處有。',32,'全唐诗/poet.song.120000.json','["行人到此宜迴首，此物元來處處有。", "除非自己肯承當，方信境緣無好醜。"]'),
('f876a346-69d8-44c8-a4b3-a6f78518550e','加頌蜀僧雪頌  其四','釋印肅','宋','宋诗','song-poetry','','[]','免使從前業浪奔，直入圓音普眼門。',32,'全唐诗/poet.song.120000.json','["免使從前業浪奔，直入圓音普眼門。", "賓主歷然誰委悉，不是通方莫與論。"]'),
('671bad3d-e0f4-4628-9422-03937b57fa7c','加頌蜀僧雪頌  其五','釋印肅','宋','宋诗','song-poetry','','[]','三世諸佛同此路，天無門兮地無戶。',32,'全唐诗/poet.song.120000.json','["三世諸佛同此路，天無門兮地無戶。", "森羅萬象一光吞，歷劫不曾少鹽醋。"]'),
('ba0a97b1-6a33-4c9b-b598-5d7c95f3002f','加頌蜀僧雪頌  其六','釋印肅','宋','宋诗','song-poetry','','[]','百千方便一乾坤，得者還須皂白分。',32,'全唐诗/poet.song.120000.json','["百千方便一乾坤，得者還須皂白分。", "珠體未明成五色，舉頭鷂子過羅村。"]'),
('f99860ec-f11e-420e-8d78-e2f99020f43c','加頌蜀僧雪頌  其七','釋印肅','宋','宋诗','song-poetry','','[]','浄人若信平常事，穿過髑髏連孔鼻。',32,'全唐诗/poet.song.120000.json','["浄人若信平常事，穿過髑髏連孔鼻。", "多中一了一中多，城東老母難迴避。"]'),
('eee0f86f-02f2-4425-8a78-ee2558687a33','加頌蜀僧雪頌  其八','釋印肅','宋','宋诗','song-poetry','','[]','自有山翁樣子存，家傳祖代沒分文。',32,'全唐诗/poet.song.120000.json','["自有山翁樣子存，家傳祖代沒分文。", "南北東西無別有，光明遍照獨爲尊。"]'),
('4a359d12-a93b-43a6-8ce3-a6d24316e1b6','頌三門  其一','釋印肅','宋','宋诗','song-poetry','','[]','古寺香華迥寂寥，焚修報國化迷流。',32,'全唐诗/poet.song.120000.json','["古寺香華迥寂寥，焚修報國化迷流。", "英賢到此須迴首，撥草瞻風笑點頭。"]'),
('d39a1821-7cdf-4a62-b8d4-3d9f1ad9c8b2','頌三門  其二','釋印肅','宋','宋诗','song-poetry','','[]','此舍絕邊無壁落，充虛露地真寥廓。',32,'全唐诗/poet.song.121000.json','["此舍絕邊無壁落，充虛露地真寥廓。", "往來只道主人寬，爭似永嘉一宿覺。"]'),
('640860c1-0ae2-4af7-a267-4760669d2af1','頌三門  其三','釋印肅','宋','宋诗','song-poetry','','[]','道人活計若虛空，應物無心世豈同。',32,'全唐诗/poet.song.121000.json','["道人活計若虛空，應物無心世豈同。", "假立化城標寶所，暫時指客懷寰中。"]'),
('2cfd0819-8ca1-4e3f-b68a-12e93a0ad209','頌三門  其四','釋印肅','宋','宋诗','song-poetry','','[]','釋達空空遍覺華，到無高下淡渾茶。',32,'全唐诗/poet.song.121000.json','["釋達空空遍覺華，到無高下淡渾茶。", "和雲假宿烟霞榻，明日東西處處家。"]'),
('436279f8-c82f-4227-9368-58d05a1d3863','化無盡曆','釋印肅','宋','宋诗','song-poetry','','[]','化城立有誰知意，普雨調和潤萬機。',64,'全唐诗/poet.song.121000.json','["化城立有誰知意，普雨調和潤萬機。", "大根枝節全體露，何殊彌勒降生時。", "石兒拍掌連雲指，木女含笙和水吹。", "試問燈籠誰解舞，知無我者快拈鎚。"]'),
('98722bdd-c2b0-48c6-837c-71705badf3b4','萍鄉縣丞求頌','釋印肅','宋','宋诗','song-poetry','','[]','杜門終日不通書，得意忘言總不拘。',176,'全唐诗/poet.song.121000.json','["杜門終日不通書，得意忘言總不拘。", "舉向世間人不會，妄談生死事區區。", "信香不昧和光爇，禍福皆心豈有殊。", "心本全真含萬有，只緣六處起諸愚。", "眼耳舌鼻身意靜，箇中何物礙明珠。", "照天照地元不壞，非心貪妄命須臾。", "天命五旬當見覺，從其耳順縱心如。", "老人百出光無變，休將庚申叩文殊。", "了道即心含法界，心無應物合菩提。", "但勸諸人心莫怕，豈勞心上外求諸。", "爲君一念真空體，肯信無心道不虛。"]'),
('c73e57be-694b-4b9d-879a-719b4e00006d','謝戴安撫書院額','釋印肅','宋','宋诗','song-poetry','','[]','普菴以此香，回向大居士。',132,'全唐诗/poet.song.121000.json','["普菴以此香，回向大居士。", "幻盡覺圓者，妙意難遮覆。", "惠我二筆端，三昧非迷悟。", "世間豈識知，何處尋門戶。", "六字光慈化，千古人欽慕。", "象出普菴名，天龍常守護。", "法本付賢侯，利益何窮數。", "傷嗟逐末流，忙忙失元路。", "千里萬里體無間，世出世間非我所。", "謝安撫，雲軒密布巴陵時，願垂青眸垂一顧。"]'),
('1a5c7c61-b876-44c1-ac87-e68598fb9ff6','題三門  其一','釋印肅','宋','宋诗','song-poetry','','[]','玄之又玄，眾妙之門。',36,'全唐诗/poet.song.121000.json','["玄之又玄，眾妙之門。", "空之又空，一法常存。", "要見本來真面目，除非直入這三門。"]'),
('c0e175bc-173e-48ba-9daf-1625da7e2046','題三門  其二','釋印肅','宋','宋诗','song-poetry','','[]','無門爲法門，無入是真入。',40,'全唐诗/poet.song.121000.json','["無門爲法門，無入是真入。", "君禮信佛心，有爲皆不及。", "舍財離相契無生，天耳廓通塵不立。"]'),
('af2864aa-fefc-49c8-b9a2-a85f151a14d4','同輪歌','釋印肅','宋','宋诗','song-poetry','','[]','應機互換不空同，任運隨時轉此公。',190,'全唐诗/poet.song.121000.json','["應機互換不空同，任運隨時轉此公。", "豈用千尋麻索拽，指端輕撥滿寰中。", "活潑潑，耀玲瓏，相繼聯綿不斷窮。", "誰識那邊關捩子，閑摇取笑各西東。", "能應也資慵，無求不得此輪中。", "墜石此時猶拙計，力多功淺眾難供。", "斯用寡，意豐濃，八萬塵勞一點融。", "饑渴永銷從此脫，兒孫代代得昌隆。", "不費力，實從容，超彼迷流摝井中。", "莫令繩斷沉泥底，手脚茫然杳絕蹤。", "謾道同輪歌表裏，到來觀者莫儱侗。", "知道本來無可說，屈伸俯仰示宗風。"]'),
('2ba62f07-43df-4ee5-9911-54e52327033a','讚三十六祖頌  其一','釋印肅','宋','宋诗','song-poetry','','[]','師子體無二，拈花應笑時。',24,'全唐诗/poet.song.121000.json','["師子體無二，拈花應笑時。", "然燈從此焰，不斷至今輝。"]'),
('5883f3e4-de0f-47ea-9635-2115922dc537','讚三十六祖頌  其二','釋印肅','宋','宋诗','song-poetry','','[]','誰易阿誰難，多聞不透關。',24,'全唐诗/poet.song.121000.json','["誰易阿誰難，多聞不透關。", "忽解空無我，內海更藏山。"]'),
('8ad97fd6-48c3-4090-9583-8707fc3607f6','讚三十六祖頌  其三','釋印肅','宋','宋诗','song-poetry','','[]','無事商那和，翛然了義多。',24,'全唐诗/poet.song.121000.json','["無事商那和，翛然了義多。", "是法不可說，轉念摩嚕陀。"]'),
('e1606453-ad73-4996-b5e1-0d95317a396b','讚三十六祖頌  其四','釋印肅','宋','宋诗','song-poetry','','[]','優波耶鞠多，三昧力降魔。',24,'全唐诗/poet.song.121000.json','["優波耶鞠多，三昧力降魔。", "法傳香種子，意氣尚周羅。"]'),
('f72198d1-0441-4283-bcb7-05cbc238d4a0','讚三十六祖頌  其五','釋印肅','宋','宋诗','song-poetry','','[]','提多迦初生，光超日月燈。',24,'全唐诗/poet.song.121000.json','["提多迦初生，光超日月燈。", "山頂泉迸涌，此路少人行。"]'),
('c4e6762c-1162-4c5c-9841-5c41c21058cd','讚三十六祖頌  其六','釋印肅','宋','宋诗','song-poetry','','[]','大士彌遮迦，憶昔阿私陀。',24,'全唐诗/poet.song.121000.json','["大士彌遮迦，憶昔阿私陀。", "邪正通一道，無法不調和。"]'),
('af59ed7e-77b8-4f38-bf21-74328fe14258','讚三十六祖頌  其七','釋印肅','宋','宋诗','song-poetry','','[]','針劄不入婆須密，正念何勞多氣力。',32,'全唐诗/poet.song.121000.json','["針劄不入婆須密，正念何勞多氣力。", "往劫親獻如來座，襄王國裏逢知識。"]'),
('d24c39a7-a133-4090-952d-1a2b9a1c7b6d','讚三十六祖頌  其八','釋印肅','宋','宋诗','song-poetry','','[]','佛陀阿難提，放光從肉髻。',23,'全唐诗/poet.song.121000.json','["佛陀阿難提，放光從肉髻。", "逢師論義，得入三摩地。"]'),
('18e228ee-049d-482e-9234-a06308020e47','讚三十六祖頌  其九','釋印肅','宋','宋诗','song-poetry','','[]','伏馱密多惺惺，父母與佛非親。',28,'全唐诗/poet.song.121000.json','["伏馱密多惺惺，父母與佛非親。", "五十不行不語，一見本人清浄。"]'),
('047f5547-4c74-453a-84ac-268b7867bea0','讚三十六祖頌  其一○','釋印肅','宋','宋诗','song-poetry','','[]','脇本號難生，泥牛入海耕。',24,'全唐诗/poet.song.121000.json','["脇本號難生，泥牛入海耕。", "隨機千萬轉，無上亦無行。"]'),
('c4dcd542-5f4e-4249-ab9a-935bea0a9d7b','讚三十六祖頌  其一一','釋印肅','宋','宋诗','song-poetry','','[]','咄哉瞿曇氏，唯富那夜奢。',24,'全唐诗/poet.song.121000.json','["咄哉瞿曇氏，唯富那夜奢。", "不拘有無種，遍地法蓮華。"]'),
('92ed0378-eeea-48fc-b0aa-e33d72ec9465','讚三十六祖頌  其一二','釋印肅','宋','宋诗','song-poetry','','[]','馬鳴分身百億，論數玄詮無極。',28,'全唐诗/poet.song.121000.json','["馬鳴分身百億，論數玄詮無極。", "六通三昧降魔，不用色聲氣力。"]'),
('416fbfb6-fc6c-4065-84c4-1e23b13f641e','讚三十六祖頌  其一三','釋印肅','宋','宋诗','song-poetry','','[]','迦毗摩羅師，外道成正真。',24,'全唐诗/poet.song.121000.json','["迦毗摩羅師，外道成正真。", "了斯第一義，非故亦非新。"]'),
('2713ef91-9458-47b0-8418-e40b8e40a0eb','讚三十六祖頌  其一四','釋印肅','宋','宋诗','song-poetry','','[]','龍樹非形相，獨現圓月體。',24,'全唐诗/poet.song.121000.json','["龍樹非形相，獨現圓月體。", "說法如虛空，非舌談真理。"]'),
('73520613-263e-4841-af09-dfc34d91fa58','讚三十六祖頌  其一五','釋印肅','宋','宋诗','song-poetry','','[]','迦那提婆針投鉢，深契無相心解脫。',32,'全唐诗/poet.song.121000.json','["迦那提婆針投鉢，深契無相心解脫。", "辨因木耳再來人，巧幻不虧於毫末。"]'),
('77dc400e-826f-44c2-9f07-0b77c9f99506','讚三十六祖頌  其一六','釋印肅','宋','宋诗','song-poetry','','[]','過去娑婆樹，如是羅睺羅。',24,'全唐诗/poet.song.121000.json','["過去娑婆樹，如是羅睺羅。", "師子同坐食，付般若摩訶。"]'),
('a8d98d36-a610-4784-b39d-7cd3ed86f372','讚三十六祖頌  其一七','釋印肅','宋','宋诗','song-poetry','','[]','莊嚴聖王子，僧迦號難提。',24,'全唐诗/poet.song.121000.json','["莊嚴聖王子，僧迦號難提。", "棄國避世榮，便入三摩底。"]'),
('6d551564-07e2-48f3-83fa-f3cf2d50834f','讚三十六祖頌  其一八','釋印肅','宋','宋诗','song-poetry','','[]','伽耶舍多人再來，常持圓鑑離塵埃。',32,'全唐诗/poet.song.121000.json','["伽耶舍多人再來，常持圓鑑離塵埃。", "風鈴非響我心應，一返常光更不回。"]'),
('b002e273-4ab5-46c6-a5e4-c7c7a4bc72aa','讚三十六祖頌  其一九','釋印肅','宋','宋诗','song-poetry','','[]','降生月氏國，名鳩摩羅多。',24,'全唐诗/poet.song.121000.json','["降生月氏國，名鳩摩羅多。", "宿乘尊者記，不二阿彌陀。"]'),
('728934b1-6855-44c5-a7b1-34980cdd11e5','讚三十六祖頌  其二○','釋印肅','宋','宋诗','song-poetry','','[]','闍夜多因地，昔爲自在天。',24,'全唐诗/poet.song.121000.json','["闍夜多因地，昔爲自在天。", "一契無作性，大用得言前。"]'),
('9df1b9f1-b12a-4fe4-a3d2-d23c5bfc0d3c','讚三十六祖頌  其二一','釋印肅','宋','宋诗','song-poetry','','[]','婆修盤頭尊，曾禮大光明。',24,'全唐诗/poet.song.121000.json','["婆修盤頭尊，曾禮大光明。", "以杖畫佛面，悔過復天真。"]'),
('8e4f4e28-f520-42a8-9cd6-af4d2e8fc82d','讚三十六祖頌  其二二','釋印肅','宋','宋诗','song-poetry','','[]','國名常自在，王子摩拏羅。',24,'全唐诗/poet.song.121000.json','["國名常自在，王子摩拏羅。", "化鶴成菩薩，動止湧禪河。"]'),
('b135a227-da0d-4dc1-867f-ab7521d59938','讚三十六祖頌  其二三','釋印肅','宋','宋诗','song-poetry','','[]','鶴勒那有智，光大包天地。',23,'全唐诗/poet.song.121000.json','["鶴勒那有智，光大包天地。", "五道貫色，日月時親禮。"]'),
('50d86a74-625a-42c1-b83b-b15a3fea0efb','讚三十六祖頌  其二四','釋印肅','宋','宋诗','song-poetry','','[]','真師子法身，究竟無頭尾。',24,'全唐诗/poet.song.121000.json','["真師子法身，究竟無頭尾。", "賺當盲眼人，華空疑不是。"]'),
('203ba208-fcd8-4494-b593-83c640744357','讚三十六祖頌  其二五','釋印肅','宋','宋诗','song-poetry','','[]','斯多婆舍擔板，重鍊出金剛眼。',28,'全唐诗/poet.song.121000.json','["斯多婆舍擔板，重鍊出金剛眼。", "正法不動纖毫，越祖超師無間。"]'),
('616d45a5-eea1-4790-ad02-2ee030b9cfec','讚三十六祖頌  其二六','釋印肅','宋','宋诗','song-poetry','','[]','德勝王太子，號不如密多。',24,'全唐诗/poet.song.121000.json','["德勝王太子，號不如密多。", "指山還梵志，魔群不奈何。"]'),
('f4b702a6-8bd6-414b-a2b3-c271814de784','讚三十六祖頌  其二七','釋印肅','宋','宋诗','song-poetry','','[]','般若多羅法，非廣亦非狹。',24,'全唐诗/poet.song.121000.json','["般若多羅法，非廣亦非狹。", "翠竹與黄華，長松并短柏。"]'),
('352eb866-f6fa-40cf-9612-5ce92b03dfe0','讚三十六祖頌  其二八','釋印肅','宋','宋诗','song-poetry','','[]','菩提達磨大醫王，全持正法度南方。',32,'全唐诗/poet.song.121000.json','["菩提達磨大醫王，全持正法度南方。", "粉骨碎身應未報，至今不離此心光。"]'),
('06df3004-8573-409f-ac32-7382df5a9578','讚三十六祖頌  其二九','釋印肅','宋','宋诗','song-poetry','','[]','直截猛利，立雪斷臂。',20,'全唐诗/poet.song.121000.json','["直截猛利，立雪斷臂。", "千古萬古，丈夫意氣。"]'),
('13e3d893-ae81-4975-863a-b2dca6daa877','讚三十六祖頌  其三○','釋印肅','宋','宋诗','song-poetry','','[]','精通無說說，本地亦無生。',24,'全唐诗/poet.song.121000.json','["精通無說說，本地亦無生。", "無生花滿地，本傳無盡燈。"]'),
('93040718-e121-4f8e-bad2-47f885c264fc','讚三十六祖頌  其三一','釋印肅','宋','宋诗','song-poetry','','[]','破頭山下起清波，流注黄梅不奈何。',32,'全唐诗/poet.song.121000.json','["破頭山下起清波，流注黄梅不奈何。", "四度敕宣端不動，尊威妙湛灌娑婆。"]'),
('ce904f88-cc70-45d8-9756-2cb27d7a0cbd','讚三十六祖頌  其三二','釋印肅','宋','宋诗','song-poetry','','[]','百鳥銜花未足奇，直須透過始方知。',32,'全唐诗/poet.song.121000.json','["百鳥銜花未足奇，直須透過始方知。", "五百眾中誰委悉，碓頭私許老盧錐。"]'),
('7cfc10c4-5a19-4b6e-8d2b-b68edd2d6297','讚三十六祖頌  其三三','釋印肅','宋','宋诗','song-poetry','','[]','曹溪一滴水，周匝無餘欠。',28,'全唐诗/poet.song.121000.json','["曹溪一滴水，周匝無餘欠。", "孤峰絕頂浪滔天，大洋海裏金剛焰。"]'),
('68a3ff43-27bf-4689-856b-79cc43a010fb','讚三十六祖頌  其三四','釋印肅','宋','宋诗','song-poetry','','[]','馬駒踏殺天下人，且有什麽相交涉。',32,'全唐诗/poet.song.121000.json','["馬駒踏殺天下人，且有什麽相交涉。", "雲作枝竿雲作花，妙光圓寂含空劫。"]'),
('4845d9bb-c5fc-45b4-933e-5b477ee85f53','讚三十六祖頌  其三五','釋印肅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一口吸盡西江水，子細思量未足奇。',48,'全唐诗/poet.song.121000.json','["一口吸盡西江水，子細思量未足奇。", "身含無盡之虛空，箇事元來非擬議。", "非心非佛又較些，即心即佛猶寐語。"]'),
('5188db6a-f407-4990-b438-399775afc6a7','讚三十六祖頌  其三六','釋印肅','宋','宋诗','song-poetry','','[]','十方諸佛入其中，十波羅蜜一光同。',32,'全唐诗/poet.song.121000.json','["十方諸佛入其中，十波羅蜜一光同。", "十世古今無間隔，十身千億法身通。"]'),
('52a62612-1046-4795-97fb-dfcdd321af36','百寶光明','釋印肅','宋','宋诗','song-poetry','','[]','青黄赤白異塵寰，知音希得似寒山。',32,'全唐诗/poet.song.121000.json','["青黄赤白異塵寰，知音希得似寒山。", "豐干未辨爭饒舌，光明不遍道應難。"]'),
('a1ee9963-f42c-427a-add2-adc569ac685f','一一光明','釋印肅','宋','宋诗','song-poetry','','[]','日月燈光未足奇，若逢肉眼轉迷癡。',32,'全唐诗/poet.song.121000.json','["日月燈光未足奇，若逢肉眼轉迷癡。", "恒沙眷屬光無二，萬億龍天守護持。"]'),
('b4b641fa-ef64-49c6-bb48-140afb8c331f','皆遍示現','釋印肅','宋','宋诗','song-poetry','','[]','春有百花冬有雪，夏有凉風秋有月。',32,'全唐诗/poet.song.121000.json','["春有百花冬有雪，夏有凉風秋有月。", "若無一事掛心頭，箇裏無私真廓徹。"]'),
('c288b1d0-f6a1-46be-8cd8-74adc9749628','十恒河沙','釋印肅','宋','宋诗','song-poetry','','[]','塵塵剎剎號南無，末後收來付老盧。',32,'全唐诗/poet.song.121000.json','["塵塵剎剎號南無，末後收來付老盧。", "結果傳燈周法界，誰人肯辨此工夫。"]'),
('4a00e196-0014-4057-a143-000de06ae136','金剛密迹','釋印肅','宋','宋诗','song-poetry','','[]','牙如劍樹目如燈，電爍妖魔法不生。',32,'全唐诗/poet.song.121000.json','["牙如劍樹目如燈，電爍妖魔法不生。", "千聖出頭難插足，普菴也道我無能。"]'),
('9188bb93-1b72-4511-8558-e3ea66ca857b','擎山持杵','釋印肅','宋','宋诗','song-poetry','','[]','擎山抱岳疾如風，持杵拈槌解脫空。',32,'全唐诗/poet.song.121000.json','["擎山抱岳疾如風，持杵拈槌解脫空。", "世間有相非身大，須彌總納一塵中。"]'),
('f5916d4d-03a9-4607-a099-86bc2edf04df','遍虛空界','釋印肅','宋','宋诗','song-poetry','','[]','和風周匝萬花開，春霧濛濛鎖綠苔。',32,'全唐诗/poet.song.121000.json','["和風周匝萬花開，春霧濛濛鎖綠苔。", "世人寐語不知意，黄鶴樓前不賞梅。"]'),
('a6041794-a122-4298-8348-1d331b306fac','大眾仰觀','釋印肅','宋','宋诗','song-poetry','','[]','多身一體少人知，不體無空自執迷。',32,'全唐诗/poet.song.121000.json','["多身一體少人知，不體無空自執迷。", "除非妙達斯三昧，箇裏圓觀始不疑。"]'),
('b39fd565-c77f-4c6b-b059-e56bde2bcdd2','畏愛兼抱','釋印肅','宋','宋诗','song-poetry','','[]','南山有條鱉鼻蛇，雪峰往日鎮常誇。',32,'全唐诗/poet.song.121000.json','["南山有條鱉鼻蛇，雪峰往日鎮常誇。", "喪身失命知多少，滿地如今號菜花。"]'),
('f875a926-be2f-45ba-8f65-7960bbab7168','求佛哀祐','釋印肅','宋','宋诗','song-poetry','','[]','母子相逢幾萬年，夕陽夢斷豈堪言。',32,'全唐诗/poet.song.121000.json','["母子相逢幾萬年，夕陽夢斷豈堪言。", "多時不隔如今見，趙州勘破老婆禪。"]'),
('fac8b86b-291d-456b-8201-3c29ebcf279c','一心聽佛','釋印肅','宋','宋诗','song-poetry','','[]','不聞聞了絕狐疑，三界浮囂總不知。',32,'全唐诗/poet.song.121000.json','["不聞聞了絕狐疑，三界浮囂總不知。", "泥牛入海通消息，木馬橫嘶貫紫微。"]'),
('8481993a-dc25-482f-90f1-f7b3ee9c0f88','無見頂相','釋印肅','宋','宋诗','song-poetry','','[]','無影樹下誰相識，瑠璃殿內絕形名。',32,'全唐诗/poet.song.121000.json','["無影樹下誰相識，瑠璃殿內絕形名。", "千巖色□祥光現，萬壑松風和沒人。"]'),
('9e668922-aca6-4f82-9502-87475eabae8a','放光如來','釋印肅','宋','宋诗','song-poetry','','[]','主伴重重絕世倫，今朝即是舊時人。',32,'全唐诗/poet.song.121000.json','["主伴重重絕世倫，今朝即是舊時人。", "迷悟是誰堪話會，姚黄魏紫一般春。"]'),
('ca1daa1e-b6c4-4cdd-aa6c-40411d453ee5','宣說神咒','釋印肅','宋','宋诗','song-poetry','','[]','癡人著色又扣聲，豈解圓音不可聽。',32,'全唐诗/poet.song.121000.json','["癡人著色又扣聲，豈解圓音不可聽。", "自古迄今宣不斷，到家方覺少知音。"]'),
('ed0f9976-33ba-4939-84b0-a840f7096f16','題寶塔','釋印肅','宋','宋诗','song-poetry','','[]','塔本無縫，真如不動。',240,'全唐诗/poet.song.121000.json','["塔本無縫，真如不動。", "說此經處，涌出虛空。", "釋迦多寶，聽說如夢。", "東西無二，見見不同。", "無剎不收，無色不融。", "層層落落，光影重重。", "恒河沙劫，盡入其中。", "三世諸佛，一法身通。", "針劄不入，壽量無窮。", "目連舍利，常隱於中。", "阿育王像，妙色金容。", "天龍八部，萬億靈通。", "擎山持杵，遍滿虛空。", "護持禮塔，摧滅魔蹤。", "顯正寶塔，八面玲瓏。", "水火不壞，障毗嵐風。", "眾生見者，永脫樊籠。", "信者施者，功德不空。", "無住布施，福德無窮。", "住相布施，猶滯途中。", "諸佛子等，無功之功。", "成如是塔，標指宗風。", "空劫壞時，此塔不鎔。", "劫火洞然，體若虛空。"]'),
('68dd9e73-798a-4ca3-87d1-1580bf52e376','題經樓語','釋印肅','宋','宋诗','song-poetry','','[]','般若貫華嚴，涅槃通寶積。',120,'全唐诗/poet.song.121000.json','["般若貫華嚴，涅槃通寶積。", "迷則龍宮海藏，悟則一字不識。", "教演三伯餘會，度人無數百億。", "如今滿目放光明，十二部經詮不及。", "崔田彭族祖墳林，無欠無餘樓獨立。", "大千沙界納其中，無說無聞真利益。", "遠祖近宗無不超，得意生身乘此力。", "現存一族福綿綿，世出世間福何極。"]'),
('8721bf96-8aed-4bf4-a7d5-f014046cada4','李總幹遺詩十四句師於一句之下加頌七句  其一','釋印肅','宋','宋诗','song-poetry','','[]','僧家起大屋，枉費他金穀。',48,'全唐诗/poet.song.121000.json','["僧家起大屋，枉費他金穀。", "不是明眼人，真如大地獄。", "黄葉止孩啼，只要免啼哭。", "不犯一滴酒，不動一片肉。"]'),
('fd37d38a-b280-4b4f-8c4c-19001fbc80d1','李總幹遺詩十四句師於一句之下加頌七句  其二','釋印肅','宋','宋诗','song-poetry','','[]','簷棟如翬飛，世間那得知。',48,'全唐诗/poet.song.121000.json','["簷棟如翬飛，世間那得知。", "不是風旛動，如如應好機。", "青青是翠竹，孤雲無性馳。", "頭頭垂示處，子細好明知。"]'),
('c19da76a-b96a-4704-b579-369bd6343d9c','李總幹遺詩十四句師於一句之下加頌七句  其三','釋印肅','宋','宋诗','song-poetry','','[]','殿堂何所有，夢幻非堅久。',48,'全唐诗/poet.song.121000.json','["殿堂何所有，夢幻非堅久。", "竹木從何來，箇箇人空手。", "石人解綵畫，木女添燈油。", "此事誰得知，真實泥牛吼。"]'),
('bab7491f-58ae-4cfd-9603-fdaea64169d3','李總幹遺詩十四句師於一句之下加頌七句  其四','釋印肅','宋','宋诗','song-poetry','','[]','塑箇泥佛兒，肚裏藏深機。',48,'全唐诗/poet.song.121000.json','["塑箇泥佛兒，肚裏藏深機。", "聚沙爲佛塔，猶尚獲菩提。", "父見諸子劣，且教令讀書。", "一日成名後，天下總皆知。"]'),
('83bfb00c-07bb-4881-b886-478ee36cb3c0','李總幹遺詩十四句師於一句之下加頌七句  其五','釋印肅','宋','宋诗','song-poetry','','[]','朝朝去禮拜，誰識丹霞在。',48,'全唐诗/poet.song.121000.json','["朝朝去禮拜，誰識丹霞在。", "打倒木佛燒，院主反招罪。", "得相而無相，參方會不會。", "如來非大身，老盧快踏碓。"]'),
('6046bcb9-0ce9-4c7b-8b62-c85f3bd5ed8c','李總幹遺詩十四句師於一句之下加頌七句  其六','釋印肅','宋','宋诗','song-poetry','','[]','便道福相隨，生天果未遲。',48,'全唐诗/poet.song.121000.json','["便道福相隨，生天果未遲。", "力盡簡還墜，來生不如意。", "假施滿七寶，不如發真歸。", "布施有爲者，觀來真自迷。"]'),
('e02113ac-1e5a-454d-a8cd-1b55eeaded11','李總幹遺詩十四句師於一句之下加頌七句  其七','釋印肅','宋','宋诗','song-poetry','','[]','問他怎如此，日輪正當午。',48,'全唐诗/poet.song.121000.json','["問他怎如此，日輪正當午。", "鼻孔廓遼天，我道無門戶。", "唯佛與佛知，有爲無作做。", "若問如何道，瞪目不相顧。"]'),
('1785f3d0-e5bb-45dc-bdd2-dc230da6399b','李總幹遺詩十四句師於一句之下加頌七句  其八','釋印肅','宋','宋诗','song-poetry','','[]','我要警昏迷，迷人愈見癡。',48,'全唐诗/poet.song.121000.json','["我要警昏迷，迷人愈見癡。", "九年面壁坐，不露一毫釐。", "法說無可說，機陳不二機。", "箇中若不會，學取須菩提。"]'),
('98d099ae-6d2e-4539-96e7-191ebd4f9df9','李總幹遺詩十四句師於一句之下加頌七句  其九','釋印肅','宋','宋诗','song-poetry','','[]','昏迷曾未警，勞我箇眼睛。',48,'全唐诗/poet.song.121000.json','["昏迷曾未警，勞我箇眼睛。", "絲毫全不漏，雲月事猶新。", "達士知幾者，常看無字經。", "打動禾山鼓，舞起道吾神。"]'),
('51170a3f-226c-4a1c-97a2-1eaf18df463d','李總幹遺詩十四句師於一句之下加頌七句  其一○','釋印肅','宋','宋诗','song-poetry','','[]','自家先已癡，逢迷實不迷。',48,'全唐诗/poet.song.121000.json','["自家先已癡，逢迷實不迷。", "能令石人舞，解使木哥吹。", "寂寂孤雲裏，逍遥勿我知。", "萬億恒沙佛，皆同一性齊。"]'),
('d20eb18e-5ea0-483f-95b1-87fb4aa79bf8','李總幹遺詩十四句師於一句之下加頌七句  其一一','釋印肅','宋','宋诗','song-poetry','','[]','不如茆蓋頭，裹箇大枯髏。',48,'全唐诗/poet.song.121000.json','["不如茆蓋頭，裹箇大枯髏。", "鬼窟作活計，閻公未肯休。", "佛以法爲身，不可以相求。", "一念無心者，法界剎那周。"]'),
('c06bf357-a7b2-4919-a1e8-bf1ddcded15e','李總幹遺詩十四句師於一句之下加頌七句  其一二','釋印肅','宋','宋诗','song-poetry','','[]','靜坐取片時，妄想自家知。',48,'全唐诗/poet.song.121000.json','["靜坐取片時，妄想自家知。", "心口兩不同，修行不透機。", "明朝與後日，作箇野狐狸。", "因果全不落，百丈一言迷。"]'),
('2476655b-6877-4eab-8ed3-c0da11193ba4','李總幹遺詩十四句師於一句之下加頌七句  其一三','釋印肅','宋','宋诗','song-poetry','','[]','有人來問我，如何向他道。',48,'全唐诗/poet.song.121000.json','["有人來問我，如何向他道。", "喪身失命處，世人怕死到。", "三界唯一心，萬法唯心造。", "不悟生死者，輪劫空招報。"]'),
('911cef46-b5c9-4129-9a88-7835980b0150','李總幹遺詩十四句師於一句之下加頌七句  其一四','釋印肅','宋','宋诗','song-poetry','','[]','山僧總不知，知不知實奇。',48,'全唐诗/poet.song.121000.json','["山僧總不知，知不知實奇。", "空知未達本，不免墮頑機。", "世尊拈華處，天人豈辨知。", "迦葉破微笑，古今信無疑。"]'),
('f16b0179-4ed3-4967-95a9-a136063f6586','詩一首','釋印肅','宋','宋诗','song-poetry','','[]','普菴見一箇蝦蟆，度日常吞鱉鼻蛇。',64,'全唐诗/poet.song.121000.json','["普菴見一箇蝦蟆，度日常吞鱉鼻蛇。", "獨立卓然真可畏，身和雲月粲星花。", "太公一見便收釣，謝三得意號玄沙。", "幾多獨獸無藏隱，不斷聲孤問水涯。"]'),
('99f9fd00-3535-4bb7-a722-f54f1a9d4d8d','頌四賓主  其一','釋印肅','宋','宋诗','song-poetry','','[]','賓中賓，借錢沽酒設狂人。',28,'全唐诗/poet.song.121000.json','["賓中賓，借錢沽酒設狂人。", "常常負債無依倚，謗教虛招地獄因。"]'),
('0189242d-73fa-4215-8e2c-91eda0dd1d76','頌四賓主  其二','釋印肅','宋','宋诗','song-poetry','','[]','六道四生同一輪，見他生滅未爲真。',32,'全唐诗/poet.song.121000.json','["六道四生同一輪，見他生滅未爲真。", "直須打破獼猴鏡，識取光中弄影人。"]'),
('c7024a8d-39e2-4384-9b47-4cfc4395aeab','頌四賓主  其三','釋印肅','宋','宋诗','song-poetry','','[]','試聽無言童子說，未徹還同第二月。',32,'全唐诗/poet.song.121000.json','["試聽無言童子說，未徹還同第二月。", "妙機普印絕思心，六月炎天鋪大雪。"]'),
('ef08b9c5-6f2e-452a-bbf3-3d996949ce4a','頌四賓主  其四','釋印肅','宋','宋诗','song-poetry','','[]','直須認得本來真，智識心知外道人。',32,'全唐诗/poet.song.121000.json','["直須認得本來真，智識心知外道人。", "眹迹不留無對待，乾坤無不是吾身。"]'),
('d955ff16-2202-4ec0-9266-0eba38792a26','頌四賓主  其五','釋印肅','宋','宋诗','song-poetry','','[]','賓中主，日久帝家頻得書。',28,'全唐诗/poet.song.121000.json','["賓中主，日久帝家頻得書。", "幾回客夢經秋雨，直至而今賃屋居。"]'),
('ced36b26-2232-4b08-be14-7e9666525f3c','頌四賓主  其六','釋印肅','宋','宋诗','song-poetry','','[]','賊是小人君記取，好手白拈猶未許。',32,'全唐诗/poet.song.121000.json','["賊是小人君記取，好手白拈猶未許。", "坐斷聖凡絕見聞，揚眉且勝拈華舉。"]'),
('1c3fcf2c-2e84-49ff-8abc-b26eb07bdc5b','頌四賓主  其七','釋印肅','宋','宋诗','song-poetry','','[]','一揮凜凜劍鋒寒，函蓋乾坤絕自觀。',32,'全唐诗/poet.song.121000.json','["一揮凜凜劍鋒寒，函蓋乾坤絕自觀。", "堪笑天龍無可說，示人祇在指頭端。"]'),
('535a7be2-46f4-4911-8c88-b107a37a6fd2','頌四賓主  其八','釋印肅','宋','宋诗','song-poetry','','[]','直下無君回避處，聲色全彰第一義。',32,'全唐诗/poet.song.121000.json','["直下無君回避處，聲色全彰第一義。", "取相凡夫承不知，頓悟圓音方了利。"]'),
('83645342-5b01-46cc-bcee-6eff002c28eb','頌四賓主  其九','釋印肅','宋','宋诗','song-poetry','','[]','主中賓，近日門風革故新。',28,'全唐诗/poet.song.121000.json','["主中賓，近日門風革故新。", "相見相聞俱不謬，時時笑覺夢中神。"]'),
('8e6f8970-d871-4de3-b4da-19368a9d55f2','頌四賓主  其一○','釋印肅','宋','宋诗','song-poetry','','[]','大地山河眼裏塵，自古至今强立名。',32,'全唐诗/poet.song.121000.json','["大地山河眼裏塵，自古至今强立名。", "衹箇絕邊無縫塔，不曾來往逐人情。"]'),
('5cdb4384-cf55-4399-9d25-748c8f6c3f8a','頌四賓主  其一一','釋印肅','宋','宋诗','song-poetry','','[]','要會箇中真活計，釋迦老子不蓋被。',32,'全唐诗/poet.song.121000.json','["要會箇中真活計，釋迦老子不蓋被。", "更尋祖意外馳求，管取下梢落魔魅。"]'),
('431e4f04-9c17-4ca5-b47f-546da7effeb9','頌四賓主  其一二','釋印肅','宋','宋诗','song-poetry','','[]','騰騰師子露全身，吞却森羅萬象形。',32,'全唐诗/poet.song.121000.json','["騰騰師子露全身，吞却森羅萬象形。", "頭尾也無常獨步，眼光不眨大驚人。"]'),
('7bc4b0b5-e910-4b0d-8f32-d05835753f97','頌四賓主  其一三','釋印肅','宋','宋诗','song-poetry','','[]','主中主，無相光中施法雨。',28,'全唐诗/poet.song.121000.json','["主中主，無相光中施法雨。", "醍醐一味灌群機，皆入無爲涅槃宇。"]'),
('b863363d-869b-4696-91ab-f7a8e9f9a826','頌四賓主  其一四','釋印肅','宋','宋诗','song-poetry','','[]','活卓自由把不住，正令當行無本據。',32,'全唐诗/poet.song.121000.json','["活卓自由把不住，正令當行無本據。", "除非北斗裏藏身，杳杳冥冥沒住處。"]'),
('3d3d37bb-be54-43ad-83e1-077ac0c3b29a','頌四賓主  其一五','釋印肅','宋','宋诗','song-poetry','','[]','無邊無表實希奇，虛空爲鼓須彌槌。',32,'全唐诗/poet.song.121000.json','["無邊無表實希奇，虛空爲鼓須彌槌。", "輕輕敲著作金聲，試問同參知不知。"]'),
('d7f288b9-fec2-40a5-8d62-66c3be9a03e4','頌四賓主  其一六','釋印肅','宋','宋诗','song-poetry','','[]','何處更容絲髮許，脫體無依誰會舉。',32,'全唐诗/poet.song.121000.json','["何處更容絲髮許，脫體無依誰會舉。", "玄玄玄了說玄玄，究竟談玄猶寐語。"]'),
('c0aafb73-807f-4a89-9a8a-93e08c0993c3','頌四賓主  其一七','釋印肅','宋','宋诗','song-poetry','','[]','賓主互用，動亦非動。',200,'全唐诗/poet.song.121000.json','["賓主互用，動亦非動。", "佛祖機關，不妨重弄。", "法共不共，十八何用。", "一相無相，自知輕重。", "信手拈來，得時不會。", "龜毛作過，兔角受罪。", "山河俱動，此義失宗。", "宗非山河，俱動是夢。", "動亦不動，收來無用。", "這回捉敗，永不費功。", "賓亦無賓，道孰可名。", "今父逃逝，契悟方親。", "主得真主，佛祖共舉。", "認賊爲子，不敢相許。", "萬國來親，唯一佛身。", "血脈不斷，得者忻忻。", "更下注脚，盲人摸索。", "見中求見，病消求藥。", "和光同塵，沒量智人。", "有誰相識，資深資深。"]'),
('b0322a68-583c-4034-864f-8536081dac1b','彭心齋諱逢源自作頌呈師師於一句下加三句  其一','釋印肅','宋','宋诗','song-poetry','','[]','妙哉心齋，淺入深埋。',26,'全唐诗/poet.song.121000.json','["妙哉心齋，淺入深埋。", "欲識神通并妙用，何妨運水及搬柴。"]'),
('1e5565ff-2912-4ffe-bf9e-5389fed86019','彭心齋諱逢源自作頌呈師師於一句下加三句  其二','釋印肅','宋','宋诗','song-poetry','','[]','光大深淵，匝地周天。',26,'全唐诗/poet.song.121000.json','["光大深淵，匝地周天。", "常憶江南三月裏，鷓鴣啼處百花鮮。"]'),
('18e04b10-91e8-4037-ba63-f05bcfde9edb','彭心齋諱逢源自作頌呈師師於一句下加三句  其三','釋印肅','宋','宋诗','song-poetry','','[]','中有居士，吞光飲露。',26,'全唐诗/poet.song.121000.json','["中有居士，吞光飲露。", "無相光中有相身，無明路上無生路。"]'),
('f187b041-4754-4e78-be5a-67eb7085ebd4','彭心齋諱逢源自作頌呈師師於一句下加三句  其四','釋印肅','宋','宋诗','song-poetry','','[]','左右逢源，大目犍連。',26,'全唐诗/poet.song.121000.json','["左右逢源，大目犍連。", "猿抱子歸青嶂裏，鳥銜花落碧巖前。"]'),
('03acf617-a9fb-4751-97cc-3615185d490f','三昧諸頌  其一','釋印肅','宋','宋诗','song-poetry','','[]','佛共眾生只此心，悟迷不間古同今。',32,'全唐诗/poet.song.121000.json','["佛共眾生只此心，悟迷不間古同今。", "千名萬字何交涉，達法圓光許一針。"]'),
('d40b3b99-f2f5-43e8-ae4d-be9a1c69123d','三昧諸頌  其二','釋印肅','宋','宋诗','song-poetry','','[]','出生入死足通神，全體三生父母靈。',32,'全唐诗/poet.song.121000.json','["出生入死足通神，全體三生父母靈。", "不是如來知見力，舍身財命卒難昇。"]'),
('bb6219a9-41b4-4bb6-bc38-04b95daa3b17','三昧諸頌  其三','釋印肅','宋','宋诗','song-poetry','','[]','千光一合圓如鏡，萬象森羅影現中。',32,'全唐诗/poet.song.121000.json','["千光一合圓如鏡，萬象森羅影現中。", "此光大用如如體，道了橋成風月同。"]'),
('54d1623e-f797-40be-977c-835d2ae3bb15','三昧諸頌  其四','釋印肅','宋','宋诗','song-poetry','','[]','空色無邊際，離垢摩尼圓。',24,'全唐诗/poet.song.121000.json','["空色無邊際，離垢摩尼圓。", "能依實相用，助發有龍天。"]'),
('394f84d3-68fe-45f2-8f9a-52ccc94968fd','三昧諸頌  其五','釋印肅','宋','宋诗','song-poetry','','[]','神光遍界，體若金剛。',20,'全唐诗/poet.song.121000.json','["神光遍界，體若金剛。", "威神力固，邪宗銷亡。"]'),
('02bf035a-973d-4254-8013-d1ec9a47ed03','三昧諸頌  其六','釋印肅','宋','宋诗','song-poetry','','[]','裏許若無這箇，何爲古佛傳心。',42,'全唐诗/poet.song.121000.json','["裏許若無這箇，何爲古佛傳心。", "我體不空無住，用時越古超今。", "會看木人牽鋸，始令石女穿針。"]'),
('acfd1fac-a50e-423d-8035-86f18ad6018e','三昧諸頌  其七','釋印肅','宋','宋诗','song-poetry','','[]','百納骨董袋，一切皆我入。',30,'全唐诗/poet.song.121000.json','["百納骨董袋，一切皆我入。", "一切莫能入，達此妙縱橫，三世佛佛佛。"]'),
('89daef1b-4097-4c33-94e3-8226cc26a34d','三昧諸頌  其八','釋印肅','宋','宋诗','song-poetry','','[]','大虛塗毒鼓，有病聞皆愈。',30,'全唐诗/poet.song.121000.json','["大虛塗毒鼓，有病聞皆愈。", "無病聞皆死，死了却甦來，誰會辜負你。"]'),
('92986689-bef9-413d-857c-fea085813138','三昧諸頌  其九','釋印肅','宋','宋诗','song-poetry','','[]','無底瑠璃井，忽爾墮其中。',30,'全唐诗/poet.song.121000.json','["無底瑠璃井，忽爾墮其中。", "勝修萬劫功，跳出跳不出，瘖痖又盲聾。"]'),
('182b2c21-3bc9-4daa-a200-8fb1a59ed775','三昧諸頌  其一○','釋印肅','宋','宋诗','song-poetry','','[]','分明無背面，相逢不相見。',30,'全唐诗/poet.song.121000.json','["分明無背面，相逢不相見。", "年年桃花面，臨州下水船，梢公力方便。"]'),
('f4d069e8-6498-40b7-a8d1-818b9f1c2592','三昧諸頌  其一一','釋印肅','宋','宋诗','song-poetry','','[]','獨脚老虎，暗時暗殺人。',29,'全唐诗/poet.song.121000.json','["獨脚老虎，暗時暗殺人。", "不識是眼睛，與君無著力，溪雲罩古城。"]'),
('59857da8-fc88-4b47-9325-dcb0e04cd148','三昧諸頌  其一二','釋印肅','宋','宋诗','song-poetry','','[]','無根樹子，混盳非出入。',29,'全唐诗/poet.song.121000.json','["無根樹子，混盳非出入。", "頭尾應皆急，妙了過這邊，渡海何曾濕。"]'),
('9011d19e-b796-4ed3-8966-932e6ae9f195','香積厨法語','釋印肅','宋','宋诗','song-poetry','','[]','咦，好辨心，以此三法爲三昧，無量無邊世不會。',118,'全唐诗/poet.song.121000.json','["咦，好辨心，以此三法爲三昧，無量無邊世不會。", "我今修供佛眾生，萬聖千賢悉同共。", "摩訶般若味真如，十波羅蜜同受用。", "大家著力要精專，一粒微塵不許動。", "爲報龍天并八部，莫入厨中乾打鬨。", "監齋使者在眼前，守護普菴無罅縫。", "針劄不入起馨香，十八元來佛不共。"]'),
('21767e59-cb4a-4bc7-b970-f4e7b963e451','贊護教  其一','釋印肅','宋','宋诗','song-poetry','','[]','給孤施地，慈化爲尊。',20,'全唐诗/poet.song.121000.json','["給孤施地，慈化爲尊。", "護人成佛，功德奚論。"]'),
('8304426b-fd60-4ea8-931a-e7cd9f0c3975','贊護教  其二','釋印肅','宋','宋诗','song-poetry','','[]','仰山顯迹，契會宗師。',20,'全唐诗/poet.song.121000.json','["仰山顯迹，契會宗師。", "一法性身，利物宏慈。"]'),
('4772eab0-57c2-4281-b885-ce95b694a1f5','贊護教  其三','釋印肅','宋','宋诗','song-poetry','','[]','以南權正，無心應物。',20,'全唐诗/poet.song.121000.json','["以南權正，無心應物。", "威德標宗，不可輕忽。"]'),
('a1fb198c-cb89-45da-9fcb-c6034e6219cc','贊護教  其四','釋印肅','宋','宋诗','song-poetry','','[]','困權反正，辦道玉泉。',20,'全唐诗/poet.song.121000.json','["困權反正，辦道玉泉。", "無相無空，義足先天。"]'),
('6cc207c6-1073-4b3d-945c-80fea2c54deb','贊護教  其五','釋印肅','宋','宋诗','song-poetry','','[]','契那一通，方全六用。',20,'全唐诗/poet.song.121000.json','["契那一通，方全六用。", "護持般若，法身不動。"]'),
('250e0c5c-3756-44bc-96d7-99f89136a691','贊護教  其六','釋印肅','宋','宋诗','song-poetry','','[]','卓立奇功，回光識性。',20,'全唐诗/poet.song.121000.json','["卓立奇功，回光識性。", "宇宙恢彰，一身清浄。"]'),
('a5b810b0-6614-498b-9259-b309f0d5178f','贊護教  其七','釋印肅','宋','宋诗','song-poetry','','[]','一成一切成，一壞一切壞。',48,'全唐诗/poet.song.121000.json','["一成一切成，一壞一切壞。", "法身無二相，總別無罣礙。", "凡聖本自無，性天真常在。", "寄語住山人，伊作麽生會。"]'),
('d6060c4f-96f5-435b-9b2d-ed42429966e8','移五瘟出市心','釋印肅','宋','宋诗','song-poetry','','[]','助佛揚名化俗徒，遣邪歸正沃心枯。',32,'全唐诗/poet.song.121000.json','["助佛揚名化俗徒，遣邪歸正沃心枯。", "國風雅泰民歡樂，只這和瘟大丈夫。"]'),
('1994280d-c5b3-432a-8a90-8384b407ff6a','證道歌  其一','釋印肅','宋','宋诗','song-poetry','','[]','普韻連天風月和，大千沙界一音聞，妙契非聲能幾箇。',24,'全唐诗/poet.song.121000.json','["普韻連天風月和，大千沙界一音聞，妙契非聲能幾箇。"]'),
('42a4f09b-8b4c-441f-a310-6f86191eab9b','證道歌  其二','釋印肅','宋','宋诗','song-poetry','','[]','君不見，日面金仙如月面。',28,'全唐诗/poet.song.121000.json','["君不見，日面金仙如月面。", "見非是見見無能，霜天月映瑠璃殿。"]'),
('137eef6d-18d0-45cf-b0cc-d851413671a3','證道歌  其三','釋印肅','宋','宋诗','song-poetry','','[]','絕學無爲閑道人，不曾禮拜不看經。',32,'全唐诗/poet.song.121000.json','["絕學無爲閑道人，不曾禮拜不看經。", "不動遍周塵剎海，卓爾孤身混白雲。"]'),
('e26bb12e-ab7e-43cc-a07d-f2102301c67c','證道歌  其四','釋印肅','宋','宋诗','song-poetry','','[]','不除妄想不求真，大開寶藏施珠珍。',32,'全唐诗/poet.song.121000.json','["不除妄想不求真，大開寶藏施珠珍。", "窮士未諳門外立，黄金窟裏作貧人。"]'),
('033e7c48-619c-45f7-b1fd-a31a81cf3a89','證道歌  其五','釋印肅','宋','宋诗','song-poetry','','[]','無明實性即佛性，心浄還同佛土浄。',32,'全唐诗/poet.song.121000.json','["無明實性即佛性，心浄還同佛土浄。", "水鳥樹林聲色中，殊無毫髮來爭競。"]'),
('06731db2-5b56-4b52-9765-ecf943e92f4c','證道歌  其六','釋印肅','宋','宋诗','song-poetry','','[]','幻化空身即法身，且無分別與緣情。',32,'全唐诗/poet.song.121000.json','["幻化空身即法身，且無分別與緣情。", "青青翠竹無非相，鬰鬰黄花搭地靈。"]'),
('2e1cfc4d-f016-413e-a9f3-c68c5eb27708','證道歌  其七','釋印肅','宋','宋诗','song-poetry','','[]','法身覺了無一物，入滅降生非出沒。',32,'全唐诗/poet.song.121000.json','["法身覺了無一物，入滅降生非出沒。", "觀身實相亦如然，究竟何曾離兜率。"]'),
('4cbf5592-8310-4a83-ac10-68795924cff4','證道歌  其八','釋印肅','宋','宋诗','song-poetry','','[]','本元自性天真佛，一體無邊含萬物。',32,'全唐诗/poet.song.121000.json','["本元自性天真佛，一體無邊含萬物。", "迷時只道有西天，悟來當甚乾蘿蔔。"]'),
('47685b18-6b04-4f8b-8658-75aba6f4f9a0','證道歌  其九','釋印肅','宋','宋诗','song-poetry','','[]','五陰浮雲空去來，自是凡夫眼不開。',32,'全唐诗/poet.song.121000.json','["五陰浮雲空去來，自是凡夫眼不開。", "爛煮堅冰充午膳，熟煎雪塊作油䭔。"]'),
('c65b8ae7-84a8-4c9d-bf2d-37ef309153d7','證道歌  其一○','釋印肅','宋','宋诗','song-poetry','','[]','三毒水泡虛出沒，將無作有埋深窟。',32,'全唐诗/poet.song.121000.json','["三毒水泡虛出沒，將無作有埋深窟。", "洛浦曾將喻色身，誰人解語依靈物。"]'),
('edb800ad-cd3b-4a8c-bc5b-05eb5e4c5aad','證道歌  其一一','釋印肅','宋','宋诗','song-poetry','','[]','證實相，無人法，不用尺刀并寸甲。',32,'全唐诗/poet.song.121000.json','["證實相，無人法，不用尺刀并寸甲。", "魔軍盡總證菩提，大地須彌一芥納。"]'),
('d210aebf-a07d-4523-a849-5995dbd252aa','證道歌  其一二','釋印肅','宋','宋诗','song-poetry','','[]','剎那滅却阿鼻業，閻羅共我休分別。',32,'全唐诗/poet.song.121000.json','["剎那滅却阿鼻業，閻羅共我休分別。", "洋銅鐵汁即醍醐，火輪便是禪心月。"]'),
('3eec422f-0538-4ac5-afbc-fdd816ed180c','證道歌  其一三','釋印肅','宋','宋诗','song-poetry','','[]','若將妄語誑眾生，永劫不來世上行。',32,'全唐诗/poet.song.121000.json','["若將妄語誑眾生，永劫不來世上行。", "無縫塔中非相貌，劈頭坐却老盧能。"]'),
