('5c8a3d39-8ddd-4b29-ba5f-b820b27ae87a','證道歌  其二五○','釋印肅','宋','宋诗','song-poetry','','[]','一句了然超百億，如如不動纖毫力。',32,'全唐诗/poet.song.121000.json','["一句了然超百億，如如不動纖毫力。", "普眼當觀如□□，春晴曉霧連天碧。"]'),
('34f5c1db-283a-4512-9c17-7999adb81aa3','證道歌  其二五一','釋印肅','宋','宋诗','song-poetry','','[]','法中王，最高勝，一微塵裏光無盡。',32,'全唐诗/poet.song.121000.json','["法中王，最高勝，一微塵裏光無盡。", "無邊身相入微塵，轉大法輪常普應。"]'),
('106ada96-2585-4ac6-99dc-544edb57d40e','證道歌  其二五二','釋印肅','宋','宋诗','song-poetry','','[]','河沙如來同共證，光光相徹無餘剩。',32,'全唐诗/poet.song.121000.json','["河沙如來同共證，光光相徹無餘剩。", "各申右手摩其頂，龍天萬億咸歸命。"]'),
('644c4d5f-a416-4697-8176-1202d0c17de4','證道歌  其二五三','釋印肅','宋','宋诗','song-poetry','','[]','我今解此如意珠，不論貧富灌頭舒。',32,'全唐诗/poet.song.121000.json','["我今解此如意珠，不論貧富灌頭舒。", "出沒往來無欠缺，四生六道入無餘。"]'),
('b83222bf-1e17-4480-be4c-d914de2d8d24','證道歌  其二五四','釋印肅','宋','宋诗','song-poetry','','[]','信受之者皆相應，不落有無凡與聖。',32,'全唐诗/poet.song.121000.json','["信受之者皆相應，不落有無凡與聖。", "八面清風宇宙寬，日月從他渾自性。"]'),
('3a39c8fd-d051-4436-a374-92af4b639edd','證道歌  其二五五','釋印肅','宋','宋诗','song-poetry','','[]','了了見，無一物，唯有天真一如佛。',32,'全唐诗/poet.song.121000.json','["了了見，無一物，唯有天真一如佛。", "普賢腹裏接觀音，善財稽首稱奇特。"]'),
('09af7288-12a9-49ca-949b-e99d50e915af','證道歌  其二五六','釋印肅','宋','宋诗','song-poetry','','[]','亦無人，亦無佛，廣大樓臺彌勒宅。',32,'全唐诗/poet.song.121000.json','["亦無人，亦無佛，廣大樓臺彌勒宅。", "豁開門戶接群生，一念無心全用得。"]'),
('61018f20-190c-42d1-a32e-cae9de8f7421','證道歌  其二五七','釋印肅','宋','宋诗','song-poetry','','[]','大千沙界海中漚，何必春風更點頭。',32,'全唐诗/poet.song.121000.json','["大千沙界海中漚，何必春風更點頭。", "雪夜一枝渾漏泄，速傳驛馬進王侯。"]'),
('2508cd0d-d0dc-409c-819d-91252151eaad','證道歌  其二五八','釋印肅','宋','宋诗','song-poetry','','[]','一切賢聖如電拂，智尊不動瑠璃色。',32,'全唐诗/poet.song.121000.json','["一切賢聖如電拂，智尊不動瑠璃色。", "紫金光聚沒遮攔，說甚寒山并拾得。"]'),
('d3b4a4c3-6ff4-490a-b060-dce023255a7a','證道歌  其二五九','釋印肅','宋','宋诗','song-poetry','','[]','假使鐵輪頂上旋，萬里神光體自然。',32,'全唐诗/poet.song.121000.json','["假使鐵輪頂上旋，萬里神光體自然。", "邪魔似雪飛湯裏，安能驚動老婆禪。"]'),
('f9c873f5-1f21-4d3a-b245-9b38e2428044','證道歌  其二六○','釋印肅','宋','宋诗','song-poetry','','[]','定慧圓明終不失，天迴地轉光澄寂。',32,'全唐诗/poet.song.121000.json','["定慧圓明終不失，天迴地轉光澄寂。", "劫火洞然轉轉新，箇事如如誰委悉。"]'),
('126e43f6-b358-4d0b-8ee1-9f8d3a9a5ad2','證道歌  其二六一','釋印肅','宋','宋诗','song-poetry','','[]','日可冷，月可熱，凡夫倒用成磨滅。',32,'全唐诗/poet.song.121000.json','["日可冷，月可熱，凡夫倒用成磨滅。", "大道圓明一性通，春夏秋冬誰辨別。"]'),
('b1df2418-09ad-4f19-9205-cb76cf00d6bd','證道歌  其二六二','釋印肅','宋','宋诗','song-poetry','','[]','眾魔不能壞真說，真說無言光廓徹。',32,'全唐诗/poet.song.121000.json','["眾魔不能壞真說，真說無言光廓徹。", "包含萬有不曾生，天地亡鋒并結舌。"]'),
('6b20364e-1c82-4475-897f-cac36c27f571','證道歌  其二六三','釋印肅','宋','宋诗','song-poetry','','[]','象駕崢嶸謾進途，氣沖牛斗耀昏衢。',32,'全唐诗/poet.song.121000.json','["象駕崢嶸謾進途，氣沖牛斗耀昏衢。", "日月失光誰敢顧，萬邪冰爍絕名模。"]'),
('cde2fe46-4521-4acb-9e54-908025506368','證道歌  其二六四','釋印肅','宋','宋诗','song-poetry','','[]','誰見螳螂能拒轍，螢蟲七夕吞明月。',32,'全唐诗/poet.song.121000.json','["誰見螳螂能拒轍，螢蟲七夕吞明月。", "織女心寬不作聲，牽牛一棒和空折。"]'),
('38b12cba-8204-45b3-8018-3da10f45fc32','證道歌  其二六五','釋印肅','宋','宋诗','song-poetry','','[]','大象不遊於兔徑，針鋒頭上禮觀音。',32,'全唐诗/poet.song.121000.json','["大象不遊於兔徑，針鋒頭上禮觀音。", "百尺竿頭猶進步，十方沙界現全身。"]'),
('8d4a2446-635d-40de-b4ef-12befadd3031','證道歌  其二六六','釋印肅','宋','宋诗','song-poetry','','[]','大悟不拘於小節，猛燄爐中撈霰雪。',32,'全唐诗/poet.song.121000.json','["大悟不拘於小節，猛燄爐中撈霰雪。", "石頭垂足示長髭，修行有甚相交涉。"]'),
('78f23d2f-794a-431c-97a4-b11117ff98f5','證道歌  其二六七','釋印肅','宋','宋诗','song-poetry','','[]','莫將管見謗蒼蒼，井底蛙牛逞巨江。',32,'全唐诗/poet.song.121000.json','["莫將管見謗蒼蒼，井底蛙牛逞巨江。", "乾坤大地一隻眼，用來還似一毫芒。"]'),
('a3b95907-5efb-4351-8075-8fb5ae749f8f','證道歌  其二六八','釋印肅','宋','宋诗','song-poetry','','[]','未了吾今爲君决，一字不留無可說。',32,'全唐诗/poet.song.121000.json','["未了吾今爲君决，一字不留無可說。", "耀古騰今徹底輝，不離當體常光潔。"]'),
('87054043-e578-41ff-aed7-d107f14c1923','普菴歌','釋印肅','宋','宋诗','song-poetry','','[]','祇箇普菴純寶貝，妙慧莊嚴真暢快。',256,'全唐诗/poet.song.121000.json','["祇箇普菴純寶貝，妙慧莊嚴真暢快。", "無門爲戶到人稀，萬里神光圓頂蓋。", "非相身，無不在，體露堂堂聲色外。", "世間夢幻曷能隨，超出世間那肯愛。", "絕意識，無眼界，浄名卧疾瞿曇解。", "指權就實度眾生，勿謂古賢來捏怪。", "悟普菴，本無壞，空劫有窮渠自在。", "四生六道豈相干，物我兼忘心唯最。", "無有無，內非內，海印發光誰敢對。", "森羅萬象普菴收，絕待靈明全體會。", "忘能所，勿知解，瓦礫真金誰敢買。", "若還不是老胡來，覿面難逢輪劫肯。", "雪齊腰，求教誨，得旨忘言轉不退。", "百鍊金剛無孔鎚，要斷龜毛兔角罪。", "如意珠，我今解，剎剎塵塵鋪障昧。", "一毫端量大千輝，爍破無明生死袋。"]'),
('5ded4cad-2a45-41ae-943f-f8e3509491ab','顯元歌','釋印肅','宋','宋诗','song-poetry','','[]','不識本家元寶貝，汩沒緣塵生死快。',256,'全唐诗/poet.song.121000.json','["不識本家元寶貝，汩沒緣塵生死快。", "阿賴耶識藏無明，十八界纏繒網蓋。", "貪嗔癡，常在在，心鏡空花分內外。", "不知四大假成軀，妄執六塵增渴愛。", "迷此心，有三界，大地茫茫誰曉解。", "依師戒定學看經，聞通真空即生怪。", "世間物，無不壞，唯獨法身鎮長在。", "毛吞巨海有誰知，芥納須彌實奇最。", "本無外，亦非內，心法無形無可對。", "假施七寶滿三千，道眼未開心不會。", "莫說知，休談解，自驪珠，不著買。", "用無盡處示眾生，識不破人還□□。", "聽語言，爲教誨，不脫聲聞生進退。", "剎那一念入魔群，萬劫虛招無間罪。", "本無傳，莫求解，祇這靈光終不昧。", "大無邊表細無塵，圓覺一輪如意袋。"]'),
('b8f61606-1c69-48d0-969d-b8a65b4f8c5e','摩尼歌','釋印肅','宋','宋诗','song-poetry','','[]','一顆摩尼非玉貝，不動隨機方便快。',256,'全唐诗/poet.song.121000.json','["一顆摩尼非玉貝，不動隨機方便快。", "無邊無表實先天，亙古迄今無覆蓋。", "六和同，心不在，放蕩汪洋塵世外。", "箇中無可表真如，不滅不生誰不愛。", "卓頑空，立世界，非界非空有誰解。", "返己迴觀一物無，光大圓融含百怪。", "珠體堅，吉怪壞，幻化元空靈本在。", "三十年看水牯牛，祇箇溈山實奇最。", "華林子，通非內，蹋倒浄缾絕待對。", "天上天下獨玄靈，直至如今少人會。", "老南泉，逞見解，提起貓兒人不買。", "一刀兩斷不曾分，主伴重重元不背。", "了非言，聞妙海，鉆火逢烟莫放退。", "忽然杲日爍冰霜，不立微塵誰受罪。", "天網恢，非結解，遍布彌漫這三昧。", "堪笑衡陽沒量人，彌勒光中拖布袋。"]'),
('fcf299ad-c92d-4a1c-b8f1-d61081a1fca6','十二時歌  其一','釋印肅','宋','宋诗','song-poetry','','[]','平旦寅，雞鳴犬吠足圓音。',60,'全唐诗/poet.song.121000.json','["平旦寅，雞鳴犬吠足圓音。", "祇這圓音無二聽，何勞妄想別求真。", "擊鍾皷，了無聲，了本無聲真好聽。", "聲錧無體門前客，體合聲空箇裏人。"]'),
('7ba78963-ea5b-4c1f-9708-082a231d3759','十二時歌  其二','釋印肅','宋','宋诗','song-poetry','','[]','日出卯，齋粥無□心覺飽。',60,'全唐诗/poet.song.121000.json','["日出卯，齋粥無□心覺飽。", "鉢盂洗了自閑閑，方信趙州機便巧。", "師子兒，全牙爪，驚殺百年老虎豹。", "捏怪文殊劈腦騎，二乘皆道莊嚴好。"]'),
('7c06c207-e562-4976-a1f1-8e2d0c451ded','十二時歌  其三','釋印肅','宋','宋诗','song-poetry','','[]','食時辰，金牛作舞笑忻忻。',60,'全唐诗/poet.song.121000.json','["食時辰，金牛作舞笑忻忻。", "漆桶漆桶喫來□，參方誰識老婆心。", "佛祖意，只如今，且無自己及他人。", "雪峰指作一面鏡，輪劫獼猴佩苦辛。"]'),
('062cbc1f-e3bf-41b1-8246-e0e0e0c66882','十二時歌  其四','釋印肅','宋','宋诗','song-poetry','','[]','禺中巳，報君學道無門戶。',60,'全唐诗/poet.song.121000.json','["禺中巳，報君學道無門戶。", "佛語諸經標此心，此心現時寂滅度。", "本無迷，曷有悟，真我非身誰作做。", "貪嗔癡愛屬眾生，達者無非涅槃路。"]'),
('68000786-5d83-4499-b5d3-c4eef653567e','十二時歌  其五','釋印肅','宋','宋诗','song-poetry','','[]','日南午，大地元來沒寸土。',60,'全唐诗/poet.song.121000.json','["日南午，大地元來沒寸土。", "天上天下獨爲尊，耀目連睛無可睹。", "石鞏癡，逢馬祖，自己如空誰射弩。", "三平了道劈開胸，不拄箭鋒徒自苦。"]'),
('f5f59090-64c3-4ffa-b5a9-579b6e682fcd','十二時歌  其六','釋印肅','宋','宋诗','song-poetry','','[]','日昳未，擔板玄沙愛鱉鼻。',60,'全唐诗/poet.song.121000.json','["日昳未，擔板玄沙愛鱉鼻。", "喪身失命幾多人，張口送睛何處避。", "不通宗，渾寐語，業識茫茫無本據。", "盲參不體弄蛇人，常被弄蛇穿却鼻。"]'),
('c0c24d12-01f7-4f35-a7c1-c6f362965051','十二時歌  其七','釋印肅','宋','宋诗','song-poetry','','[]','晡時申，衙鼓鼕鼕妙意新。',60,'全唐诗/poet.song.121000.json','["晡時申，衙鼓鼕鼕妙意新。", "括地該天人不會，如飄野馬入迷津。", "不取相，勿疎親，露體堂堂絕翳塵。", "屠兒一念無諸業，龍女逡巡作佛身。"]'),
('8ce8c420-8598-4e7e-815b-eaff5e72a574','十二時歌  其八','釋印肅','宋','宋诗','song-poetry','','[]','日入酉，萬戶千家無別有。',60,'全唐诗/poet.song.121000.json','["日入酉，萬戶千家無別有。", "相呼相喚去還來，誰識一身非妍醜。", "也無頭，也無手，劫火洞然渠不朽。", "豬羊牛馬化爲真，毫髮不留無可守。"]');
